// Declare global environment [object]
var jsos						= null;
var JestEnvironment				= null;
var JestEnvironmentStatus		= 'shutdown';
var JestLibraryRegistry			= {};				// [object] for registering custom libraries
var JestAppsRegistry			= {};				// [object] for registering custom apps
var JestMixins					= {};				// [object] for registering mixins

// Set status function
const setStatus =
	() => {
		JestEnvironmentStatus	= 'running';
	};

//const BASE_PATH = "http://jesterly.net/"; // or "/apps/jest/" if deployed under a subfolder
function jestGetURL( path ) {
	/*if ( typeof chrome!=='undefined' && chrome.runtime?.getURL ) {
		return jestGetURL( path );
	}*/
	return /*BASE_PATH +*/ path;
}

/* --- BEGIN js/includes/prototype/Array.prototype.js --- */

//-------------------------
// Extend Array Prototype
//-------------------------
// Remove value from [array] if it exists.
// RETURNS: new modified [array].
// * value		- [...] value to remove if inside [array].
Array.prototype.remove = function( value ) {
	return this.filter( cls => cls!==value );
}

// Obtain first value of an [array].
// RETURNS: [...] first value of [array].
Array.prototype.first = function() {
	return this[0]; // first element
}

//-----------------------------
// Array.prototype.mergeUnique
//-----------------------------
// Description: Merges this array with another and removes duplicates.
// * otherArray - [array] Array to merge
// RETURNS: [array] New array with unique strings
Array.prototype.mergeUnique = function ( otherArray ) {
	if ( !Array.isArray(otherArray) )
		throw new TypeError('Argument must be an array');

	return Array.from(new Set([...this, ...otherArray]));
};

/* --- BEGIN js/os/OSConfigurable.js --- */

// OSConfigurable class
class OSConfigurable {
	// Plugin handling
	static plugins	= {};			// static plugins [array] for extending the Jest application
	// Declare properties
	_options		= {};			// specific options passed to constructor
	_vars 			= {};			// [object] of mode statuses
	_data			= {};			// [object] of misc. data to set internally
	_temp			= {};			// [object] of temporary data for progressive actions
	_clocks			= {};			// [object] of clocked time(s)

	//-------------------------
	// Constructor
	//-------------------------
	// Initializes a new OSConfigurable instance.
	// * options		- [object] Configuration options.
	constructor( options={} ) {
		// Save argument data
		this._options		= options;
	}

	//--------------------------------
	// Plugin Manager
	//--------------------------------
	// Register a plugin.
	// * type	- [string] Value of plugin type.
	// * plugin	- plugin [object] to plug into the system.
	// A plugin may define:
	//  - extend( Class, prototype )	→ called immediately, to augment static or prototype
	//  - init(instance)				→ called in the constructor, to wire instance-level hooks
	// * targetClass  - [string|null] optional name of the class to defer for
	static use( type, plugin ) {
		// -----------------------
		// Because this.plugins is static to OSConfigurable,
		// we will ensure that all children have their own
		// class-specific plugins.
		// -----------------------
		// Shadow plugins per subclass if not already
		if ( !Object.hasOwn( this, 'plugins' ) ) {
			this.plugins = {}; // fork it
			console.log( `[plugin:init] Shadowed plugin map for ${this.name}` );
		}

		// Ensure plugins exist.
		if ( !this.plugins?.[type] )
			this.regPlugins( type );

		// Check if plugin is extending the object's prototype.
		if ( typeof plugin.extend==='function' )
			plugin.extend( this, this.prototype );
		// Check if plugin has an initialization function.
		if ( typeof plugin.init==='function' )
			this.plugins[type].push( plugin.init );
	}

	// Initialize plugins.
	// * type	- [string] Value of plugin type.
	static regPlugins( type ) {
		// Ensure plugin type does not exist.
		if ( this.plugins?.[type] ) {
			//console.warn( `Plugins type "${type}" already registered.` );
			return; // escape
		}
		// Create new plugins type for this.
		this.plugins[type]	= [];
	}

	//-------------------------
	// Initialize plugins scoped to this class (not subclasses)
	//-------------------------
	// * type - [string] Plugin type (e.g. 'tools')
	// RETURNS: [Promise|false]
	static async initPlugins( type, instance ) {
		// Validate caller
		if ( typeof instance!=='object' ) {
			console.error( `[plugin:init] Invalid instance passed to ${this.name}.initPlugins()` );
			return false;
		}

		// Ensure this class owns its own plugins (no inherited leaks)
		if ( !Object.hasOwn(this,'plugins') ) {
			console.warn( `[plugin:init] ${this.name} has no local plugins.` );
			return false;
		}

		// Retrieve plugins for type
		const pluginList = this.plugins[type];
		if ( !pluginList || pluginList.length===0 ) {
			console.warn( `[plugin:init] ${this.name} has no plugins for type '${type}'` );
			return false;
		}

		// Execute plugins with the given instance as context
		for ( const initFn of pluginList ) {
			const isAsync = initFn[Symbol.toStringTag] === 'AsyncFunction';
			if ( isAsync ) await initFn.call( instance, instance );
			else initFn.call( instance, instance );
		}

		return true; // success
	}

	// Counts how many plugins for a type exist.
	// RETURNS: [int] number of registered plugins of given type.
	// * type - [string] Value of plugin type to check (e.g., 'tools', 'filters')
	countPlugins( type ) {
		// Validate plugin type.
		if ( typeof type!=='string' || !type.length ) {
			console.error( 'countPlugins() failed: invalid type:', type );
			return 0;
		}
		// Access plugin set.
		const set = this.constructor.plugins?.[type];
		if ( !set || typeof set!=='object' ) return 0;
		// Return count of plugins under type.
		return Object.keys(set).length;
	}

	//-------------------------
	// Data Methods
	//-------------------------
	// Sets or updates a variable in the container.
	// RETURNS: [void].
	// * name		- [string|array<string>] Path name or group + key (e.g., ['group', 'key']).
	// * value		- [...] Value to store.
	set( name, value ) {
		if ( Array.isArray(name) ) {
			const [group,key] = name;
			if ( !(group in this._data) )
				this._data[group] = {};
			this._data[group][key] = value;
		}
		else {
			name = jsos.pathologize( name );
			this._data[name] = value;
		}
	}

	// Retrieves a variable from the container (optionally removes it).
	// RETURNS: [...] Value of the variable, or `false` if not found.
	// * name		- [string|array<string>] Path name or group + key.
	// * wipe		- [boolean] Whether to remove the variable (default: false).
	get( name, wipe=false ) {
		if ( Array.isArray(name) ) {
			const [group,key] = name;
			if ( group in this._data && key in this._data[group] ) {
				const value = this._data[group][key];
				if ( wipe )
					delete this._data[group][key];
				return value;
			}
		}
		else {
			name = jsos.pathologize( name );
			if ( name in this._data ) {
				const value = this._data[name];
				if ( wipe )
					delete this._data[name];
				return value;
			}
		}
		return false;
	}

	// Checks if a variable exists in the container.
	// RETURNS: [boolean] `true` if the variable exists, `false` otherwise.
	// * name		- [string|array<string>] Path name or group + key.
	has( name ) {
		if ( Array.isArray(name) ) {
			const [group,key] = name;
			return group in this._data && key in this._data[group];
		}
		else {
			name = jsos.pathologize( name );
			return name in this._data;
		}
	}

	// Deletes variables from the container.
	// RETURNS: [boolean] `true` if successful, `false` otherwise.
	// * ...names	- [array<string>] Path names or group + key to delete.
	unset( ...names ) {
		names.forEach( ( name ) => {
			if ( Array.isArray(name) ) {
				const [group,key] = name;
				if ( group in this._data && key in this._data[group] ) {
					delete this._data[group][key];
				}
			}
			else {
				name = jsos.pathologize( name );
				if ( name in this._data ) delete this._data[name];
			}
		});
		return true;
	}

	// Clears all data from the container.
	// RETURNS: [void].
	clear() {
		this._data = {}; // Reset the container.
	}

	// Temporarily pushes a value onto `_temp` and pops it off.
	// RETURNS: [...] Pushed or popped value.
	// * lever   - [boolean] Whether to push (true) or pop (false).
	// * name    - [string] Key name to store the variable under.
	// * value   - [...] Value to temporarily store (only used if `lever` is true).
	pushpop( lever=true, name='variable', value=null ) {
		this._temp = this._temp || {}; // Ensure `_temp` exists.
		if ( lever ) {
			// Push value onto `_temp`.
			this._temp[name] = value;
			return value;
		}
		else {
			// Pop value off `_temp`.
			const result = this._temp[name] ?? null;	// Retrieve and ensure null fallback.
			delete this._temp[name];					// Remove key from `_temp`.
			return result;
		}
	}

	// Finds variables in `_data` by path patterns, including wildcards.
	// RETURNS: [object|false] Matches as key-value pairs, or false if no matches.
	// * ...args	- [array<string>] Paths or patterns to search for (e.g., 'group/*').
	// NOTES:
	// - Use `*` for wildcard matches (e.g., 'group/*').
	// - If `snip` is provided, trims the specified number of path parts.
	herd( ...args ) {
		// Ensure `_temp` exists.
		this._temp		= this._temp || {};
		// Retrieve and clear the `snip` value from `_temp`.
		const snip		= this.pushpop( false, 'snip' ); // Pop temporary snip value.
		const matches	= {};
		let found		= false;
		// Process each argument.
		args.forEach(
			( arg ) => {
				const name			= jsos.pathologize( arg );
				const hasWildcard	= name.includes( '*' );
				// Handle wildcards.
				if ( hasWildcard ) {
					const pathParts	= name.split( '/' );
					const loose		= pathParts[pathParts.length-1] === '*';
					// Search `_data` for matches.
					for ( const key in this._data ) {
						const keyParts	= key.split( '/' );
						// Skip if the key is shorter than the path pattern.
						if ( keyParts.length<pathParts.length ) continue;
						// Check each part of the key against the pattern.
						let match		= true;
						for ( let i=0; i<pathParts.length; i++ ) {
							// If loose match, accept any extra parts beyond the wildcard.
							if ( i>=pathParts.length-1 && loose ) break;
							// Skip if parts don't match and it's not a wildcard.
							if ( pathParts[i]!=='*' && pathParts[i]!==keyParts[i] ) {
								match	= false;
								break;
							}
						}
						// If matched, add to results.
						if ( match ) {
							found = true;
							matches[key] = this._data[key];
						}
					}
				}
				// Handle exact matches.
				else if ( this.has(name) ) {
					found = true;
					matches[name] = this._data[name];
				}
			});

		// Return false if no matches found.
		if ( !found ) return false;

		// Apply `snip` logic to trim path parts if needed.
		if ( typeof snip==='number' && snip>0 ) {
			const trimmedMatches = {};
			Object.keys(matches).forEach(
				( key ) => {
					const keyParts		= key.split( '/' );
					// Skip if snipping would remove the entire key.
					if ( keyParts.length<=snip ) return;
					// Trim path parts and reindex.
					const trimmedKey	= keyParts.slice(snip).join('/');
					trimmedMatches[trimmedKey] = matches[key];
				});
			return trimmedMatches;
		}

		// Return result(s)
		return matches;
	}

	//-------------------------
	// Dynamic Var Method(s)
	//-------------------------
	// Set a dynamic variable.
	// RETURNS: [bool] `true` on success, else `false`.
	// * key	- [string] name of key to set.
	// * val	- [string] value of var.
	jot( key, val ) {
		//console.log( 'jestAlert: Changing var ...' );
		this._vars[key]	= val;
		return true; // success
	}

	// Get a dynamic variable.
	// RETURNS: [string] value of dynamic var.
	// * key	- [string] name of key to set.
	//   pop	- [bool] whether to pop the item off (delete it).
	skim( key, pop=false ) {
		//console.log( 'jestAlert: Getting var ...' );
		if ( !(key in this._vars) )
			this._vars[key]	= null;
		const val	= this._vars[key];		// get value
		if ( pop ) delete this._vars[key];	// remove value
		return val; // return value
	}

	//-------------------------
	// Timer Functions
	//-------------------------
	// Timer method: returns elapsed time in milliseconds
	//   name		- [string] Optional name of the clock (default: 'default')
	//   datetime	- [boolean] Whether to log Date.now(), or performance ( defaults to false, e.g. performance.now() )
	//   report		- [boolean] Whether to console log a report
	_clock( name='default', datetime=false, report=false ) {
		// Ensure clock storage exists
		if ( !this._clocks ) this._clocks = {};
		// Get current timestamp
		const now		= !datetime ? performance.now() : Date.now();
		// Calculate time difference
		const elapsed	= !this._clocks[name] ? 0 : now - this._clocks[name];
		// Update stored timestamp
		this._clocks[name] = now;
		// Output a report if requested
		if ( report )
			console.log( `Clock '${name}' recorded: ${elapsed / 1000} seconds` );
		return elapsed; // Return time
	}
}

/* --- BEGIN js/os/OSCallback.js --- */

// OSCallback class
class OSCallback extends OSConfigurable {
	// Element properties
	handlers		= {};			// [array] of event callback(s): [{ command, id, callback, type }]

	//-------------------------
	// Initialization
	//-------------------------
	// Initializes a new OSCallbacks instance.
	// * options		- [object] Configuration options.
	//   callbacks		- [array] Array of callback definitions.
	constructor( options={} ) {
		super( options ); // call parent constructor
	}

	// Apply the [object] initial callback(s) if set.
	// RETURNS: [boolean] `true` on success else `false` on fail.
	initCallbacks() {
		// Apply callbacks if exists.
		if ( this._options.callbacks )
			this._initializeCallbacks( this._options.callbacks );
		return true; // success
	}

	//-------------------------
	// Private Methods
	//-------------------------
	// Initializes callbacks from options (if provided).
	// RETURNS: [void] Nothing.
	// * callbacks		- [array] Array of callback definitions.
	_initializeCallbacks( callbacks ) {
		// Iterate eeach callback & register.
		callbacks.forEach(
			( { command, id, callback, type='manual', iterations=null, data={} } ) => {
				this.register( command, id, callback, type, iterations, data );
			});
	}

	//-------------------------
	// Check Registration
	//-------------------------
	// Determines whether a callback is already registered.
	// RETURNS: [boolean] True if registered, else False.
	// * command	- [string|array] Event name or array of names.
	// * id			- [string] Unique callback ID.
	isRegistered( command, id ) {
		//--------------------------------
		// Validate Argument(s)
		//--------------------------------
		if ( typeof id!=='string' || (!Array.isArray(command) && typeof command!=='string') ) {
			console.warn( `OSCallback.isRegistered(): invalid argument(s). command=${command}, id=${id}` );
			return false;
		}

		//--------------------------------
		// Handle Array of Commands
		//--------------------------------
		if ( Array.isArray(command) ) {
			// If ANY command contains the ID, consider it registered.
			for ( const cmd of command ) {
				if ( this.isRegistered(cmd,id) )
					return true;
			}
			return false;
		}

		//--------------------------------
		// Access Handler List
		//--------------------------------
		const list = this.handlers?.[command];
		if ( !Array.isArray(list) ) return false; // no such command

		//--------------------------------
		// Check for Matching ID
		//--------------------------------
		return list.some( handler => handler.id===id );
	}

	//--------------------------------
	// Register Callback(s)
	//--------------------------------
	// Registers a callback under one or more event names.
	// RETURNS: [boolean] `true` on success else `false` on fail.
	// * command		– [string|array] Event name or array of event names.
	// * id				– [string] Unique ID for the callback.
	// * callback		– [function] The callback function.
	// * type			– [string] Type of callback (default: 'manual').
	// * iterations		– [number|null] Max invocations (null = unlimited).
	// * data			– [object] Additional data (used by extended subclasses).
	register( command, id, callback, type='manual', iterations=null, data={} ) {
		// Handle multiple commands.
		if ( Array.isArray(command) ) {
			let allRegistered = true;
			command.forEach(
				cmd => {
					const success = this.register( cmd, id, callback, type, iterations, { ...data } );
					if ( !success ) allRegistered = false;
				});
			return allRegistered;
		}
		// Create the event category if it doesn't exist.
		if ( !this.handlers[command] )
			this.handlers[command] = [];
		// Prevent duplicate ID registration under same command.
		if ( this.handlers[command].some(handler=>handler.id===id) ) {
			console.warn( `Callback with ID "${id}" is already registered for event "${command}".` );
			return false; // failed
		}
		// Bind & store the handler.
		this.handlers[command].push({
			id,
			callback	: callback.bind(this),
			type,
			iterations,
			iteration	: 0,
			data
			});
		return true; // success
	}

	// -------------------------
	// Helper: Is Promise-like
	// -------------------------
	// RETURNS: [bool] Whether v is thenable (Promise-like).
	// * v	- [any]
	_isThenable( v ) {
		return v!=null && (typeof v==='object' || typeof v==='function') && typeof v.then==='function';
	}

	// -------------------------
	// Helper: Parse stack for file:line:col
	// -------------------------
	// RETURNS: [object] { file, line, col } best-effort from error stack.
	// * err	- [Error]
	_parseStack( err ) {
		try {
			const s = String( err?.stack || '' );
			const lines = s.split( '\n' );
			for ( const line of lines ) {
				// Match patterns:
				// Chrome:    at func (path/file.js:123:45)
				// Firefox:   func@path/file.js:123:45
				// Node:      at path/file.js:123:45
				const match = line.match(/(?:at\s+)?(?:.*?@)?(.+?):(\d+):(\d+)/);
				if ( match ) {
					const [, file, lineNum, colNum] = match;
					return {
						file,
						line: Number(lineNum),
						col: Number(colNum)
					};
				}
			}
		} catch(e) {}
		// Return generic error (no filename & line #)
		return { file:'<unknown>', line:0, col:0 };
	}


	// -------------------------
	// Trigger (Async-Aware)
	// -------------------------
	// Triggers a specific callback by ID under an event name.
	// RETURNS: [Promise<any>] Resolves/rejects based on the callback.
	// * command	- [string] Name of the event.
	// * id			- [string] ID of the callback to trigger.
	// * args		- [any] Arguments to pass to the callback.
	async _trigger( command, id, ...args ) {
		// Require callbacks by command to exist.
		const callbacks = this.handlers?.[command];
		if ( !callbacks ) {
			console.warn( `No handlers found for event: ${command}` );
			return;
		}

		// Access handler & attempt to trigger a callback.
		const handler = callbacks.find( (h)=>h.id===id );
		if ( !handler || typeof handler.callback!=='function' ) {
			console.warn( `Handler with ID "${id}" not found for event "${command}".` );
			return;
		}

		//try {
			// Call; await if Promise-like. Works for both sync & async functions.
			const result	= handler.callback( ...args );
			const awaited	= this._isThenable(result) ? await result : result;

			// Track handler iterations AFTER successful completion.
			if ( handler.iterations!==null ) {
				handler.iteration++;
				if ( handler.iteration>=handler.iterations )
					this.unregister( command, id );
			}
			return awaited;
		//}
		/*catch ( err ) {
			// Extract file:line:col for precise reporting (your hard requirement).
			const { file, line, col } = this._parseStack( err );
			console.error(
				`[OSCallback] Error in handler "${id}" for "${command}" at ${file}:${line}:${col} — ${err?.message||err}`,
				err );
			throw err; // let caller policy decide (log/throw/skip)
		}*/
	}

	//-------------------------
	// Emit (Safe Serial Async, No Await Required)
	//-------------------------
	// Triggers handlers in order, respecting limit, and auto-waits for Promises.
	// RETURNS: [void] Never returns early; all handlers guaranteed to complete.
	// * command	– [string] Event name to emit.
	// * limit		– [int|null] Max number of callbacks to run (null = all).
	// * args		– [any] Arguments to pass to handlers.
	emit( command, limit=null, ...args ) {
		// Access requested callback (by command name).
		const callbacks = this.handlers?.[command];
		if ( !callbacks || !Array.isArray(callbacks) ) return; // no event by command name

		// Filter only manual handlers and respect limit.
		const list	= callbacks.filter( h => h.type==='manual' );
		const slice	= (limit===null) ? list : list.slice( 0, Math.max(0,limit) );

		// Run each handler serially, awaiting if it's a Promise.
		(async()=>{
			// Iterate each requested handler.
			for ( const h of slice ) {
				//try {
					// Call a requested handler.
					const result = h.callback( ...args );
					if ( this._isThenable(result) ) await result;

					// Track iterations.
					if ( h.iterations!==null ) {
						h.iteration++; // continue to next iteration
						if ( h.iteration>=h.iterations )
							this.unregister( command, h.id );
					}
				//}
				/*catch ( err ) { // error
					const { file, line, col } = this._parseStack(err);
					console.error(
						`[OSCallback] Error in handler "${h.id}" for "${command}" at ${file}:${line}:${col} — ${err?.message||err}`
						);
				}*/
			}
		})();
	}


	// -------------------------
	// EmitAsync (Configurable)
	// -------------------------
	// Configurable async emitter.
	// RETURNS: [Promise<void|any[]>] Serial resolves void; parallel resolves results array.
	// * command	- [string] Name of event to emit.
	// * options	- [null|int|object] { limit:[int|null], mode:'serial'|'parallel', onError:'throw'|'log'|'skip' }
	//      NOTE: If [null] or [int], options treats argument as options.limit=[int|null]
	// * args		- [any]
	async emitAsync( command, options={}, ...args ) {
		// Process user supplied options.
		//if ( options===null || Number.isInteger(options) )
		//	options	= { limit: options }; // generic object
		const { limit=null, mode='serial', onError='throw' } = options;
		const callbacks = this.handlers?.[command]; // access requested callback (by command name)
		if ( !callbacks || !Array.isArray(callbacks) ) return; // no callback found

		// Filter eligible handlers (manual only) and enforce limit.
		const list	= callbacks.filter( h => h.type==='manual' );
		const slice	= (limit===null) ? list : list.slice( 0, Math.max(0,limit) );

		if ( mode==='parallel' ) {
			// Fire all and wait. Error policy via allSettled + onError.
			const promises	= slice.map( h=>this._trigger(command, h.id, ...args) );
			const settled	= await Promise.allSettled( promises );
			if ( onError==='throw' ) {
				const firstRej = settled.find( s => s.status==='rejected' );
				if ( firstRej ) throw firstRej.reason;
			}
			if ( onError==='log' ) {
				settled.forEach(
					( s ) => {
						if ( s.status==='rejected' )
							console.warn( '[emitAsync] handler rejected:', s.reason );
					});
			}
			// 'skip' simply ignores rejections.
			return settled.map( s => s.status==='fulfilled' ? s.value : undefined );
		}

		// Default: serial (predictable order + easier reasoning).
		for ( const h of slice ) {
			try {
				await this._trigger( command, h.id, ...args );
			}
			catch (err) {
				if ( onError==='throw' ) throw err;
				if ( onError==='log' )
					console.warn( '[emitAsync] handler error (logged and continuing):', err );
				// 'skip' falls through
			}
		}
	}

	//--------------------------------
	// Unregister Callback(s)
	//--------------------------------
	// Unregisters a callback by one or more event names.
	// RETURNS: [void] Nothing.
	// * command	– [string|array] Event name or array of names.
	// * id		– [string] ID of the callback to unregister.
	unregister( command, id ) {
		// Handle multiple commands.
		if ( Array.isArray(command) ) {
			command.forEach( cmd => this.unregister(cmd,id) );
			return;
		}
		// Remove handler(s) for the command if present.
		if ( this.handlers?.[command] ) {
			this.handlers[command] = this.handlers[command].filter( (handler)=>handler.id!==id );
			// Clean up empty categories.
			if ( this.handlers[command].length===0 )
				delete this.handlers[command];
		}
	}
}

