// Jest HTML DOM Element class
class OSElement extends OSEventTarget {
	// Element properties
	el				= null;		// DOM element [object]
	tag				= null;		// DOM element type [string]
	id				= null;		// id [string] attribute value of DOM element
	classes			= null;		// class(es) [stray] attribute value of DOM element
	attributes		= null;		// [object] of attributes
	text			= null;		// [string] value of inner text

	// Creates the class [object] with configurable components.
	// RETURNS: [object] A new instance.
	// * options		- [object] Configuration options for the class [object].
	constructor( options={} ) {
		super( options ); // call parent constructor
		this.tag			= options.tag || 'div';			// [string] value of HTML markup tag
		// Setup element properties
		this.id				= options.id ?? null;			// HTML id [string] value
		this.classes		= options.classes ?? [];		// HTML class(es) [stray] value(s)
		let	classesDataType	= jsos.datatype( this.classes );
		if ( classesDataType!=='array' )
			this.classes	= classesDataType==='string' ? [this.classes] : [];
		this.attributes		= options.attributes || {};
		this.text			= options.text ?? '';
	}

	// --------------------------------
	// Initialization
	// --------------------------------
	// Setup the DOM element [object].
	// RETURNS: [boolean] `true` on success else `false` on fail.
	setup() {
		return super.setup();	// call parent setup method
	}

	// Render the OSElement [object].
	// RETURNS: [boolean] `true` on success else `false` on fail.
	render() {
		// --------------------------------
		// Create the DOM Element
		// --------------------------------
		this.createElement();				// Create the DOM element [object]
		this.initCallbacks();				// apply initial callback(s)
		//this._attachEventListeners();		// apply callback listeners
		return true;						// sucess
	}

	// Creates the DOM element for the [object].
	// RETURNS: [object] The created DOM element.
	createElement() {
		// Create the DOM element for the panel.
		const el	= jsos.generateElement( this.tag, this.id, this.classes, this.text, this.objectURL );
		this.el		= el;					// cross-reference to DOM element
		// Inject inner text content.
		this.el.innerHTML	= this.text;	// clear existing content
		// Use enhanced attribute method instead of raw loop
		if ( typeof this.attributes==='object' && this.attributes!==null )
			this.addAttributes( this.attributes );
	}

	//--------------------------------
	// Append child element
	//--------------------------------
	// RETURNS: [void]
	// * child - [Element|OSElement] Element to append
	append( child ) {
		if ( child instanceof OSElement )
			this.el.appendChild( child.el );
		else this.el.appendChild( child );
	}

	// Prepend child element
	// RETURNS: [void]
	// * child - [Element|OSElement] Element to prepend
	prepend( child ) {
		if ( child instanceof OSElement )
			this.el.prepend( child.el );
		else this.el.prepend( child );
	}

	// Remove this element from the DOM
	// RETURNS: [void]
	remove( ) {
		// Attempt to remove the element from the DOM.
		this.el.remove(); // remove DOM element
	}

	// Remove all child elements
	// RETURNS: [void]
	clear( ) {
		// Set inner HTML as empty.
		this.el.innerHTML = ''; // clear inner HTML
	}

	//-----------------------------
	// Insert Child at Specific Index
	//-----------------------------
	// Inserts a child [OSElement|Element] at a specific index inside this element.
	// RETURNS: [bool] true on success, false on failure.
	// * child	- [OSElement|Element] element to insert
	// * index - [int] target position to insert at
	insertAt( child, index=null ) {
		// Validate base element
		if ( !this.el || !(this.el instanceof Element) ) {
			console.error( 'insertAt() failed: invalid parent element:', this.el );
			return false;
		}
		// Resolve raw DOM element
		const newEl = ( child instanceof OSElement ) ? child.el : child;
		if ( !(newEl instanceof Element) ) {
			console.error( 'insertAt() failed: invalid child element:', newEl );
			return false;
		}

		// Clamp index if out of range
		const children = this.el.children;
		if ( index>=children.length || index==null ) {
			this.el.appendChild( newEl );
			return true;
		}
		else if ( index <= 0 ) {
			this.el.prepend( newEl );
			return true;
		}

		// Insert before the node currently at the target index
		this.el.insertBefore( newEl, children[index] );
		return true;
	}

	//-----------------------------
	// Reorder Existing Child
	//-----------------------------
	// Moves an existing child element to a new index.
	// RETURNS: [bool] true on success, false on failure.
	// * child		- [OSElement|Element] element to reposition
	// * newIndex	- [int|string|null] target index, or -1/'end' to push to end
	reorderChild( child, newIndex ) {
		//--------------------------------
		// Validate Parent Element
		//--------------------------------
		// Validate parent element
		if ( !this.el || !(this.el instanceof Element) ) {
			console.error( 'reorderChild() failed: invalid parent element:', this.el );
			return false;
		}

		//--------------------------------
		// Resolve Child Element
		//--------------------------------
		// Resolve DOM element
		const movingEl = ( child instanceof OSElement ) ? child.el : child;
		if ( !(movingEl instanceof Element) || !this.el.contains(movingEl) ) {
			console.error( 'reorderChild() failed: element is not a valid child of this.el:', movingEl );
			return false;
		}

		//--------------------------------
		// Remove Element Temporarily
		//--------------------------------
		// Temporarily remove element and reinsert at new index
		this.el.removeChild( movingEl );

		//--------------------------------
		// Handle Special Case: Push to End
		//--------------------------------
		// Allow 'end', -1, or null to mean "append to end"
		if (
			newIndex===-1 || newIndex===null ||
			newIndex===undefined || newIndex==='end'
		) {
			this.el.appendChild( movingEl ); // standard DOM append
			return true;
		}

		//--------------------------------
		// Insert at Requested Index
		//--------------------------------
		return this.insertAt( movingEl, newIndex );
	}

	//--------------------------------
	// DOM Class Handling
	//--------------------------------
	// Add class(es) to [this.el], if not already present.
	// RETURNS: [bool] true on success, false on error.
	// * classes - [string|string[]] Class or array of classes to add.
	addClass( classes=[] ) {
		// Validate element
		if ( !this.el || !(this.el instanceof Element) ) {
			console.error( 'addClass() failed: invalid element:', this.el );
			return false;
		}
		// Normalize input
		if ( typeof classes==='string' ) classes = [ classes ];
		if ( !(classes instanceof Array) ) {
			console.error( 'addClass() failed: invalid classes input:', classes );
			return false;
		}
		// Add only missing classes
		for ( const cls of classes ) {
			if ( typeof cls!=='string' ) continue;
			if ( !this.el.classList.contains(cls) )
				this.el.classList.add( cls );
		}
		return true;
	}

	// Remove class(es) from [this.el], only if present.
	// RETURNS: [bool] true on success, false on error.
	// * classes - [string|string[]] Class or array of classes to remove.
	removeClass( classes=[] ) {
		// Validate element
		if ( !this.el || !(this.el instanceof Element) ) {
			console.error( 'removeClass() failed: invalid element:', this.el );
			return false;
		}
		// Normalize input
		if ( typeof classes==='string' ) classes = [ classes ];
		if ( !(classes instanceof Array) ) {
			console.error( 'removeClass() failed: invalid classes input:', classes );
			return false;
		}
		// Remove only existing classes
		for ( const cls of classes ) {
			if ( typeof cls!=='string' ) continue;
			if ( this.el.classList.contains(cls) )
				this.el.classList.remove( cls );
		}
		return true;
	}

	//--------------------------------
	// Check for presence of class(es)
	//--------------------------------
	// RETURNS: [bool] true if all classes exist, false otherwise
	// * classes - [string|string[]] Class or array of classes to check
	hasClass( classes=[] ) {
		// Validate element
		if ( !this.el || !(this.el instanceof Element) ) {
			console.error( 'hasClass() failed: invalid element:', this.el );
			return false;
		}
		// Normalize input
		if ( typeof classes==='string' ) classes = [ classes ];
		if ( !(classes instanceof Array) ) {
			console.error( 'hasClass() failed: invalid classes input:', classes );
			return false;
		}
		// Check if all classes exist
		for ( const cls of classes ) {
			if ( typeof cls!=='string' ) continue;
			if ( !this.el.classList.contains(cls) )
				return false; // one or more class missing
		}
		return true; // all classes present
	}

	//--------------------------------
	// Toggle class(es) on [this.el]
	//--------------------------------
	// Add or remove class(es) based on state.
	// RETURNS: [bool] true on success, false on error.
	// * classes	- [string|string[]] Class or array of classes to toggle.
	// * state		- [bool] true=add, false=remove
	toggleClass( classes=[], state=true ) {
		// Validate element
		if ( !this.el || !(this.el instanceof Element) ) {
			console.error( 'toggleClass() failed: invalid element:', this.el );
			return false;
		}
		// Normalize input
		if ( typeof classes==='string' ) classes = [ classes ];
		if ( !(classes instanceof Array) ) {
			console.error( 'toggleClass() failed: invalid classes input:', classes );
			return false;
		}
		// Dispatch to add or remove
		return ( state )
			? this.addClass( classes )
			: this.removeClass( classes );
	}

	//--------------------------------
	// Set Attribute on Element
	//--------------------------------
	// Applies an attribute key/value to the DOM element.
	// RETURNS: [bool] true on success, false on failure
	// * key	- [string] name of attribute to set
	// * value	- [string] value to assign to attribute
	addAttribute( key, value ) {
		// Validate element
		if ( !this.el || !(this.el instanceof Element) ) {
			console.error( 'addAttribute() failed: invalid element:', this.el );
			return false; // fail
		}
		// Validate input
		if ( typeof key!=='string' ) {
			console.error( 'addAttribute() failed: key must be string:', key );
			return false; // fail
		}
		// Update internal config (optional)
		if ( !this.attributes ) this.attributes = {};
		this.attributes[key] = value;
		// Use appropriate setter
		try {
			// Parse HTML inside attribute(s).
			const finalValue = this.useHTMLAttributes ? this.parseHTMLAttrValue(value) : value;
			if ( key==="xmlns" )
				this.el.setAttribute( key, finalValue );
			else this.el.setAttributeNS( null, key, finalValue );
		}
		catch ( err ) { // error
			console.error( `addAttribute() failed for ${key}:`, err );
			return false; // fail
		}
		return true; // success
	}

	// --------------------------------
	// Inner Content Handling
	// --------------------------------
	// Set the inner text of an element.
	// NOTE: This replaces all the inner content.
	// RETURNS: [void]
	// * text	- [string] Content to display insid the element.
	setText( text ) {
		// Replace text content with text.
		this.el.textContent = text;
	}
	// Set the inner HTML of an element.
	// NOTE: This replaces all the inner content.
	// RETURNS: [void]
	// * text	- [string] HTML to display insid the element.
	setHTML( text ) {
		// Replace inner HTML with text.
		this.el.innerHTML = text;
	}

	//--------------------------------
	// Set Multiple Attributes
	//--------------------------------
	// Applies all key/value pairs in one object to DOM.
	// RETURNS: [int] Number of successful attributes set
	// * map - [object] key:value pairs
	addAttributes( map ) {
		// Require element to be set.
		if ( !this.el || !(this.el instanceof Element) ) {
			console.error( 'addAttributes() failed: invalid element:', this.el );
			return 0;
		}
		// Validate argument(s).
		if ( typeof map!=='object' || map===null ) {
			console.error( 'addAttributes() failed: invalid map:', map );
			return 0;
		}
		// Iterate attributes & set them.
		let count = 0;
		for ( const key in map ) {
			if ( typeof key!=='string' ) continue;
			const val = map[key];
			if ( this.addAttribute(key,val) )
				count++;
		}
		return count; // return success
	}

	//--------------------------------
	// Parse HTML Escaped Attribute Value
	//--------------------------------
	// Converts HTML entities like &lt;kbd&gt; into actual HTML tags.
	// RETURNS: [string] parsed HTML string
	// * str - [string] HTML-encoded text
	parseHTMLAttrValue( str ) {
		if ( typeof str!=='string' || !str.includes('&lt;') ) return str;
		const div = document.createElement('div');
		div.innerHTML = str;
		return div.textContent ?? str;
	}

	//--------------------------------
	// Unset Attribute from Element
	//--------------------------------
	// Removes a single attribute from DOM and internal map.
	// RETURNS: [bool] true if removed, false on fail
	// * key - [string] name of attribute to remove
	removeAttribute( key ) {
		// Require element to be set.
		if ( !this.el || !(this.el instanceof Element) ) {
			console.error( 'removeAttribute() failed: invalid element:', this.el );
			return false; // fail
		}
		// Validate argument(s).
		if ( typeof key!=='string' ) {
			console.error( 'removeAttribute() failed: key must be string:', key );
			return false; // fail
		}
		// Attempt to remove an attribute.
		try {
			this.el.removeAttribute( key );
			if ( this.attributes && this.attributes.hasOwnProperty(key) )
				delete this.attributes[key];
		}
		catch ( err ) { // handle error
			console.error( `removeAttribute() failed for ${key}:`, err );
			return false; // fail
		}
		return true; // success
	}

	//-----------------------------
	// Positioning DOM element.
	//-----------------------------
	// Resize the DOM element.
	// RETURNS: [void].
	// * width	- [int] Value of new width or [null] for no change.
	// * height	- [int] Value of new height or [null] for no change.
	resize( width, height ) {
		// Resize the DOM element style width and/or height.
		if ( width!==null ) // update element width
			this.el.style.width		= `${width}px`;
		if ( height!==null ) // update element height
			this.el.style.height	= `${height}px`;
	}
	// Expand the DOM element by some amount (adds to existing size).
	// RETURNS: [void]
	// * dw - [int|null] Amount to increase width (optional)
	// * dh - [int|null] Amount to increase height (optional)
	expand( dw=null, dh=null ) {
		// Get existing style(s).
		const style	= window.getComputedStyle( this.el );
		// Parse current size as integer
		const currW	= parseInt( style.width, 10 );
		const currH	= parseInt( style.height, 10 );
		// Apply added dimensions
		if ( dw!==null )
			this.el.style.width  = `${currW + dw}px`;
		if ( dh!==null )
			this.el.style.height = `${currH + dh}px`;
	}
	// Moves an element using the top|left|bottom|right style properties.
	// RETURNS: [void]
	// * top     - [int|null] New top offset in pixels (optional)
	// * left    - [int|null] New left offset in pixels (optional)
	// * bottom  - [int|null] New bottom offset in pixels (optional)
	// * right   - [int|null] New right offset in pixels (optional)
	move ( top=null, left=null, bottom=null, right=null ) {
		if ( top!==null )
			this.el.style.top    = `${top}px`;
		if ( left!==null )
			this.el.style.left   = `${left}px`;
		if ( bottom!==null )
			this.el.style.bottom = `${bottom}px`;
		if ( right!==null )
			this.el.style.right  = `${right}px`;
	}

	//-----------------------------
	// Positioning DOM element.
	//-----------------------------
	// Get the relative position of a mouse click event.
	// RETURNS: [void]
	// * event	- event [object] sent through mouse event.
	mousePos( event ) {
		// Get the bounding rect.
		const rect = this.el.getBoundingClientRect();
		return {
			x: event.clientX - rect.left,
			y: event.clientY - rect.top
			};
	}

	//--------------------------------
	// Show DOM Element
	//--------------------------------
	// Makes DOM element visible.
	// RETURNS: [void]
	show() {
		// See if element exists.
		if ( !this.el ) return;
		// Remove "hidden" class from element.
		this.removeClass( 'hidden' );
	}

	//--------------------------------
	// Hide DOM Element
	//--------------------------------
	// Hides DOM element from document.
	// RETURNS: [void]
	hide() {
		// See if element exists.
		if ( !this.el ) return;
		// Add "hidden" class to element.
		this.addClass( 'hidden' );
	}
}

/* --- BEGIN js/system/dom/element/ElementCanvas.js --- */

// ElementCanvas class
class ElementCanvas extends OSElement {
	// Attribute properties
	// Movement propert(ies)
	anchor			= null;			// [object] Anchor for matrix handling.
	width			= 100;			// [int] value of canvas width
	height			= 100;			// [int] value of canvas height

	// Creates the class [object] with configurable components.
	// RETURNS: [object] A new instance.
	// * options		- [object] Configuration options for the class [object].
	constructor( options={} ) {
		// --------------------------------
		// Configure DOM "Canvas" Data
		// --------------------------------
		options.tag		= 'canvas';
		super( options );	// call OSObject parent constructor
		// Handle default canvas size
		this.width		= options.width ? options.width : this.width;
		this.height		= options.height ? options.height : this.height;
		// Setup the [object] before creating the element
		this.setup();		// setup the [object]
		this.render();		// render the [object]
	}

	// Setup the [object].
	// RETURNS: [boolean] true or false.
	setup() {
		// --------------------------------
		// Setup Canvas [object]
		// --------------------------------
		super.setup();		// call parent setup method
		// Ensure class(es) include element base class(es)
		this.classes.push( 'jest-canvas' );
		// --------------------------------
		// Create Anchor [object]
		// --------------------------------
		// Create an anchor [object] for moving & size specifications
		const anchor	= new Anchor();		// create central anchor
		anchor.move( 0, 0 );				// move anchor to default position
		this.anchor		= anchor;			// store anchor as property
		return true;		// success
	}

	// Render the [object].
	// RETURNS: [boolean] true or false.
	render() {
		// --------------------------------
		// Add Event Handler(s)
		// --------------------------------
		// Add resize event handler for canvas updating
		this.anchor.register( 'resize', 'canvas', (w,h)=>this.resize(w,h) );
		// --------------------------------
		// Render Canvas
		// --------------------------------
		super.render();		// call parent render method
		// --------------------------------
		// Default Orientation(s)
		// --------------------------------
		this.resize ( this.width, this.height );
		return true;		// success
	}

	// --------------------------------
	// Sizing & Positioning Method(s)
	// --------------------------------
	// Resize the DOM canvas.
	// RETURNS: [boolean] `true` on success else `false` on fail.
	// * width	- [int] Value of new width.
	// * height	- [int] Value of new height.
	resize( width=100, height=100 ) {
		// Validate argument(s)
		if ( !Number.isInteger(width) ) {
			console.error( `Argument "width" must be an integer.` );
			width	= 100;
		}
		if ( !Number.isInteger(height) ) {
			console.error( `Argument "width" must be an integer.` );
			height	= 100;
		}
		// Set width & height
		this.width		= Math.max( 0, width );		// save new width
		this.height		= Math.max( 0, height );	// save new height
		this.el.width	= width;					// update element width
		this.el.height	= height;					// update element height
		// Call parent resize() method.
		super.resize( width, height );
		// Ensure anchor dimensions match (fallback)
		this.anchor.width	= width;
		this.anchor.height	= height;
		return true; // success
	}

	// --------------------------------
	// Rendering Method(s)
	// --------------------------------
	// Render an image into the display.
	// RETURNS: [void].
	// * canvas	- [object] ElementCanvas object to render inside the display.
	// clear	- [bool] Whether to clear area first.
	// resize	- [bool] Whether to resize the canvas to match the sw,sh.
	// dx,dy	- [number] Coordinates of location on destination canvas to draw.
	// sx,sy	- [number] Coordinates of location on source canvas to clip.
	// sw,sh	- [number] Width and height dimensions of source canvas to clip.
	draw( canvas, clear=false, resize=false, dx=0, dy=0, sx=0, sy=0, sw=null, sh=null ) {
		// Set auto dimension(s) if not supplied.
		const w	= sw ?? canvas.el.width;
		const h	= sh ?? canvas.el.height;
		// Get tooldrop canvas context & clear it.
		const ctx	= this.el.getContext( '2d' );
		// Clear area if requested.
		if ( clear )
			ctx.clearRect( 0, 0, w, h );
		// Resize crate to show contents if requested.
		if ( resize )
			this.resize( w, h );

		// Draw the selected tile on the dragdrop crate canvas.
		ctx.drawImage(
			canvas.el,			// image contents being copied
			sx,    sy,			// source crop x,y
			w,     h,			// source W x H
			dx,    dy,			// destination x,y
			w,     h			// destination W x H
			);
	}

	//--------------------------------
	// Load & Copy Image to Canvas
	//--------------------------------
	// Copies an image & resizes canvas to match its dimensions & pixels.
	// RETURNS: [boolean] `true` on success else `false` on fail.
	// * image	– [ElementImage] to conform to & replicate pixels.
	// clear	- [bool] Whether to clear area first.
	// resize	- [bool] Whether to resize the canvas to match the sw,sh.
	// dx,dy	- [number] Coordinates of location on destination canvas to draw.
	// sx,sy	- [number] Coordinates of location on source canvas to clip.
	// sw,sh	- [number] Width and height dimensions of source canvas to clip.
	copyImage( image, clear=false, resize=false, dx=0, dy=0, sx=0, sy=0, sw=null, sh=null ) {
		//--------------------------------
		// Safety Check: Image Must Be Loaded
		//--------------------------------
		// Check if image is fully loaded & has dimension.
		if ( !image.el.complete || image.el.naturalWidth===0 ) {
			console.warn( 'Image not fully loaded or invalid' );
			return false; // abort
		}

		//--------------------------------
		// Create Canvas and Draw Image
		//--------------------------------
		// Get dimension(s) if not supplied.
		const w	= sw ?? image.el.naturalWidth;
		const h	= sh ?? image.el.naturalHeight;
		// Resize canvas to match image dimensions.
		if ( resize )
			this.resize( w, h );

		//--------------------------------
		// Copy Image to Canvas
		//--------------------------------
		// Access canvas context & copy image.
		const ctx = this.el.getContext( '2d' );
		// Clear area if requested.
		if ( clear )
			ctx.clearRect( 0, 0, w, h );
		// Draw the selected tile on the dragdrop crate canvas.
		ctx.drawImage(
			image.el,		// image contents being copied
			sx,    sy,		// source crop x,y
			w,     h,		// source W x H
			dx,    dy,		// destination x,y
			w,     h		// destination W x H
			);
		return true; // success
	}

	//--------------------------------
	// Crop Canvas Region
	//--------------------------------
	// Crops a rectangular region from the current canvas and
	// resizes this canvas to only show that region.
	// RETURNS: [boolean] `true` on success else `false` on fail.
	// * x		– [int] Left coordinate of crop area.
	// * y		– [int] Top coordinate of crop area.
	// * width	– [int] Width of crop area.
	// * height	– [int] Height of crop area.
	crop( x, y, width, height ) {
		//--------------------------------
		// Validate Argument(s)
		//--------------------------------
		// Ensure valid arguments.
		if ( !Number.isFinite(x) || !Number.isFinite(y) ||
			 !Number.isFinite(width) || !Number.isFinite(height) )
			return false; // abort

		if ( width<=0 || height<=0 )
			return false; // abort

		//--------------------------------
		// Create Temporary Offscreen Canvas
		//--------------------------------
		const sourceCanvas = this.el;
		const offCanvas = document.createElement('canvas');
		offCanvas.width = width;
		offCanvas.height = height;

		const offCtx = offCanvas.getContext('2d');
		offCtx.drawImage(
			sourceCanvas,
			x, y,				// source crop origin
			width, height,		// source crop size
			0, 0,				// destination origin
			width, height		// destination size
			);

		//--------------------------------
		// Resize This Canvas and Replace Pixels
		//--------------------------------
		// Resize the canvas.
		this.resize( width, height );

		// Draw image from crop back onto canvas.
		const ctx = this.el.getContext('2d');
		ctx.clearRect( 0, 0, width, height );
		ctx.drawImage( offCanvas, 0, 0 );

		return true; // success
	}

	//--------------------------------
	// Clear Canvas Pixels
	//--------------------------------
	// Clears all pixels without resizing or resetting transforms.
	// RETURNS: [boolean] `true` on success else `false` on fail.
	clear() {
		// Safety check.
		if ( !this.el ) return false; // abort
		// Clear pixel buffer.
		const ctx	= this.el.getContext( '2d' );
		ctx.clearRect( 0, 0, this.el.width, this.el.height );
		return true; // success
	}

	//--------------------------------
	// Reset Canvas
	//--------------------------------
	// Clears canvas by resetting dimensions (resets state).
	// RETURNS: [boolean] `true` on success else `false` on fail.
	reset() {
		// Reset via dimension reassignment.
		this.el.width	= this.width;
		this.el.height	= this.height;
		return true; // success
	}

	//--------------------------------
	// Destroy Canvas Content
	//--------------------------------
	// Shrinks canvas to 0x0 to fully erase and disable rendering.
	// RETURNS: [boolean] `true` on success else `false` on fail.
	collapse() {
		// Collapse canvas.
		this.resize( 0, 0 );
		return true; // success
	}
}

/* --- BEGIN js/system/dom/element/ElementImage.js --- */

// ElementImage class
class ElementImage extends OSElement {
	// Attribute properties
	url				= null;			// [string] value of src URL

	//-------------------------
	// Setup [Object]
	//-------------------------
	// Creates the class [object] with configurable components.
	// RETURNS: [object] A new instance.
	// * options		- [object] Configuration options for the class [object].
	constructor( options={} ) {
		// Parse some data
		options.tag		= 'img';
		super( options );	// call OSObject parent constructor
		this.jot( 'source', 'empty' ); // set status
		// Setup the [object] before creating the element
		this.setup();		// setup the [object]
		this.render();		// render the [object]
		// Call load complete if source preloaded
		this.isReady();
	}

	// Setup the [object].
	// RETURNS: [boolean] true or false.
	setup() {
		super.setup();	// call parent setup method
		// Ensure class(es) include element base class(es)
		this.classes.push( 'jest-image' );
		return true;	// success
	}

	// Render the [object].
	// RETURNS: [boolean] true or false.
	render() {
		// Remove 'src' attribute if supplied
		let url	= null;
		if ( this.attributes.src ) {
			url	= this.attributes.src;	// save source
			delete this.attributes.src;	// delete attribute src
		}
		super.render();	// call parent render method
		// Apply an onload listener
		this.register( 'load', 'status', e=>this.isReady(), 'dom' );
		// Set source if exists
		const finalURL = url ?? this._options?.objectURL;
		if ( finalURL )
			this.setSrc( finalURL ); // set supplied source
		return true; // success
	}

	//-------------------------
	// Setting Source
	//-------------------------
	// Set the element src attribute.
	// RETURNS: [boolean] true or false.
	// * url		- [string] value of attribute source URL.
	setSrc( url ) {
		// Change status to unloaded & parse URL
		this.jot( 'source', 'unloaded' );		// set status
		this.url	= jestGetURL( url );		// update URL
		// Apply the src URL
		//console.warn( this.url );
		this.el.setAttribute( 'src', this.url );
		return true;
	}

	//-------------------------
	// Event Listener(s)
	//-------------------------
	// Determine if media is ready
	// RETURNS: [boolean] true or false.
	isReady() {
		// Determine if media is ready
		const status	= this.skim( 'source' )
		// Check if image is complete & width is not 0
		const ready		= this.el.complete && this.el.naturalWidth>0;
		if ( ready && status!=='loaded' ) {
			this.jot( 'source', 'loaded' );		// src loaded
			this.emit( 'loaded' );				// emit src load event
		}
		return ready; // return ready state
	}
}

/* --- BEGIN js/system/dom/element/ElementAudio.js --- */

// ElementAudio class
class ElementAudio extends OSElement {
	// Attribute properties
	url				= null;			// [string] value of src URL
	// Playback status properties
	playing			= false;		// [bool] Value indicating playing status (unreliable).
	// Playback timing
	queued			= false;		// [bool] Whether sound is queued to play as soon as ready
	volume			= 1;			// [float] Volume sound should play at.

	//-------------------------
	// Setup [Object]
	//-------------------------
	// Creates the class [object] with configurable components.
	// RETURNS: [object] A new instance.
	// * options		- [object] Configuration options for the class [object].
	constructor( options={} ) {
		// Parse some data
		options.tag		= 'audio';
		super( options );	// call OSObject parent constructor
		this.jot( 'source', 'empty' );				// set status
		this.jot( 'playback', 'unplayed' );			// playback empty
		// Store volume.
		this.volume		= options.volume ?? 0.2;	// Store internal volume default
		// Setup the [object] before creating the element
		this.setup();								// setup the [object]
		this.render();								// render the [object]
		// Determine if audio should autoplay upon load
		this.queued		= options.queued ?? false;	// whether to auto-play
		// Call load complete if source preloaded
		if ( this.isReady() ) this.onLoad();
	}

	// Setup the [object].
	// RETURNS: [boolean] true or false.
	setup() {
		super.setup();		// call parent setup method
		// Ensure class(es) include element base class(es)
		this.classes.push( 'jest-audio' );
		return true;		// success
	}

	// Render the [object].
	// RETURNS: [boolean] true or false.
	render() {
		// Remove 'src' attribute if supplied
		let url	= null;
		if ( this.attributes.src ) {
			url	= this.attributes.src;		// save source
			delete this.attributes.src;		// delete attribute src
		}
		super.render();			// call parent render method
		// Apply listener(s)
		this.register( 'loadeddata', 'status', e=>this.onLoad(e), 'dom' );
		// Apply listener(s)
		this.register( 'play', 'playback', e=>this.onPlay(e), 'dom' );
		this.register( 'playing', 'playback', e=>this.onResume(e), 'dom' );
		const stops	=
			[
				'pause', 'ended',
				'abort', 'error',
				'waiting', 'stalled', 'suspend',
				'emptied'
			];
		stops.forEach(
			type => {
				this.register( 'interrupt', `playback_${type}`, e=>this.onInterrupt(e), 'dom' );
			});
		this.register( 'ended', 'playback', e=>this.onEnd(e), 'dom' );
		// Set source if exists
		const finalURL = url ?? this._options?.objectURL;
		if ( finalURL )
			this.setSrc( finalURL ); // set supplied source
		return true;			// success
	}

	//-------------------------
	// Set Playback Volume
	//-------------------------
	// Sets the audio element volume and stores internally.
	// * volume - [float] Value between 0.0 and 1.0
	setVolume( volume ) {
		// Require volume to be a number.
		if ( typeof volume==='number' )
			this.volume	= Math.min( 1, Math.max(0,volume) ); // clamp
		// Set volume on element.
		this.el.volume	= this.volume; // apply immediately
	}

	//-------------------------
	// Setting Source
	//-------------------------
	// Set the element src attribute.
	// RETURNS: [boolean] true or false.
	// * url		- [string] value of attribute source URL.
	setSrc( url ) {
		// Change status to unloaded & parse URL
		this.jot( 'source', 'unloaded' );			// set status
		this.url	= jestGetURL( url );		// update URL
		// Apply the src URL
		this.el.setAttribute( 'src', this.url );
		return true;
	}

	// Determine if media is ready
	// RETURNS: [boolean] true or false.
	isReady() {
		// Determine if media is ready
		const status	= this.skim( 'source' )
		// 2 = HAVE_CURRENT_DATA, means it has loaded enough to play
		const ready		= this.el.readyState >= 2;
		if ( ready && status!=='loaded' )
			this.jot( 'source', 'loaded' );
		return ready; // return ready state
	}

	//-------------------------
	// Playback Handling
	//-------------------------
	// Plays the audio from the beginning.
	// * volume		- [float] Playback volume.
	play( volume=null ) {
		// Make sure file is already loaded
		if ( !this.isReady() ) {
			// console.warn( `Cannot play audio before load.` );
			return;
		}
		// If queued, it is not queued anymore
		if ( this.queued===true )
			this.queued		= false;	// no longer queued
		// Set audio volume.
		if ( typeof volume==='number' )
			this.setVolume( volume );	// override
		else this.setVolume( this.volume ); // use internal
		// Play audio stream.
		this.el.play().catch( err => console.error(`Error playing ${this.name}:`,err) );
	}

	// Plays the audio from the beginning.
	// * volume		- [float] Playback volume.
	replay( volume=null ) {
		// Make sure file is already loaded
		if ( !this.isReady() ) {
			// console.warn( `Cannot replay audio before load.` );
			return;
		}
		// Set audio volume.
		if ( typeof volume==='number' )
			this.setVolume( volume );	// override
		else this.setVolume( this.volume ); // use internal
		// Reset audio stream & play
		this.el.currentTime	= 0;		// reset the audio stream time
		this.el.play().catch( err => console.error(`Error replaying ${this.name}:`,err) );
	}

	// Stops the audio.
	// * volume		- [float] Playback volume.
	stop() {
		// Make sure file is already loaded
		if ( !this.isReady() ) {
			// console.warn( `Cannot stop audio before load.` );
			return;
		}
		// Stop the audio
		this.el.currentTime	= 0;		// reset the audio stream time
		this.el.stop().catch( err => console.error(`Error stopping ${this.name}:`,err) );
	}

	//-------------------------
	// Event Listener(s)
	//-------------------------
	// onLoad event handler callback for attribute src
	// RETURNS: [void].
	onLoad() {
		this.jot( 'source', 'loaded' );			// src loaded
		this.emit( 'loaded' );					// emit src load event
		// Play sound if queued
		if ( this.queued===true ) this.play();
	}

	// onPlay event handler callback for playback start.
	// RETURNS: [void].
	onPlay() {
		this.jot( 'playback', 'playing' );		// playback begin
		this.playing	= true;					// sound started playing
		this.emit( 'started' );					// emit playback start event
	}

	// onResume event handler callback for when playback resumes.
	// RETURNS: [void].
	onResume() {
		this.jot( 'playback', 'playing' );		// playback resumed
		this.playing	= true;					// sound resumed playing
		this.emit( 'resumed' );					// emit playback resume event
	}

	// onInterrupt event handler callback for playback interrupt.
	// RETURNS: [void].
	onInterrupt() {
		this.jot( 'playback', 'interrupted' );	// playback interrupted
		this.playing	= false;				// sound playing interrupted
		this.emit( 'interrupted' );				// emit playback interrupted event
	}

	// onEnd event handler callback for playback complete.
	// RETURNS: [void].
	onEnd() {
		this.jot( 'playback', 'ended' );		// playback finished
		this.playing	= false;				// sound playing interrupted
		this.emit( 'ended' );					// emit playback end event
	}
}

