//-------------------------
// AnimationAnimator Class
//-------------------------
// Manages a pile of animations for sequential updates.
class AnimationAnimator {
	// Declare properties
	canvas			= null;				// ElementCanvas [object] (for CanvasRenderingContext2D [object] drawing)
	animations		= new Set();		// [object] Set of animations to manage & update sequentially.

	// Initializes the Sequencer.
	// RETURNS: [void].
	constructor() { }

	//-------------------------
	// Canvas Management
	//-------------------------
	// Sets the canvas element
	// * canvas		- [object] Canvas element to set
	setCanvas( canvas ) {
		if ( !(canvas instanceof HTMLCanvasElement) )
			throw new Error( 'Invalid canvas element' );
		this.canvas = canvas;
	}

	//-------------------------
	// Animation Management
	//-------------------------
	// Adds an animation to the stack of animations.
	// RETURNS: [void].
	// * animation		- [object] Animation instance to add.
	add( animation ) {
		this.animations.add( animation ); // Add animation
	}

	// Removes an animation from the stack of animations.
	// RETURNS: [void].
	// * animation		- [object] Animation instance to remove.
	remove( animation ) {
		this.animations.delete( animation ); // Remove animation
	}

	//-------------------------
	// Rendering Methods
	//-------------------------
	// Updates all animations in the stack of animations.
	// RETURNS: [void].
	// [object] {}
	// 		* elapsedTime	- [int] how much time has passed since the ticker started.
	// 		* tickDelay		- [int] how much time between each tick (ie. 60ms)
	// 		* tickCount		- [int] how many ticks have occurred
	update( { elapsedTime, tickDelay, tickCount } ) {
		// Iterate each animation & update it
		this.animations.forEach(
			animation => {
				for ( const name in animation.views ) {
					// Access view & update it
					const view		= animation.views[name];
					if ( typeof view.update==='function' )
						view.update( tickDelay );
					else console.warn( 'Animation view missing update method' );
				}
			});
	}

	// Draws all animation(s).
	// RETURNS: [void].
	// *views	- [array] of AnimationViews to draw
	draw( views=null ) {
		// Determine if canvas is set
		if ( !this.canvas || !this.canvas.el ) {
			console.warn( 'Canvas is not set or invalid' );
			return;
		}
		// Access context & clear the board
		const ctx = this.canvas.el.getContext( '2d' );
		// Iterate each animation & draw onto the canvas
		views.forEach(
			view => {
				if ( !view.frame || !view.active ) return;
				// Access active layer
				const animation	= view.animation;		// get animation
				const lindex	= view.getLayerIndex();	// layer index
				const layer		= view.frame.layers[lindex] ?? null;
				if ( !layer ) return;
				// Render sprite(s)
				layer.stickers.forEach(
					sticker => {
						// Get [AnimationSprite] from animation.
						const sprite	= animation.getSpriteByID( sticker.sid );
						try {
							// Attempt to get image.
							const image		= view.getGroup( sprite.group );
							// Render each sprite (if image available).
							if ( !image?.file || image.file.skim('source')!=='loaded' ) return;
							// Calculate final values (using overrides if necessary).
							const sx		= sprite.sx;		// sprite source x
							const sy		= sprite.sy;		// sprite source y
							const width		= sprite.width;		// sprite crop width
							const height	= sprite.height;	// sprite crop height
							// Get x & y positions
							const x			= Math.round( view.globalX + sticker.globalX );
							const y			= Math.round( view.globalY + sticker.globalY );
							//console.log( image.file.el );
							//console.log( sx, sy, width, height, x, y, width, height )
							// Draw the sprite on the canvas.
							ctx.drawImage(
								image.file.el,
								sx, sy, width, height,		// Source crop
								x, y, width, height			// Destination
								);
						}
						catch ( error ) {
							console.error( "An error occurred:", error.message );
						}
					});
			});
	}
}

/* --- BEGIN js/mediacore/animation/AnimationView.js --- */

//-------------------------
// AnimationView Class
//-------------------------
// Animation configuration "view" [object] for calibrating dynamic variable(s).
class AnimationView extends AnimationObject {
	// Object reference(s).
	animation	= null;				// [object] Animation this View is configuring.
	// Identification properties.
	name		= null;				// [string] Value of animation view name.
	// General animation properties.
	active		= false;			// [bool] Whether the animation is currently active.
	playing		= false;			// [bool] Play state of the animation.
	// Animation progress and layer.
	loop		= false;			// Whether the animation should loop.
	time		= 0;				// [int] Current time in the animation.
	progress	= 0;				// [float] Progress through the animation (0 to 1).
	_layerIndex	= 0;				// [int] Active layer being viewed in frame.
	// Frame(s) and Group(s).
	frame		= null;				// [object] reference of current active frame.

	//-------------------------
	// Instantiation
	//-------------------------
	// Construct the [object].
	// * ani	- [object] Animation instance to add.
	// * name	- [string] Name of the animation.
	//   x		- [int] value of horizontal offset relative to sprite
	//   y		- [int] value of vertical offset relative to sprite
	//   w		- [int] value of animation width
	//   h		- [int] value of animation height
	constructor( ani, name, x=0, y=0, w=null, h=null ) {
		super( x, y, 0, w, h );		// call parent constructor
		this.animation	= ani;		// store animation reference
		this.name		= name;		// Assign the view name
	}

	//-------------------------
	// Frame Handlnig
	//-------------------------
	// Set animation frame
	// RETURNS: [this].
	// *index	- [int] value of frame to set to.
	setFrameIndex( index ) {
		// Set [null] if no frames exist.
		if ( this.animation.frames.length>0 ) {
			// Confine index to bounds of possible [array] indices
			index	= Math.min( this.animation.frames.length-1, index );
			index	= Math.max( 0, index );
			// Set the frame
			this.frame	= this.animation.frames[index];
		}
		else this.frame	= null;
		return this; // return `this` for chaining
	}

	// If no frame set, returns 0. If frame not found, clamps safely.
	// RETURNS: [int] the index of the current active frame.
	getFrameIndex() {
		// --------------------------------
		// Validate Frame Reference
		// --------------------------------
		// If frame is null or animation missing, default to 0.
		if ( !this.frame || !this.animation || !Array.isArray(this.animation.frames) )
			return 0;

		// --------------------------------
		// Resolve Index
		// --------------------------------
		// Find index inside animation.frames array.
		let index = this.animation.frames.indexOf( this.frame );

		// If frame not found (rare but possible), clamp to 0.
		if ( index===-1 )
			index = 0;

		// --------------------------------
		// Constrain to Valid Range
		// --------------------------------
		// Prevent OOB: clamp within [0 .. frames.length-1].
		index = Math.max( 0, Math.min( index, this.animation.frames.length-1 ));

		// Return resolved index.
		return index;
	}

	// Increment animation frame
	// RETURNS: [this].
	nextFrame() {
		// Calculate next frame index
		let index	= this.animation.frames.indexOf(this.frame) + 1;
		// If looping and out of bounds, wrap to start
		if ( this.loop && index>=this.animation.frames.length )
			index	= 0;
		// Confine index to bounds of possible [array] indices
		index		= Math.min( this.animation.frames.length-1, index );
		index		= Math.max( 0, index );
		// Set the frame
		this.frame	= this.animation.frames[index];
		return this; // return `this` for chaining
	}
	// Decrement animation frame
	// RETURNS: [this].
	previousFrame() {
		// Calculate previous frame index
		let index	= this.animation.frames.indexOf(this.frame) - 1;
		// If looping and out of bounds, wrap to end
		if ( this.loop && index<0 )
			index	= this.animation.frames.length-1;
		// Confine index to bounds of possible [array] indices
		index		= Math.min( this.animation.frames.length-1, index );
		index		= Math.max( 0, index );
		// Set the frame
		this.frame	= this.animation.frames[index];
		return this; // return `this` for chaining
	}

	//-------------------------
	// State Changing
	//-------------------------
	// Get the animation layer [object].
	// RETURNS: [AnimationLayer] instance or [null] if not found.
	getLayer() {
		// Get current layer index.
		const lindex = typeof this._layerIndex==="number" && Number.isInteger(this._layerIndex)
			? this._layerIndex
			: 0; // Default to 0 if _layerIndex is invalid
		// Return the [AnimationLayer] instance.
		return this.frame.getLayerAt( lindex );
	}

	// Attempt to set the layer.
	setLayerIndex( index ) { this._layerIndex = index; }
	// Attempt to get the layer.
	getLayerIndex() { return this._layerIndex; }

	// Return count of layers in the frame.
	getLayerCount( index ) {
		return this.frame.layers.length;
	}

	//-------------------------
	// Clamp Selected Frame & Layer
	//-------------------------
	// Revalidates `frame` and `_layerIndex` to avoid referencing removed content.
	// Should be called after frame or layer deletion.
	// RETURNS: [void]
	/*clampSelected() {
		//--------------------------------
		// Clamp Frame Selection
		//--------------------------------
		// Determine if active frame exists.
		const frames	= this.animation.frames;
		const frameCount = this.animation.getFrameCount();
		// Check if no frames are left.
		if ( frames.length===0 ) {
			this.frame	= null;		// no frames remain
			this._layerIndex = 0;	// reset layer index
			return; // abort
		}

		//--------------------------------
		// Clamp Frame Index
		//--------------------------------
		// Get current frame index.
		const index = this.getFrameIndex();
		const clampedIndex = Math.max( 0, Math.min(index,frameCount-1) );
		this.setFrameIndex( clampedIndex );

		//--------------------------------
		// Clamp Layer Index
		//--------------------------------
		// Determine if selected layer index is valid.
		const layers	= this.frame?.layers ?? [];
		if ( !Array.isArray(layers) || layers.length===0 )
			this._layerIndex = 0;
		// Clamp within [0, layers.length-1]
		else this._layerIndex = Math.max( 0, Math.min(this._layerIndex,layers.length-1) );
	}*/

	//-------------------------
	// Playback Control
	//-------------------------
	// Enable looping for the animation.
	// RETURNS: [void].
	loopOn() {
		this.loop		= true;
		//console.log( `Animation "${this.name}" set to loop.` );
		return this;
	}

	// Disable looping for the animation.
	// RETURNS: [void].
	loopOff() {
		this.loop		= false;
		//console.log( `Animation "${this.name}" set to stop looping.` );
		return this;
	}

	// Play the animation.
	// RETURNS: [this].
	play() {
		if ( this.playing ) {
			//console.warn( `Animation "${this.name}" is already playing.` );
			return this;
		}
		this.playing	= true;
		//console.log( `Animation "${this.name}" started.` );
		return this;
	}

	// Pause the animation.
	// RETURNS: [this].
	pause() {
		if ( !this.playing ) {
			//console.warn( `Animation "${this.name}" is already paused.` );
			return this;
		}
		this.playing = false;
		//console.log( `Animation "${this.name}" paused.` );
		return this;
	}

	// Toggle play/pause state.
	// RETURNS: [this].
	togglePlay() {
		this.playing ? this.pause() : this.play();
		return this;
	}

	// Enable the animation.
	// RETURNS: [this].
	enable() {
		this.active		= true;
		//console.log( `Animation "${this.name}" enabled.` );
		return this;
	}

	// Disable the animation.
	// RETURNS: [this].
	disable() {
		this.active		= false;
		//console.log( `Animation "${this.name}" disabled.` );
		return this;
	}

	// Reset the animation to the start.
	// RETURNS: [this].
	reset() {
		this.time			= 0;		// reset the playhead
		this.progress		= 0;		// reset playhead progress % tracking
		this._clocks.start	= null;		// reset the start time
		this.frame			= this.animation.frames[0]; // reset to first frame
		this.pause().disable();			// pause & disable the animation
		//console.log( `Animation "${this.name}" reset.` );
		return this;
	}

	//-------------------------
	// Rendering
	//-------------------------
	// Updates the animation's progress.
	// RETURNS: [void].
	// * tickDelay	- the FPS of the ticker (ie. 60 = 60ms/1000ms or 60fps)
	update( tickDelay ) {
		//-------------------------
		// Determine If Playable
		//-------------------------
		// Determine if animation is paused
		if ( !this.playing ) return;
		else if ( this._clocks.start===null )
			this._clock( 'start' ); // set the start time
		//-------------------------
		// Calculate Time
		//-------------------------
		// Increment the animation's elapsed time
		this.time += tickDelay;
		// Check if the animation has completed
		if ( this.time>=this.animation.duration ) {
			if ( this.loop ) {
				this.time	%= this.animation.duration; // Wrap around for looping animations
			}
			else this.complete();			// Animation complete
		}
		// Calculate progress as a percentage (if needed for sprites)
		const progress	= this.time / this.animation.duration;
		//-------------------------
		// Calculate Current Frame
		//-------------------------
		// Determine the current frame based on time
		let elapsed		= this.time;
		let index		= 0;
		for ( const frame of this.animation.frames ) {
			if ( elapsed<frame.duration ) {
				this.frame	= frame;
				break;
			}
			index++;
			elapsed -= frame.duration;		// Reduce elapsed time by the frame's duration
		}
	}

	// Complete the animation
	complete() {
		//-------------------------
		// Determine If Playing
		//-------------------------
		// Determine if animation is paused
		if ( !this.playing ) return;
		//-------------------------
		// Complete Animation
		//-------------------------
		this.time	 = this.animation.duration; // Cap time at the end
		this.pause();	      				// Pause the animation
		this.emit( 'complete' );			// Emit end of sequence callback(s)
	}
}

/* --- BEGIN js/mediacore/animation/AnimationAnimation.js --- */

//-------------------------
// AnimationAnimation Class
//-------------------------
class AnimationAnimation extends AnimationObject {
	// Identification properties.
	name		= 'ani';		// [string] Value of animation name
	// Animation progress.
	duration	= 1000;			// [int] Duration in ms calculated in frame(s)
	// Frame(s) & group(s).
	views		= {};			// [array] List of views to handle individual configurations (branch renders).
	frames		= [];			// [array] of frames with offsets
	sprites		= {};			// [object] Sprites set during parsing.
	options		= {};			// [object] Options set during parsing.
	// ID Counter(s)
	// Ensures sprite.id values are always unique even after deletions.
	_spriteIdCounter = 1;		// [int] auto-incrementing ID seed

	//-------------------------
	// Instantiation
	//-------------------------
	// Construct the [object].
	// * name		- [string] Name of the animation.
	constructor( name ) {
		super();				// call parent constructor
		this.name	= name;		// assign the animation name
		// Ensure at least one frame & layer exists:
		this.createFrame();		// creates exactly 1 frame (no layers by default)
	}

	//-------------------------
	// Building Methods
	//-------------------------
	// Unset a sprite group (iterates all sprites & removes them).
	// RETURNS: [void].
	// * groupName	- [string] Group name
	unsetGroup( groupName ) {
		//-------------------------
		// Clear Matching Sprites' Group
		//-------------------------
		// Iterate frame sprites & unset matching group.
		for ( const key in this.sprites ) {
			// Get sprite instance.
			const sprite	= this.sprites[key];
			// Unset sprite's group if matching group name.
			if ( sprite.getGroup()===groupName )
				sprite.unsetGroup(); // unset matching group
		}

		//-------------------------
		// Clear Mirrored Views' Group
		//-------------------------
		// Iterate all views & unset matching group.
		for ( const name in this.views ) {
			const view = this.views[name];
			// Unset view's group if matching group name.
			view.unsetGroup( groupName ); // unset mirror group
		}

		//-------------------------
		// Call Parent unsetGroup()
		//-------------------------
		// Call parent unset group method.
		super.unsetGroup( groupName ); // unset animation group
	}

	//-------------------------
	// RENAME GROUP (IN-PLACE)
	//-------------------------
	// Renames an existing group without unsetting or recreating it.
	// All references are updated:
	// - sprites
	// - views
	// - animation group registry
	//
	// RETURNS: [boolean] true on success
	// * oldName	- [string] existing group name
	// * newName	- [string] new group name
	renameGroup( oldName, newName ) {
		//--------------------------------
		// Validate Argument(s)
		//--------------------------------
		if ( typeof oldName!=='string' || typeof newName!=='string' )
			return false; // abort
		if ( oldName===newName )
			return false; // abort

		//--------------------------------
		// Rename Group on Sprites
		//--------------------------------
		// Update sprite.group in-place.
		for ( const id in this.sprites ) {
			// Access [AnimationSprite] & rename group.
			const sprite = this.sprites[id];
			if ( sprite.getGroup?.()===oldName )
				sprite.setGroup( newName );
		}

		//--------------------------------
		// Rename Group on Views
		//--------------------------------
		// Views store groups as keyed maps.
		for ( const key in this.views ) {
			// Access [AnimationView] & rename group (if exists).
			const view = this.views[key];
			view.renameGroup( oldName, newName );
		}

		//--------------------------------
		// Rename Animation Group Registry
		//--------------------------------
		// Update internal group map (AnimationObject).
		if ( this.groups?.[oldName]!==undefined ) {
			// Move old group value to new group name.
			this.groups[newName] = this.groups[oldName];
			// Delete old group value (remove loose duplicate).
			delete this.groups[oldName];
		}

		return true; // success
	}

	//-------------------------
	// Building Methods
	//-------------------------
	// Adds a sprite to this layer.
	// RETURNS: [void].
	// * sprite		- Sprite [object] to add to layer.
	addSprite( sprite ) {
		// Require sprite id.
		if ( !sprite || sprite.id==null )
			return false;
		// Check if sprite already exists.
		if ( this.sprites[sprite.id] )
			return false; // already exists
		// Add sprite.
		this.sprites[sprite.id] = sprite;
		return true; // success
	}

	// Retrieves a sprite by index
	// RETURNS: [object|null] AnimationSprite or [null] if not found.
	// * id		- [int] id of the sprite to retrieve
	getSpriteByID( id ) {
		// Get sprite by id.
		return this.sprites[id] ?? null; // return [null] if id invalid
	}

	// Removes a sprite from this layer.
	// RETURNS: [void].
	// * sprite		- [AnimationSprite] to remove from layer.
	removeSprite( sprite ) {
		// Require sprite id.
		if ( !sprite ) return false;
		// Iterate sprites & remove if a match.
		for ( const key in this.sprites ) {
			const item = this.sprites[key];
			if ( sprite!==item ) continue; // skip
			// Proceed to remove sprite.
			this.removeSpriteByID( sprite.getId() );
			return true; // removed
		}
		return false; // nothing removed
	}

	// Removes a sprite by index
	// RETURNS: [void].
	// * id		- [int] id of the sprite to remove
	removeSpriteByID( id ) {
		// Check if sprite exists.
		if ( this.sprites?.[id] ) {
			delete this.sprites[id];
			return true; // removed
		}
		return false; // not found
	}

	// Checks if a sprite with the given ID exists in this layer.
	// RETURNS: [boolean] True if found, else false.
	// * id		- [string|number] Sprite ID to check for existence
	hasSpriteByID( id ) {
		// Determine if sprite exists.
		return this.sprites?.[id] ? true : false;
	}

	//-------------------------
	// Get Next Sprite ID
	//-------------------------
	// Generate a new guaranteed-unique sprite ID.
	// RETURNS: [int] next unused sprite ID.
	getNextSpriteId() {
		//--------------------------------
		// Generate ID Using Monotonic Counter
		//--------------------------------
		// Loop in case a previously used ID was reinserted manually
		let id;
		do {
			id = this._spriteIdCounter++;
		} while ( this.sprites[ id ] ); // ensure not in use (paranoid check)
		// Return the safe, unique ID
		return id;
	}

	// Ensure next index id is synced to items in sprites.
	// RETURNS: [void].
	_syncSpriteIdCounter() {
		// Ensure max id pushes the next sprite id counter.
		const maxSpriteId =
			Object.keys( this.sprites )
				.map( id => parseInt(id,10) )
				.filter( n => !isNaN(n) )
				.reduce( (a,b) => Math.max(a,b), 0 );
		// Check if next sprite id exceeds existing max id.
		if ( maxSpriteId >= this._spriteIdCounter )
			this._spriteIdCounter = maxSpriteId + 1;
	}

	//-------------------------
	// View Management
	//-------------------------
	// Adds an animation view configuration to the pile.
	// RETURNS: [object] AnimationView on success else [null] on fail.
	// * name		- [string] Value of view name (e.g. 'user').
	addView( name ) {
		// Validate arguments
		if ( !jsos.argue('name',name,'string') ) return null;
		// Remove view if it exists
		if ( this.views?.[name] ) {
			console.warn( `Animation already contains a view named "${name}"! Remove existing view first, or try a different name.` );
			return null;
		}
		// Create an animation configuration [object]
		const view	= new AnimationView( this, name );
		// Process options
		if ( this.options['LOOP']===true )
			view.loopOn();
		// Set groups.
		for ( const key in this.groups )
			view.setGroup( key, this.groups[key] );
		this.views[name] = view;	// Add to pile
		return view;				// Return view [object]
	}

	// Adds an animation view configuration to the pile.
	// RETURNS: [object] AnimationView on success else [null] on fail.
	// * name		- [string] Value of view name (e.g. 'user').
	getView( name ) {
		return name in this.views ? this.views[name] : null;
	}

	// Removes an animation configuration (e.g. "AnimationView") from the pile.
	// RETURNS: [boolean] `true` on success else `false` on fail.
	// * name		- [string] Value of view name (e.g. 'user').
	removeView( name ) {
		// Remove view if it exists
		if ( this.views?.[name] )
			delete this.views[name]; // Remove view
		return true;
	}

	// Calls clampSelected() on all views to resolve invalid frame/layer references.
	// RETURNS: [void]
	_clampAllViews() {
		//--------------------------------
		// Validate Frame(s) Exist
		//--------------------------------
		// If no frame(s) exist, abort.
		if ( this.getFrameCount()===-1 ) return;

		//--------------------------------
		// Iterate All View(s) & Clamp
		//--------------------------------
		// Iterate all views & clamp selection (during removals).
		for ( const name in this.views ) {
			// Access registered [AnimationView] instance.
			const view = this.views[name];

			//--------------------------------
			// Clamp Frame Index
			//--------------------------------
			// Determine view's frame index.
			const maxFindex	= this.getFrameCount() - 1;		// animation's max frame index
			const findex	= Math.max( 0, Math.min(view.getFrameIndex(),maxFindex) );
			view.setFrameIndex( findex ); // apply clamped index

			//--------------------------------
			// Clamp Layer Index (if frame exists)
			//--------------------------------
			// Access current frame in view & clamp layer index.
			const frame		= this.getFrameAt( findex );	// view's active frame
			if ( !frame ) continue;
			const lindex	= view.getLayerIndex();			// view's active layer index
			const maxLindex = frame.getLayerCount() - 1;	// frame's max layer index
			view.setLayerIndex( Math.max(0,Math.min(lindex,maxLindex)) );

			//--------------------------------
			// Clamp Cursor Selection(s)
			//--------------------------------
			// Clamp cursor selection(s).
			//view.clampSelected();
		}
	}

	// Removes all layer(s) from all frame(s).
	// RETURNS: [boolean] true if removed
	clearLayers() {
		//--------------------------------
		// Remove All Layer(s) from All Frame(s)
		//--------------------------------
		// Iterate all frames & remove every layer.
		for ( const frame of this.frames )
			for ( let i=frame.getLayerCount()-1; i>=0; i-- )
				frame._removeLayerAt( i );

		//--------------------------------
		// Update Layer Count & Clamp View(s)
		//--------------------------------
		this._clampAllViews();		// Clamp selection.
		return true;				// success
	}

	//-------------------------
	// Frame Handling
	//-------------------------
	// Adds a frame to the animation.
	// RETURNS: [AnimationFrame].
	createFrame() {
		return this.createFrames(1)[0];
	}

	// Adds new frame(s) to the animation and clones global layer count.
	// RETURNS: [array] of [AnimationFrame].
	// * amount – [int] number of frames to create (default = 1)
	createFrames( amount=1 ) {
		// Validate amount
		if ( amount<1 ) return [];

		//-------------------------
		// Create Exactly Requested Amount
		//-------------------------
		// Prepare result
		const result = [];
		// Create total # of frames
		for ( let i=0; i<amount; i++ ) {
			// Create empty frame
			const frame = this.createFrameAt( null );
			// Push frame into return result [array].
			result.push( frame );
		}

		//-------------------------
		// Return Data
		//-------------------------
		// Return the newly created frame(s).
		return result; // [array of AnimationFrame]
	}

	//-------------------------
	// Frame Handling Method(s)
	//-------------------------
	// Returns the animation's # of frame(s).
	// RETURNS: [int] count
	getFrameCount() {
		return this.frames.length;
	}

	// Instantiates and inserts a new frame at the specified index.
	// RETURNS: [AnimationFrame]
	// * index – [int] Index to insert the new frame
	createFrameAt( index=null ) {
		//-------------------------
		// Validate argument(S).
		//-------------------------
		// Validate argument(s).
		if ( index===null || index<0 || index>this.frames.length )
			index	= this.frames.length;

		//-------------------------
		// Create & Add Frame
		//-------------------------
		// Generate name from index.
		const name	= `frame_${index}`;
		const frame	= new AnimationFrame( this, name, null, index );
		this._insertFrameAt( frame, index ); // Insert it

		//-------------------------
		// Return Data
		//-------------------------
		// Return the newly created frame.
		return frame; // [AnimationFrame] instance
	}

	// Inserts a frame into the timeline at a given index.
	// If already exists, will relocate it.
	// RETURNS: [void].
	// * frame – [AnimationFrame] to insert (containing layers with sprites)
	// * index	– [int] Index to insert the new frame
	_insertFrameAt( frame, index=null ) {
		//-------------------------
		// Validate argument(S).
		//-------------------------
		// Frame must be object type specific.
		if ( !(frame instanceof AnimationFrame) )
			throw new Error( 'Invalid frame object' );

		// Validate argument(s).
		if ( index===null || index>this.frames.length )
			index	= this.frames.length;
		// Clamp insertion index
		index	= Math.max( 0, index );

		// -------------------------
		// Move Frame If Already In Animation
		// -------------------------
		// Check if frame is inside animation.
		const currentIndex = this.frames.indexOf( frame );
		if ( currentIndex !== -1 ) {
			this.moveFrameTo( frame, index ); // relocate
			return; // abort
		}

		//-------------------------
		// Add to Animation Frames
		//-------------------------
		// Insert new frame.
		this.frames.splice( index, 0, frame );

		//--------------------------------
		// Reindex + Recalculate
		//--------------------------------
		// Increase sprite duration to include frame duration.
		this._resortFrameIndexes();	// Ensure frame.index = array index
		this._clampAllViews();		// Clamp selection.
		this._calculateDuration();	// Ensure duration stays consistent
	}

	// Get the frame at the specified index.
	// RETURNS: [AnimationFrame] or [null].
	// * index – [int] Index of frame retrieve.
	getFrameAt( index=null ) {
		// Validate argument(s).
		if ( index===null || index<0 || index>=this.frames.length || this.frames.length<1 )
			return null; // invalid index
		else return this.frames[index]; // [AnimationFrame] instance
	}

	// -------------------------
	// Remove a Frame (with View Clamp)
	// -------------------------
	// Removes frame at index, clamps views referencing it.
	// RETURNS: [void].
	// * index	– [int] index of frame to remove.
	removeFrameAt( index ) {
		//--------------------------------
		// Validate Index
		//--------------------------------
		// Check if index is within bounds.
		if ( index<0 || index>=this.frames.length )
			return; // no frame found

		//--------------------------------
		// Deconstruct the Frame
		//--------------------------------
		// Access [AnimationFrame] being removed.
		const frame	= this.frames[index];
		// Splice frame out the frames [array].
		this.frames.splice( index, 1 );
		/*🛑 frame._clearLayers(); // wipe layers*/

		//--------------------------------
		// Clamp All Views Using This Frame
		//--------------------------------
		// Iterate all views & clamp selected frame.
		for ( const key in this.views ) {
			const view		= this.views[key];
			// After removing frame, index is next frame.
			const findex	= view.getFrameIndex();
			if ( findex === index ) {
				// If pointing to the deleted frame,
				// keep index as-is (next frame slides into position)
				// If that makes it out of bounds, clamp later.
			}
			else if ( findex > index ) {
				// Shift left to follow frame shuffle
				view.setFrameIndex( findex - 1 );
			}
		}

		//--------------------------------
		// Reindex + Recalculate
		//--------------------------------
		// Recalibrate frame indices & re-calculate duration.
		this._resortFrameIndexes();	// Ensure frame.index = array index
		this._calculateDuration();	// Update duration after removal

		//--------------------------------
		// Ensure At Least One Frame Exists
		//--------------------------------
		// If no frames remain, create an empty frame.
		if ( this.frames.length === 0 ) {
			const newFrame = this.createFrame();
			console.warn( '[AnimationAnimation] No frames remaining. Auto-created fallback frame:', newFrame.name );
		}

		//--------------------------------
		// Clamp View Selections
		//--------------------------------
		// Clamp view index selection(s).
		this._clampAllViews();
	}

	//-------------------------
	// Frame Ordering Utilities
	//-------------------------
	// Reindexes all frames so that index = position in array.
	// Internal: Call after mutation to maintain consistency.
	// RETURNS: [void].
	_resortFrameIndexes() {
		// Iterate and reindex all frames chronologically.
		for ( let i=0; i<this.frames.length; i++ )
			this.frames[i].setIndex( i ); // Set logical index
	}

	// Moves a frame to a new index in the timeline.
	// Shifts others to maintain strict 0..n order.
	// RETURNS: [void].
	// * frame  – [AnimationFrame] to move
	// * newIndex – [int] target index
	moveFrameTo( frame, newIndex ) {
		// Check if frame is inside animation.
		const currentIndex = this.frames.indexOf( frame );
		if ( currentIndex === -1 )
			throw new Error( `AnimationAnimation.moveFrameTo(): frame not found.` );

		// Remove & insert @ new index.
		this.frames.splice( currentIndex, 1 );
		this.frames.splice( newIndex, 0, frame );
		this._resortFrameIndexes();	// Ensure frame.index = array index
		this._calculateDuration();	// Sync animation duration
	}

	// Sorts frames with a comparator function.
	// Useful for timeline manipulations or custom logic.
	// RETURNS: [void].
	// * compareFn – [function] sort callback
	sortFrames( compareFn ) {
		this.frames.sort( compareFn );	// Sort in-place
		this._resortFrameIndexes();		// Sync .index properties
	}

	//-------------------------
	// Time Handling Method(s)
	//-------------------------
	// Recalibrate the duration of the animation based upon frames
	// RETURNS: [void].
	_calculateDuration() {
		this.duration =
			this.frames.reduce(
				( sum, frame ) => sum+frame.duration, 0 );
	}
}

/* --- BEGIN js/mediacore/animation/AnimationFrame.js --- */

//-------------------------
// AnimationFrame Class
//-------------------------
class AnimationFrame {
	// Object propert(ies).
	_index			= -1;		// [int] Value of frame's position in animation.
	animation		= null;		// [object] Animation the layer belonds to.
	// Identification properties.
	name			= null;		// [string] Value of animation view name.
	// Timing propert(ies)
	duration		= null;		// [int] Value of duration of the frame in ms
	// Visual propert(ies)
	layers			= [];		// [array] of layer(s) (layers contain the sprite(s))

	//-------------------------
	// Instantiation
	//-------------------------
	// Declare properties.
	// Construct the [object].
	// * animation	- [object] Animation instance to add.
	// * name		- [string] Name of the layer.
	//   duration	- [int] value of duration of the frame in ms (defaults to 60)
	//   index		- [int] value of frame's index in the animation.
	constructor( animation, name, duration=null, index=0 ) {
		this.animation	= animation;	// store animation reference
		this.name		= name;			// Assign the view name
		this.duration	= duration ?? 1000/60*4; // Duration of the frame in ms
		this.setIndex( index );			// default frame index
	}

	//-------------------------
	// Index Management
	//-------------------------
	// Sets the frame's timeline index.
	// Called internally during reindexing.
	// * index		- [int] value of frame's index in the animation.
	setIndex( index ) {
		this._index	= index;	// set frame index
	}

	// Returns the frame's timeline index.
	// RETURNS: [int] index
	getIndex() {
		return this._index;
	}

	//-------------------------
	// Layer Management
	//-------------------------
	// Returns the frame's # of layer(s).
	// RETURNS: [int] count
	getLayerCount() {
		return this.layers.length;
	}

	// Adds a layer to the frame
	// RETURNS: [AnimationLayer] instance.
	_createLayer() {
		return this._createLayerAt( null ); // [AnimationLayer]
	}

	// Creates and inserts a layer at a specific index.
	// RETURNS: [AnimationLayer] instance.
	// * index – [int] Where to insert the new layer
	_createLayerAt( index=null ) {
		// Validate argument(s).
		if ( index===null || index<0 || index>this.getLayerCount() )
			index	= this.getLayerCount();
		// Generate name from index.
		const name	= `layer_${index}`;
		// Construct the new layer.
		const layer	= new AnimationLayer( this.animation, name, this );
		// Insert layer at the target index.
		this._insertLayerAt( layer, index ); // Insert it
		// Return the layer.
		return layer; // [AnimationLayer] instance
	}

	// Inserts a new or existing layer at a specific index.
	// If already exists, moves it.
	// RETURNS: [void].
	// * layer – [AnimationLayer] to insert
	// * index – [int] Insertion index
	_insertLayerAt( layer, index ) {
		//--------------------------------
		// Forbid Double Insertion
		//--------------------------------
		// Remove layer first if already inside frame.
		const currentIndex = this.layers.indexOf( layer );
		if ( currentIndex !== -1 )
			this._removeLayerAt( currentIndex );

		//--------------------------------
		// Insert Layer @ Requested Index
		//--------------------------------
		// Clamp to valid range
		index = Math.max( 0, Math.min(index,this.getLayerCount()) );
		this.layers.splice( index, 0, layer );
		this._resortLayerIndices(); // enforce index = array position
	}

	//-------------------------
	// Remove Layer
	//-------------------------
	// Removes a layer at a specified index from this frame.
	// RETURNS: [boolean] True if removed, false if index invalid.
	// * index - [int] Index of the layer to remove
	_removeLayerAt( index ) {
		//--------------------------------
		// Validate Index
		//--------------------------------
		// Check if index is within bounds.
		if ( index<0 || index>=this.getLayerCount() )
			return false; // invalid index

		//--------------------------------
		// Remove Layer
		//--------------------------------
		// Access [AnimationLayer] instance.
		const layer	= this.layers[index];
		/*🛑 layer.removeAllStickers(); // wipe stickers*/
		// Splice layer out of frame layers [array].
		this.layers.splice( index, 1 );

		//--------------------------------
		// Reindex & Return
		//--------------------------------
		this._resortLayerIndices();	// Refresh all indexes
		return true; // success
	}

	// Removes all layer(s) from all frame(s).
	// RETURNS: [boolean] true if removed
	_clearLayers() {
		// Iterate frame & remove every layer.
		for ( let i=(this.getLayerCount()-1); i>=0; i-- )
			this._removeLayerAt( i );
		return true; // success
	}

	//-------------------------
	// Utility Methods
	//-------------------------
	// Retrieves a layer by index
	// RETURNS: [object|null] AnimationLayer at the given index or null if out of bounds.
	// * index		- [int] Index of the layer to retrieve
	getLayerAt( index=null ) {
		return this.layers[index] ?? null; // Return null if invalid
	}

	//-------------------------
	// Layer Ordering Utilities
	//-------------------------
	// Sorts layers with external comparator, then reindexes.
	// RETURNS: [void].
	// * compareFn – [function] (a,b) comparator
	sortLayers( compareFn ) {
		this.layers.sort( compareFn );
		this._resortLayerIndices(); // sync ._index
	}

	// Reindexes all layers so that .index = position in array.
	// RETURNS: [void].
	_resortLayerIndices() {
		// Reindex all chronologically.
		for ( let i=0; i<this.getLayerCount(); i++ )
			this.layers[i].setIndex( i );
	}
}

