//-------------------------
// AnimationSticker Class
//-------------------------
// A categorized & named "clip" region inside a spritesheet,
// belonging to an animation.
class AnimationSticker extends Anchor {
	// Declare properties
	sid			= 0;			// [string] value of [AnimationSprite] id (e.g. 0)
	_layer		= null;			// [AnimationLayer] instance sticker appears in.

	//-------------------------
	// Instantiation
	//-------------------------
	// Constructor for animation sprite reference "sticker".
	// RETURNS: [void].
	// * sid	- [int] value of [AnimationSprite] id
	constructor( sid ) {
		// Construct the anchor parent class.
		super( 0, 0, 0, 0, 0 );	// call parent constructor
		// Identity of [AnimationSprite].
		this.sid = sid;			// [AnimationSprite] id
	}

	//-------------------------
	// Layer Handling Method(s)
	//-------------------------
	// Set the layer object reference (sticker appears in).
	// RETURNS: [void].
	// * layer	- [AnimationLayer] instance sticker appears in.
	setLayer( layer ) {
		//-------------------------
		// Validate argument(S).
		//-------------------------
		// Layer must be object type specific.
		if ( !(layer instanceof AnimationLayer) )
			throw new Error( 'Invalid layer object' );
		// Layer of [AnimationSprite].
		this._layer = layer; // [AnimationLayer] reference
	}

	// Get the layer object reference (sticker appears in).
	// RETURNS: [AnimationLayer] or [null].
	getLayer() {
		// Layer of [AnimationSprite].
		return this._layer ?? null; // [AnimationLayer] reference
	}
}

/* --- BEGIN js/mediacore/pacing/Delegator.js --- */

//-----------------------------
// Delegator Class
//-----------------------------
// Manages suppression of specific actions for specific tools/actors,
// allowing temporary suspension of certain interactions during transitions.
//
// USAGE:
//  client.delegator.suppress( 'dragdrop', ['click','mouseup'], 500 );
//  client.delegator.allowed( 'paintbrush', 'click' ); // returns true/false
//
class Delegator extends OSCallback {
	// Object Properties
	suppressions		= {};		// [object] Map of { actor: { action: timestamp } }
	// Permanent suppressions (manual toggle)
	permaSuppressions	= {};		// [object] { actor: Set<action> }

	//--------------------------------
	// Constructor
	//--------------------------------
	// Construct the [object].
	constructor() {
		super();	// call parent constructor
	}

	//--------------------------------
	// Suppress Actions for Actor
	//--------------------------------
	// Temporarily disables one or more actions for a given actor/tool.
	// They will be blocked from triggering until the timeout expires.
	// * actor		- [string] name of the actor/tool (e.g. 'dragdrop')
	// * actions	- [string|array<string>] action(s) to suppress (e.g. 'click')
	// * timeout	- [int] duration in ms to suppress action(s)
	suppress( actor, actions, timeout ) {
		if ( !actor || !timeout ) return;
		if ( typeof actions==='string' )
			actions = [ actions ];
		if ( !Array.isArray(actions) ) return;

		// Create actor entry if needed
		if ( !this.suppressions[ actor ] )
			this.suppressions[ actor ] = {};

		const now = Date.now();

		// Set each action with timeout
		for ( const act of actions )
			this.suppressions[actor][act] = now + timeout;
	}

	//--------------------------------
	// Is Actor Allowed for Action?
	//--------------------------------
	// Checks if the given actor is allowed to perform the specified action.
	// RETURNS: [bool] true if allowed, false if suppressed by others
	// * actor		- [string] name of actor/tool (e.g. 'paintbrush')
	// * action		- [string] action being attempted (e.g. 'click')
	allowed( actor, action ) {
		// Validate argument(s).
		if ( !actor || !action ) return true;

		// First check: permanent suppression
		for ( const [suppressor, actions] of Object.entries(this.permaSuppressions) ) {
			if ( suppressor!==actor && actions.has(action) )
				return false; // forbid
		}

		// Then check: temporary suppression
		const now = Date.now();
		for ( const [suppressor, actions] of Object.entries(this.suppressions) ) {
			// Check if actor allowed.
			if ( suppressor===actor ) continue;
			// Actor mismatch, check if suppression expired.
			const expiry = actions[ action ];
			if ( expiry && expiry>now ) return false; // forbid
		}

		// Not blocked by others
		return true; // allowed
	}

	//--------------------------------
	// Is Action Allowed
	//--------------------------------
	// Checks if an action is currently allowed for a given actor/tool.
	// RETURNS: [bool] true if allowed, false if suppressed
	// * actor		- [string] name of actor/tool
	// * action		- [string] action to check (e.g. 'click')
	selfBlocked( actor, action ) {
		// Validate argument(s).
		if ( !actor || !action ) return true;

		// Check permanent suppression.
		const perma = this.permaSuppressions[ actor ];
		if ( perma && perma.has(action) ) return false;

		// Check temporary suppression.
		const map = this.suppressions[ actor ];
		if ( !map ) return true;

		const expiry = map[ action ];
		if ( !expiry ) return true;

		// If expired, remove entry
		if ( Date.now()>=expiry ) {
			delete map[ action ];
			if ( Object.keys(map).length===0 )
				delete this.suppressions[ actor ];
			return true;
		}

		// Still suppressed
		return false;
	}

	//--------------------------------
	// Clear All Suppressions
	//--------------------------------
	// Instantly clears all active suppressions for all actors.
	// RETURNS: [void]
	clearAll() {
		this.suppressions = {};
	}

	//--------------------------------
	// Clear Specific Actor or Action
	//--------------------------------
	// Removes suppression from a specific actor or actor+action.
	// * actor		- [string] name of actor/tool
	// * action		- [string|null] optional action to clear; if null, clears all
	clear( actor, action=null ) {
		if ( !this.suppressions[ actor ] ) return;

		if ( action===null )
			delete this.suppressions[ actor ];
		else {
			delete this.suppressions[ actor ][ action ];
			if ( Object.keys(this.suppressions[ actor ]).length === 0 )
				delete this.suppressions[ actor ];
		}
	}

	//--------------------------------
	// Permanently Suppress Action(s)
	//--------------------------------
	// Prevents action(s) from being allowed for this actor indefinitely.
	// * actor		- [string]
	// * actions	- [string|array<string>]
	permaSuppress( actor, actions ) {
		if ( typeof actions === 'string' ) actions = [ actions ];
		if ( !Array.isArray(actions) ) return;

		if ( !this.permaSuppressions[ actor ] )
			this.permaSuppressions[ actor ] = new Set();

		for ( const act of actions )
			this.permaSuppressions[ actor ].add( act );
	}

	//--------------------------------
	// Remove Permanent Suppression (with optional cooldown)
	//--------------------------------
	// Removes permanent suppression from an actor or specific action(s).
	// If a timeout is supplied, the action(s) will remain suppressed temporarily.
	// * actor		- [string]
	// * action	- [string|array|null] action or list of actions to clear; null = all
	// * timeout	- [int|null] optional cool-off time in ms
	clearPerma( actor, action=null, timeout=null ) {
		if ( !this.permaSuppressions[actor] ) return;

		const wasCleared = [];

		if ( action === null ) {
			// Clear all permanent suppressions for this actor
			for ( const act of this.permaSuppressions[actor] )
				wasCleared.push( act );

			delete this.permaSuppressions[actor];
		}
		else {
			// Normalize to array
			const actions = ( typeof action === 'string' ) ? [ action ] : action;

			for ( const act of actions ) {
				this.permaSuppressions[actor].delete( act );
				wasCleared.push( act );
			}

			// Clean up empty set
			if ( this.permaSuppressions[actor].size === 0 )
				delete this.permaSuppressions[actor];
		}

		// Apply temporary suppression if needed
		if ( timeout && timeout > 0 ) {
			const now = Date.now();
			if ( !this.suppressions[actor] )
				this.suppressions[actor] = {};

			for ( const act of wasCleared )
				this.suppressions[actor][act] = now + timeout;
		}
	}
}

/* --- BEGIN js/mediacore/pacing/Timeout.js --- */

//-------------------------
// Timeout Class
//-------------------------
// Drives the center clock loop and emits 'tick' events.
class Timeout extends OSCallback {
	// Declare properties
	delay			= null;						// [number] Time interval between ticks in milliseconds.
	running			= false;					// [bool] Indicates if the ticker is currently running.
	startTime		= performance.now();		// [number] Start time of ticker.
	ticksEmitted	= 0;						// [int] Accumulates ticks to maintain precise # of tick intervals.
	boundTick		= null;						// [function] Binds the tick method to preserve context.
	pauseTime		= null;						// [number|null] Pause time of ticker.
	timerId			= null;						// [] Timer ID if using setInterval

	// --------------------------
	// Initialization
	// --------------------------
	// Initializes the timeout.
	// * delay	- [number] Time interval between ticks in milliseconds.
	// * mode	- [string] 'timer' or 'raf'.
	constructor( mode='timer' ) {
		super();											// call parent constructor
		this.delay			= 1000 / 60;					// [number] Time interval for each tick.
		this.running		= false;						// [bool] Whether the ticker is active.
		this.boundTick		= this.tick.bind( this );		// Preserve context for the tick method.
		// Set the mode.
		if ( mode!=='raf' ) mode = 'timer';
		this.jot( mode );
	}

	// --------------------------
	// Overloaded Method(s)
	// --------------------------
	// Sets the ticker mode.
	// RETURNS: [void].
	// * mode	- [string] 'timer' or 'raf' (requestAnimationFrame).
	jot( mode='timer' ) {
		// Ensure mode is only "ref" or "timer".
		if ( mode!=='timer' && mode!=='raf' )
			throw new Error( `Timeout: invalid mode "${mode}". Use 'raf' or 'timer'.` );
		// Set parent mode.
		super.jot( 'mode', mode );
	}

	// --------------------------
	// Toggling Method(s)
	// --------------------------
	// Starts the ticker.
	// RETURNS: [void].
	start() {
		// Reset & recalibrate ticker if not running
		if ( !this.running ) {
			this.running		= true;						// Set the ticker to running state.
			this.startTime		= performance.now();		// [number] Start time of ticker.
			this.ticksEmitted	= 0;						// [int] # of "frames rendered".
			requestAnimationFrame( this.boundTick );		// Schedule the first tick.
			// Start correct loop
			if ( this.skim('mode')==='raf' )
				requestAnimationFrame( this.boundTick );
			else this.timerId = setInterval( this.boundTick, this.delay );
		}
	}

	// Stops the ticker.
	// RETURNS: [void].
	stop() {
		this.running	= false; // Set the ticker to stopped state.
		// Clear timer if mode is "timer".
		if ( this.skim('mode')==='timer' && this.timerId!==null ) {
			clearInterval( this.timerId );
			this.timerId = null;
		}
	}

	// Pauses the ticker.
	// RETURNS: [void].
	pause() {
		// Do not double-pause
		if ( !this.running ) return;
		this.running	= false;						// Set the ticker to stopped state.
		this.pauseTime	= performance.now();			// Record pause time.
		// Clear timer if mode is "timer".
		if ( this.skim('mode')==='timer' && this.timerId!==null ) {
			clearInterval( this.timerId );
			this.timerId = null;
		}
	}

	// Resumes the ticker from pause.
	// RETURNS: [void].
	resume() {
		// Do not resume if already running
		if ( this.running ) return;
		this.running	= true;							// Set ticker to running state.
		// If resuming from pause → adjust startTime
		if ( this.pauseTime!==null ) {
			this.startTime	+= ( performance.now() - this.pauseTime );
			this.pauseTime	= null;
		}
		else { // fresh start if no pause time
			this.startTime		= performance.now();
			this.ticksEmitted	= 0;
		}
		// Resume correct loop
		if ( this.skim('mode')==='raf' )
			requestAnimationFrame( this.boundTick );	// Schedule next tick.
		else this.timerId = setInterval( this.boundTick, this.delay );
	}


	// --------------------------
	// Rendering
	// --------------------------
	// Main tick method called on each frame.
	// Calculates elapsed time, maintains consistent timing, and emits tick events.
	// RETURNS: [void].
	tick() {
		// Require ticker event to be running
		if ( !this.running ) return;
		// Calculate time elapsed.
		const now			= performance.now();			// Current time.
		const elapsedTime	= now - this.startTime;			// Time since ticker started.
		// Calculate how many ticks should have occurred since the start.
		const expectedTicks	= Math.floor( elapsedTime / this.delay );
		const missedTicks	= expectedTicks - this.ticksEmitted;
		// Notice any spikes/lag in rendering.
		if ( missedTicks>10 )
			console.warn( `Timer logged a spike in lag: ${missedTicks} missed ticks.` );
		// Emit ticks for all missed intervals.
		for ( let i=0; i<missedTicks; i++ ) {
			const tickDelay	= this.delay;					// Each tick is a fixed interval.
			// Pass the time data to listener(s).
			this.emit(
				'tick', null,
				{
					elapsedTime,
					tickDelay,
					tickCount: this.ticksEmitted + i + 1	// Adjust for missed ticks.
				});
		}
		this.ticksEmitted	= expectedTicks;				// Update ticksEmitted count
		// Reset periodically to avoid infinite growth
		if ( this.ticksEmitted>=60 ) {
			this.startTime		= now;						// Adjust startTime forward
			this.ticksEmitted	= this.ticksEmitted % 60;	// Reset counter
		}
		// Only reschedule if using rAF
		if ( this.skim('mode')==='raf' )
			requestAnimationFrame( this.boundTick );		// Schedule the next tick.
	}
}

/* --- BEGIN js/widgets/loadbar/Loadbar.js --- */

//-------------------------
// Loadbar Class
//-------------------------
class Loadbar extends OSElement {
	// Declare properties
	percent		= null;			// [element] of percent counter
	bar			= null;			// [element] of animated bar

	// Creates a loadbar [object].
	// RETURNS: [object] A new instance.
	// * options		- [object] Configuration options for the class [object].
	constructor( options={} ) {
		// Call the parent constructor
		super( options );
		// Setup the loadbar before creating the element
		this.setup();			// setup the loadbar
		this.render();			// render the loadbar
	}

	// Setup the loadbar [object].
	// RETURNS: [boolean] `true` on success else `false` on fail.
	setup() {
		super.setup();			// call parent setup method
		// Ensure class(es) include loadbar class(es)
		this.classes.push( 'jest-loadbar' );
		return true;			// success
	}

	// Render the [object].
	// RETURNS: [boolean] `true` on success else `false` on fail.
	render() {
		// --------------------------------
		// Create the DOM Element
		// --------------------------------
		super.render(); // call parent setup method
		// --------------------------------
		// Create bar element [object]
		// --------------------------------
		const bar		= jsos.generateElement( 'div', null, ['jest-loadbar-bar'] );
		this.el.appendChild( bar );
		this.bar		= bar;				// cross-reference
		// --------------------------------
		// Create percent element [object]
		// --------------------------------
		const percent	= jsos.generateElement( 'div', null, ['jest-loadbar-text'], '0%' );
		bar.appendChild( percent );			// add # percent to bar
		this.percent	= percent;			// cross-reference
		return true;						// success
	}

	// Reset the loadbar to 0
	// RETURNS: [void].
	reset() {
		// Add end animation
		this.jot( 'loading', 'pending' );	// set state to pending
		jsos.classflip( this.bar, 'pending', ['tracking','complete'] );	// visual classes
		// Reset loadbar width & text
		this.update( 0, 1 );
		this.bar.offsetWidth;				// trigger reflow
	}

	// Set loadbar to active
	// RETURNS: [void].
	activate() {
		// Activate the bar
		this.jot( 'loading', 'tracking' );	// set state to tracking
		jsos.classflip( this.bar, 'tracking', ['pending','complete'] );	// visual classes
	}

	// Set to active
	// RETURNS: [void].
	complete() {
		// Add end animation
		this.jot( 'loading', 'complete' );	// set state to complete
		jsos.classflip( this.bar, 'complete', ['pending','tracking'] );	// visual classes
		// Fully expand loadbar width & text
		this.update( 1, 1 );
		// Remove the animation class after completion
		setTimeout(
			() => {
				if ( this.skim('loading')==='complete' )
					this.el.classList.remove( 'complete' );
			},
			1500 );
		return true;
	}

	// Update the loadbar visual animation
	update( current, total ) {
		// Update loadbar bar percentage text
		const progress				= Math.min( (current/total) * 100, 100 ); // Ensure it doesn't exceed 100%
		this.bar.style.width		= `${progress}%`;
		this.percent.textContent	= `${Math.round(progress)}%`;
	}
}

/* --- BEGIN js/system/components/panel/Panel.js --- */

//-------------------------
// Panel Class
//-------------------------
// Provides a class for creating a panel [object].
class Panel extends OSElement {
	// Same constructor argument(s)
	name		= null;				// [string] value of panel name (used for sorting)
	type		= null;				// Type of panel (form, etc.)

	//-------------------------
	// Constructor
	//-------------------------
	// Construct panel [object]
	constructor( options ) {
		super( options ); // parent construct
		// Handle option argument(s)
		this.name		= options.name || null;				// [string] name of object
		this.type		= options.type || 'unspecified';	// [string] value of type of panel
		// Setup the panel before creating the element
		this.setup();		// setup the panel
		this.render();		// render the panel
	}

	//-------------------------
	// Initialization
	//-------------------------
	// Setup the panel [object].
	// RETURNS: [boolean] true or false.
	setup() {
		super.setup(); // call parent setup method
		// Ensure class(es) include panel base class(es)
		this.classes.push( 'jest-panel' );
		return true; // success
	}
	// Render the panel [object].
	// RETURNS: [boolean] true or false.
	render() {
		super.render(); // call parent render method
		// --------------------------------
		// Render the children
		// --------------------------------
		this.addElements( this._options.elements );	// Generate the panel elements
	}

	//-------------------------
	// Add/Remove Panel(s)
	//-------------------------
	// Dynamically updates the panel content.
	// RETURNS: [void].
	// * elements	- [array] New content definitions for the panel.
	addElements( elements ) {
		// Require element data
		if ( !elements ) return;
		// Create panel element [objects]
		for ( const data of elements ) {
			// Create the custom PanelElement [object]
			const element	= this.createPanel( data );
		}
	}

	// Dynamically create a child panel element [object].
	// RETURNS: PanelElement [object]
	// * data	- [object] of content definition for the element.
	createPanel( data ) {
		// Require this element to be created
		if ( this.el===null ) return false;
		// Ensure panel element [object] contains breadcrumbs
		data.breadcrumbs	= [ ...this.breadcrumbs ];
		// --------------------------------
		// Create PanelElement [object]
		// --------------------------------
		let panel = null; // define element
		/*switch ( data.type ) {
			case 'form':
				panel		= new PanelForm( data );
				break;
			case 'button':
				panel		= new PanelFormButton( data );
				break;
			case 'dropdown':
				panel		= new PanelFormDropdown( data );
				break;
			default:
				panel		= new PanelElement( data );
				break;
		}*/
		panel		= new Panel( data );
		// Append to DOM & return
		const index	= data?.index ?? null;
		this.addPanel( data.name, panel );
		// Return panel containing DOM element [object]
		return panel; // panel [object]
	}

	// Add a panel [object].
	// RETURNS: [void].
	// * name		- [string] Value of Panel name.
	// * panel		- Panel [object] to add to the window.
	//   index		- [int|null] Value of index to insert child at.
	addPanel( name, panel, index=null ) {
		// Append to DOM & return
		this.insertAt( panel.el, index );
		// Store quick-ref
		const key			= name ?? null;
		const breadcrumbs	= [ ...this.breadcrumbs ];
		this.addBreadcrumbs( breadcrumbs ); // copy breadcrumbs
		this.ref( key, panel );
	}

	// Remove a panel [object] from the window.
	// RETURNS: [bool] true on success, false on failure.
	// * nameOrPanel - [string|Panel] key used in ref(), or the panel instance.
	removePanel( nameOrPanel ) {
		// Resolve panel reference
		let panel	= null;
		let key		= null;
		if ( typeof nameOrPanel==='string' ) {
			key		= nameOrPanel;
			panel	= this.refs?.[key] ?? null;
		}
		else if ( nameOrPanel && typeof nameOrPanel==='object' ) {
			panel	= nameOrPanel;
			key		= Object.keys(this.refs).find( k=>this.refs[k]===panel) ?? null;
		}
		// Validate panel existence
		if ( !panel || !panel.el || !panel.el.parentNode ) {
			console.error( `Panel not found or already removed.` );
			return false; // abort
		}
		// Remove from DOM
		panel.el.parentNode.removeChild( panel.el );
		// Remove stored ref
		if ( key ) delete this.refs[key];
		return true; // success
	}

	//-------------------------
	// Destroy Panel
	//-------------------------
	// Destroy this panel and all child panels.
	// RETURNS: [void]
	destroy() {
		// Emit destruction event (optional hook)
		this.emit?.( 'destroy', this );
		// Destroy all referenced children if they have a destroy() method
		if ( this.refs ) {
			for ( const key in this.refs ) {
				const panel = this.refs[key];
				if ( panel && typeof panel.destroy==='function' ) {
					panel.destroy();
				}
			}
		}
		// Remove this element from DOM
		if ( this.el && this.el.parentNode )
			this.el.parentNode.removeChild( this.el );
		// Clear references and internal flags
		this.refs		= {};
		this.el			= null;
		this.client		= null;
		this._options	= null;
		this.breadcrumbs = [];
		// Optional logging
		//console.log( `Panel.destroy(): '${this.name}' panel destroyed.` );
	}

}

