//-------------------------
// PanelFormDropdown Class
//-------------------------
// Provides a modular and extensible way to create a form dropdown.
class PanelFormDropdown extends PanelElement {
	// Construct the form dropdown [object]
	constructor( options ) {
		options.tag    = 'select';
		super( options );
	}

	// Setup the panel form dropdown [object].
	// RETURNS: [boolean] true or false.
	setup() {
		super.setup();
		this.classes.push( 'jest-panel-element-form-dropdown' );
		// Validate and preprocess options
		if ( this._options.elements ) {
			this.elements = {};
			for ( let key in this._options.elements ) {
				const option		= this._options.elements[key];
				// Parse the option
				const optionParsed	=
					{
						...option,				// Merge additional properties,
						type:		'option',	// Enforce option type
						tag:		'option'	// Enforce tag
					};
				this._options.elements[key] = optionParsed; // set option as parsed
			}
		}
		return true;
	}
}

/* --- BEGIN js/system/window/BaseWindow.js --- */

// BaseWindow class to handle shared functionality
class BaseWindow extends OSElement {
	// Declare properties
	measurements		= null;			// [object] of window measurements (x, y, width, height)

	// Construct the base window
	constructor( options ) {
		super( options ); // call parent constructor
	}

	// Setup the window [object].
	// RETURNS: [boolean] `true` on success else `false` on fail.
	setup() {
		super.setup(); // call parent setup method
		// Add base window class(es)
		this.classes.push( 'jest-window' );
		return true; // success
	}

	// Open the window inside the OS environment.
	// RETURNS: [boolean] `true` on success else `false` on fail.
	open() {
		// --------------------------------
		// Create window [object]
		// --------------------------------
		// Append the window to the environment
		const environment		= JestEnvironment.getEnvironment();
		environment.appendChild( this.el );
		// Bind window-specific events
		//this.bindWindowEvents();
		// --------------------------------
		// Reframe State of window [object]
		// --------------------------------
		// Set current reframe state
		this.jot( 'reframing', 'idle' );	// change reframing state
		this.measure();							// Measure the window
		this.maximize();						// Maximize the window
		return true; // success
	}

	// Minimize window
	// RETURNS: [boolean] `true` on success else `false` on fail.
	minimize() {
		// Attempt to reframe to minimized
		return this.reframe( 'minimized' );
	}

	// Maximize window
	// RETURNS: [boolean] `true` on success else `false` on fail.
	maximize() {
		// Attempt to Reframe to maximized
		return this.reframe( 'maximized' );
	}

	// Reframe the window to maximize or minimized state.
	// RETURNS: [boolean] `true` on success else `false` on fail.
	// * newFrame		- [string] value of frame state to change window to.
	reframe( newFrame ) {
		// Get current state
		const currentFrame		= this.skim( 'frame' );				// 'minimized', 'maximized', etc.
		const currentState		= this.skim( 'reframing' );			// 'transitioning' or 'idle'
		console.log( `Reframing window from '${currentFrame}' to '${newFrame}'...` );
		// Determine classes
		const staticClasses		= [ 'maximized', 'minimized', 'restored' ]; // root classes / modes
		const dynamicClasses	= [ newFrame, 'transitioning' ];		// motion state change
		const excludeClasses	= staticClasses.filter( c => c!==newFrame );
		if ( newFrame!==currentFrame && currentState!=='transitioning' ) {
			jsos.classflip( this.el, dynamicClasses, excludeClasses );	// change class mode
			this.jot( 'frame', newFrame );							// change frame state
			this.jot( 'reframing', 'transitioning' );				// change reframing state
			// Remove the transition class after completion
			const transitionDuration = parseFloat(getComputedStyle(this.el).transitionDuration) * 1000 || 1500;
			setTimeout(
				() => {
					if ( this.skim('reframing')==='transitioning' ) {
						this.el.classList.remove( 'transitioning' );
						this.jot( 'reframing', 'idle' );			// change reframing state
					}
				},
				transitionDuration );
			return true; // successfully reframing
		}
		return false; // failed to reframe
	}

	// Close window
	close() {
		console.log( 'Closing window...' );
		if ( this.el ) {
			this.el.remove();
		}
	}

	// Update the window measurements (for resizing)
	// RETURNS: [void].
	measure() {
		// Ensure the element is [null]
		if ( this.el!==null ) {
	        // Get accurate dimensions
	        const rect	= this.el.getBoundingClientRect();
			// Calculate width, height, and location
			this.measurements = {
				width:		this.el.style.width || `${rect.width}px`,			// Use rect width for precision
				height:		this.el.style.height || `${rect.height}px`,			// Use rect height for precision
				top:		this.el.style.top || `${rect.top}px`,				// Save accurate top position
				left:		this.el.style.left || `${rect.left}px`				// Save accurate left position
			}
		}
	}
}

/* --- BEGIN js/system/window/Window.js --- */

//-------------------------
// Window Class
//-------------------------
class Window extends BaseWindow {
	// Declare properties
	options			= null;		// [object] of options supplied to constructor
	title			= null;		// title of window [object]

	// Creates a window with configurable components.
	// RETURNS: [object] A new instance.
	// * options		- [object] Configuration options for the class [object].
	constructor( options={} ) {
		// Call the parent constructor
		super( options );
		// Save options
		this.title		= options.title || 'Window'; // store base title for the window [object]
		// Setup the window [object]
		this.setup();		// setup the window
		this.render();		// render the window
	}

	// Initializes the window with dynamic panels.
	// RETURNS: [boolean] `true` on success else `false` on fail.
	// * elements		- [object] Configuration options for the panels.
	addElements( elements ) {
		// Require element data
		if ( !elements ) return;
		// Generate panels dynamically based on configuration
		( elements || [] ).forEach(
			data => {
				this.createPanel( data );
			});
		return true; // success
	}

	// Dynamically create a child panel [object].
	// RETURNS: Panel [object]
	// * data	- [object] of content definition for the element.
	createPanel( data ) {
		// Require this element to be created
		if ( this.el===null ) return false;
		// --------------------------------
		// Create Panel [object]
		// --------------------------------
		let element = null; // define element
		switch ( data.type ) {
			case "panel":
			default:
				// Create element [object]
				element		=
					new Panel({
						...data,
						breadcrumbs: [ ...this.breadcrumbs ]
						});
				break;
		}
		// Append to DOM & return
		this.addPanel( data.name, element );
		// Return DOM element [object]
		return element;
	}

	// Add a panel [object].
	// RETURNS: [void].
	// * name		- [string] value of Panel name.
	// * panel		- Panel [object] to add to the window.
	addPanel( name, panel ) {
		// Append to DOM & return
		this.el.appendChild( panel.el );
		// Store quick-ref
		const key	= name ?? null;
		//this.addBreadcrumbs( this ); // add window as breadcrumb
		this.ref( key, panel );
	}

	// Initializes the window with dynamic panels.
	// RETURNS: [boolean] `true` on success else `false` on fail.
	// * elements		- [object] Configuration options for the panels.
	render() {
		// Call the parent render method
		super.render();
		// Add resize & drag events
		//this.resizable();
		return true; // success
	}

	// Add resize handles
	resizable() {
		const directions = [
			'top', 'right', 'bottom', 'left',
			'top-left', 'top-right', 'bottom-left', 'bottom-right'
			];
		directions.forEach(
			dir => {
				const handle		= document.createElement( 'div' );
				handle.className	= `resize-handle resize-${dir}`;
				this.el.appendChild( handle );

				handle.addEventListener(
					'mousedown',
					( e ) => {
						// Prevent bubbling.
						e.stopPropagation();
						// Get starting positions & dimensions.
						const startWidth	= this.el.offsetWidth;
						const startHeight	= this.el.offsetHeight;
						const startX		= e.clientX;
						const startY		= e.clientY;
						const startLeft		= this.el.offsetLeft;
						const startTop		= this.el.offsetTop;

						const onMouseMove	=
							(e) => {
								const dx	= e.clientX - startX;
								const dy	= e.clientY - startY;

								if ( dir.includes('right') )
									this.resize( startWidth+dx );

								if ( dir.includes('bottom') )
									this.resize( null, startHeight+dy );

								if ( dir.includes('left') ) {
									const newWidth	= startWidth - dx;
									const newLeft	= startLeft + dx;
									// Prevent window from going off-screen on the left or shrinking too much
									if ( newWidth>50 && newLeft>=0 ) {
										this.resize( newWidth );
										this.move( null, newLeft );
									}
								}

								if ( dir.includes('top') ) {
									const newHeight	= startHeight - dy;
									const newTop	= startTop + dy;
									// Prevent window from going off-screen at the top or shrinking too much
									if ( newHeight>50 && newTop>=0 ) {
										this.resize( null, newHeight );
										this.move( newTop );
									}
								}
							};

						const onMouseUp =
							() => {
								document.removeEventListener( 'mousemove', onMouseMove );
								document.removeEventListener( 'mouseup', onMouseUp );
							};

						document.addEventListener( 'mousemove', onMouseMove );
						document.addEventListener( 'mouseup', onMouseUp );
					}
				);

			});
	}

	// Override minimize method
	// RETURNS: [boolean] `true` on success else `false` on fail.
	minimize() {
		// Call parent minimize method & reframe if possible
		if ( super.minimize() ) { // attempt to minimize
			// Get saved state data
			this.measure(); // save measurements before minimizing
			this.el.style.width		= '100%';
			this.el.style.height	= '0px';
			// Pin window to bottom right
			this.el.style.bottom	= '0px';
			this.el.style.right		= '0px';
			this.el.style.top		= '';        // clear top
			this.el.style.left		= '';        // clear left
			this.el.style.position	= 'fixed'; // Ensure it's at the bottom-right corner
			return true; // successfully reframing
		}
		return false; // failed to reframe
	}

	// Override restore method
	// RETURNS: [boolean] `true` on success else `false` on fail.
	restore() {
		// Call parent restore method & reframe if possible
		if ( super.restore() ) { // attempt to restore
			if ( this.measurements ) {
				this.el.style.width		= this.measurements.width || 'auto';	// Restore width, default to auto
				this.el.style.height	= this.measurements.height || '';		// Restore height
				this.el.style.top		= this.measurements.top || '';		// Restore top
				this.el.style.left		= this.measurements.left || '';		// Restore left
				this.el.style.bottom	= '';	// Clear bottom
				this.el.style.right		= '';	// Clear right
				this.el.style.position	= '';	// Restore original position
			}
			return true; // successfully restoring
		}
		return false; // failed to reframe
	}

	// Override maximize method
	// RETURNS: [boolean] `true` on success else `false` on fail.
	maximize() {
		// Call parent maximize method & reframe if possible
		if ( super.maximize() ) { // attempt to maximize
			if ( this.measurements ) {
				this.el.style.top		= '0'; // top-left
				this.el.style.left		= '0'; // top-left
				this.el.style.width		= window.innerWidth + 'px';
				this.el.style.height	= window.innerHeight + 'px';
			}
			return true; // successfully reframing
		}
		return false; // failed to reframe
	}

	// Close the window.
	// RETURNS: [void].
	close() {
		console.log( 'Closing window...' );
		super.close();
	}
}

/* --- BEGIN js/system/forms/FormBuilder.js --- */

//-------------------------
// FormBuilder Class
//-------------------------
// Provides a modular and extensible way to build forms and nested elements.
class FormBuilder {
	// Generates a DOM element with attributes and content using Environment methods.
	// RETURNS: [object] The created DOM element.
	// * options - [object] Configuration for the element.
	//     tag         - [string] The HTML tag (default: 'div').
	//     id          - [string] ID of the element.
	//     classes     - [string|array] Classes to add to the element.
	//     attributes  - [object] Additional attributes for the element.
	//     text        - [string] Text content of the element.
	//     children    - [array] Nested child elements.
	static createElement( options ) {
		// Generate the DOM element
		switch ( options.type ) {
			/*case 'button':
				const element	= new FormButton(options).el;
			case 'dropdown':
				const element	= new FormDropdown(options).el;*/
			default:
				const element	=
					jsos.generateElement(
						options.tag || 'div',
						options.id || '',
						options.classes || [],
						options.text || ''
					);
		}

		// Add attributes
		if ( options.attributes ) {
			Object.keys( options.attributes ).forEach(
				attr => element.setAttribute( attr, options.attributes[attr] )
			);
		}

		// Add nested children
		if ( options.children && Array.isArray(options.children) ) {
			options.children.forEach(
				child => element.appendChild( FormBuilder.createElement(child) )
			);
		}

		return element;
	}

	// Generates a form element with optional inputs, labels, and buttons.
	// RETURNS: [object] The created form element.
	// * config			- [object] Configuration for the form.
	//   id				- [string] ID of the form.
	//   classes		- [string|array] Classes to add to the form.
	//   attributes		- [object] Additional attributes for the form.
	//   elements		- [array] Nested input/label/button definitions.
	static createForm( config ) {
		//  Create a form element
		return FormBuilder.createElement({
			tag: 'form',
			id: config.id || '',
			classes: config.classes || [],
			attributes: config.attributes || {},
			children: config.elements || []
			});
	}

	// Populates content recursively for nested elements.
	// RETURNS: [void].
	// * parent   - [object] The parent DOM element.
	//   content  - [array] Nested content definitions.
	/*static populateContent( parent, content ) {
		content.forEach(
			item => parent.appendChild( FormBuilder.createElement( item ) )
		);
	}*/
}

