// OSLibrary class
class OSLibrary {
	// Declare properties
	name				= 'Library';			// name of library
	version				= '0.0';				// library version
	libs				= {};					// [object] of sub-libs part of the library

	// Creates the class [object] with configurable components.
	// RETURNS: [object] A new instance.
	// * libs		- [array|string] of libs inside of library to include.
	constructor( libs=[] ) {
		// Call ship
		this.ship( libs );
	}

	// Setup the DOM element [object].
	// RETURNS: [boolean] `true` on success else `false` on fail.
	setup() {
		return true;			// success
	}

	// Include librar(ies).
	// RETURNS: [bool] `true` on success, else `false`.
	// * libs		- [array|string] value of library name(s) to include: ie. 'HarlequinWindow'
	ship( libs ) {
		// Iterate libs & generate
		if ( !(libs instanceof Array) )
			libs	= [libs];
		for ( let lib of libs ) {
			const library	= JestEnvironment.librarian.ship( lib ); // generate lib
			this.libs[lib]	= library;
		}
	}
}

/* --- BEGIN js/os/OSLibrarian.js --- */

// Jest librarian class
class OSLibrarian {
	// Declare properties
	libs			= {};					// [object] of OSLibrary [objects]

	// Creates the class [object] with configurable components.
	// RETURNS: [object] A new instance.
	constructor() { }

	// Include a library as part of the librarian
	// RETURNS: [bool] `true` on success, else `false`.
	// * lib		- [string] value of lib name to include: ie. 'HarlequinWindow'
	ship( lib ) {
		// Declare variables
		const className		= 'Library'+lib;
		const LibraryClass	= JestLibraryRegistry[className];
		if ( !LibraryClass )
			throw new Error( `Library "${className}" not found.` );
		// Return generated [object]
		this.libs[lib]		= new LibraryClass();
		return true;
	}
}

/* --- BEGIN js/system/interface/JSOS/classes/jsos.parse.js --- */

// Jest OS class
class JSOSParse {
	//-------------------------
	// Instantiation Methods
	//-------------------------
	// Creates the class [object].
	// RETURNS: [object] A new instance.
	constructor() { }

	//-------------------------
	// Mathematics
	//-------------------------
	// Round a value to n decimal points.
	// RETURNS: [any] The parsed result.
	// * num			- [int] Value to round.
	// * decimalPlaces	- [int] Value of number of decimal places to round to.
	roundTo( num, decimalPlaces ) {
		const factor = Math.pow( 10, decimalPlaces );
		return Math.round( (num+Number.EPSILON)*factor ) / factor;
	}

	//-------------------------
	// Parsing Methods
	//-------------------------
	// Parses a value into a specified format or type.
	// RETURNS: [any] The parsed result.
	// * value - [string|number] The value to parse.
	// * type  - [string] The type of parse to perform (e.g., 'int', 'title').
	parse( value, type ) {
		// Validate input: parsing non-string types (except integers) is not allowed.
		if ( typeof value!=='string' && type!=='int' && type!=='integer' ) {
			console.warn( `Invalid value type for parse: expected string for type "${type}"` );
			return value;
		}
		// Parse based on the specified type.
		switch ( type ) {
			case 'int':
			case 'integer':		return this._parseInteger( value );
			case 'title':		return this._parseTitle( value );
			case 'brand':		return this._parseBrand( value );
			case 'variable':
			case 'var':			return this._parseVariable( value );
			case 'alphanumeric':
			default:			return this._parseAlphanumeric( value );
		}
	}

	//-------------------------
	// Parse Helpers
	//-------------------------
	// Parses a string to remove all non-alphanumeric characters.
	// RETURNS: [string] The cleaned string containing only a-z, 0-9.
	// * value - [string] The value to parse and clean.
	_parseAlphanumeric( value ) {
		return value.replace( /[^a-z0-9]/gi, '' );
	}

	// Parses a string into an integer by removing non-numeric characters.
	// RETURNS: [number] The parsed integer.
	// * value - [string] The value to parse.
	_parseInteger( value ) {
		return parseInt( value.replace( /[^0-9]/g, '' ) );
	}

	// Converts a string to title case (e.g., "hello world" -> "Hello World").
	// RETURNS: [string] The title-cased string.
	// * value - [string] The string to convert.
	_parseTitle( value ) {
		return value
			.split( ' ' )
			.map( (word)=>this._parseBrand(word) )
			.join( ' ' );
	}

	// Capitalizes the first letter of a string and ensures it's alphanumeric.
	// RETURNS: [string] The formatted string.
	// * value - [string] The string to process.
	_parseBrand( value ) {
		value = this._parseAlphanumeric( value );
		return value.charAt(0).toUpperCase() + value.slice(1);
	}

	// Formats a string as a variable-friendly identifier (lowercase, underscores).
	// RETURNS: [string] The variable-friendly string.
	// * value - [string] The string to convert.
	_parseVariable( value ) {
		value = value.replace( / /g, '_' ); // Replace spaces with underscores.
		return value.replace( /[^A-Za-z0-9_-]/g, '' ).toLowerCase(); // Remove invalid characters and lowercase.
	}

	//-------------------------
	// Typecasting Methods
	//-------------------------
	// Converts a value to a specified type.
	// RETURNS: [any] The converted value.
	// * value  - [...] The value to convert.
	// * type   - [string] The target type (e.g., 'array', 'object').
	// * action - [string] Additional action for the conversion (optional).
	typecast( value, type, action ) {
		switch ( type ) {
			case 'array':	return this._toArray( value, action );
			case 'object':	return this._toObject( value );
			case 'obray':	return this._toObray( value );
			case 'stray':	return this._toStray( value );
			case 'intray':	return this._toIntray( value );
			default:		return value; // Return the original value if no match is found.
		}
	}

	//-------------------------
	// Typecasting Helpers
	//-------------------------
	// Converts a value to an array.
	// RETURNS: [array] The converted array.
	// * value		- [...] The value to convert.
	// * action		- [string] Additional action for array conversion (optional).
	_toArray( value, action ) {
		// Convert an [object] to an array
		if ( action==='collect' && this.prove(value,'object') ) {
			return Object.values( value );
		}
		// Return [array] value
		return Array.isArray(value) ? value : [value];
	}

	// Converts a value to an object, using strings/numbers as keys.
	// RETURNS: [object] The converted object.
	// * value - [...] The value to convert.
	_toObject( value ) {
		if ( typeof value!=='object' ) {
			const obj	= {};
			const arg	= Array.isArray(value) ? value : [value];
			arg.forEach(
				( key ) => {
					if ( typeof key==='string' || typeof key==='number' ) {
						obj[ key.toString() ] = true;
					}
				});
			return obj;
		}
		return value;
	}
	// Converts a value to an array of objects, filtering out non-object values.
	// RETURNS: [array] The filtered array of objects.
	// * value	- [...] The value to filter.
	_toObray( value ) {
		return this._toArray(value).filter( (item)=>this.prove(item,'object') );
	}

	// Converts a value to an array of strings, flattening nested arrays and extracting object keys.
	// RETURNS: [array] The converted array of strings.
	// * value - [...] The value to convert.
	_toStray( value ) {
		const arr = this._toArray( value );
		return arr.flatMap(
			( item ) => {
				if ( typeof item==='string' || typeof item==='number' ) return [item.toString()];
				if ( Array.isArray(item) )		return this._toStray( item );
				if ( typeof item==='object' )	return Object.keys( item );
				return [];
			});
	}

	// Converts a value to an array of integers, filtering out non-integer values.
	// RETURNS: [array] The filtered array of integers.
	// * value	- [...] The value to filter.
	_toIntray( value ) {
		return this._toArray(value).filter( (item)=>this.prove(item,'int') );
	}
}

/* --- BEGIN js/system/interface/JSOS/classes/jsos.validation.js --- */

// Jest OS class
class JSOSValidation extends JSOSParse {
	//-------------------------
	// Instantiation Methods
	//-------------------------
	// Creates the class [object].
	// RETURNS: [object] A new instance.
	constructor() {
		super(); // call parent constructor
	}

	//-------------------------
	// Validation Utilities
	//-------------------------
	// Validates an argument type.
	// RETURNS: [boolean] `true` if success else `false` on fail.
	// * argument	- [string] The name of the argument being tested.
	// * value		- [...] The value to validate.
	// * types		- [string|array] The type(s) to validate against.
	argue( argument, value, types ) {
		if ( !this.prove(value,types) ) {
			console.warn(`Argument '${argument}' failed validation. Expected type(s): ${Array.isArray(types) ? types.join(', ') : types}.`);
			return false;
		}
		return true;
	}

	// Validates multiple arguments against their expected types.
	// RETURNS: [boolean] True if all arguments pass validation, false otherwise.
	// * args - [object] An object where keys are argument names and values are [value, types] pairs.
	//				e.g. { name: ["John Doe", "string"] }
	argues( args ) {
		let valid = true; // determine if any args are invalid
		for ( const [argument,[value,types]] of Object.entries(args) ) {
			if ( !this.prove(value,types) ) {
				console.warn( `Argument '${argument}' failed validation. Expected type(s): ${Array.isArray(types) ? types.join(', ') : types}.` );
				valid = false; // at least one arg is invalid
			}
		}
		return valid;
	}

	// Validates a value against one or more types.
	// RETURNS: [boolean] `true` if success else `false` on fail.
	// * value - [...] The value to validate.
	// * types - [string|array] The type(s) to validate against.
	prove( value, types ) {
		types = Array.isArray(types) ? types : [types]; // Ensure types is an array.
		return types.some( (type)=>this._checkType(value,type) );
	}

	// Internal type-checking logic for individual types.
	// RETURNS: [boolean] True if the value matches the type.
	// * value - [...] The value to validate.
	// * type  - [string] The type to validate against.
	_checkType( value, type ) {
		// Define type-checking logic for each supported type.
		const typeChecks = {
			array:		(v) => Array.isArray(v),
			boolean:	(v) => typeof v==='boolean',
			int:		(v) => Number.isInteger(v),
			number:		(v) => typeof v==='number' && !isNaN(v),
			object:		(v) => typeof v==='object' && v!==null && !Array.isArray(v),
			string:		(v) => typeof v==='string',
			stray:		(v) => Array.isArray(v) && v.every( item =>typeof item==='string' )
			// Additional types can be added here as needed.
		};
		// Define multiple aliases for each type
		const aliasGroups = {
			int:		[ 'int', 'integer' ],
			boolean:	[ 'bool', 'boolean' ],
			object:		[ 'obj', 'object' ],
			string:		[ 'str', 'string' ],
		};
		// Resolve alias if it exists
		const resolvedType = Object.entries(aliasGroups).find(
			( [ _, aliases ] ) =>
				aliases.includes( type )
			)?.[0] || type;
		// Use the corresponding check or fallback to a basic typeof comparison.
		return typeChecks[resolvedType] ? typeChecks[resolvedType](value) : typeof value === type;
	}

	//-------------------------
	// DATA Validating
	//-------------------------
	// Get variable / data type with validation.
	// RETURNS: [string|boolean] The detected data type or a boolean if validation is performed.
	// * variable       - [any] The variable to check.
	//   expectedType   - [string|null] The expected data type (optional, default: null).
	//   validValues    - [Array|null] An array of valid values to check against (optional, default: null).
	datatype( variable, expectedType=null, validValues=null ) {
		// Determine the data type of the variable.
		let detectedType;
		if ( variable===null )
			detectedType	= 'null';
		else if ( Array.isArray(variable) )
			detectedType	= 'array';
		else if ( typeof variable==='number' ) {
			if ( isNaN(variable) )
				detectedType	= 'nan';		// Special case for NaN
			else if ( !isFinite( variable ) )
				detectedType	= 'infinity';	// Special case for Infinity
			else detectedType	= Number.isInteger(variable) ? 'integer' : 'float';
		}
		else if ( typeof variable==='object' ) {
			if ( variable instanceof HTMLElement
				 || variable instanceof HTMLImageElement
				 || variable instanceof HTMLAudioElement ) {
				detectedType	= 'dom'; // General DOM element
			}
			else {
				const proto		= Object.getPrototypeOf( variable );
				detectedType	= proto && proto.constructor ? proto.constructor.name.toLowerCase() : 'object';
			}
		}
		else detectedType	= typeof variable;	// Handle string, boolean, function, undefined, etc.
		// If no validation is requested, return the detected data type.
		if ( !expectedType && !validValues ) return detectedType;
		// Validate the detected type against the expected type.
		const typeValid		= expectedType ? detectedType===expectedType : true;
		// Validate the variable against the array of valid values.
		const valuesValid	= validValues ? validValues.includes(variable) : true;
		// Return true if both validations pass; otherwise, false.
		return typeValid && valuesValid;
	}

	// Validate supplied button data
	/*validateButton( button, index ) {
		// Detect if button is proper
	    if ( !button || typeof button!=='object' ) {
	        console.warn( `Invalid button definition at index ${index}:`, button );
	        return null;
	    }
		// Return validated button data
	    return {
	        text: button.text || `Button ${index + 1}`,
	        classes: button.classes || 'jest-button',
	        onClick: typeof button.onClick==='function' ? button.onClick : null,
	    };
	}*/
}

