//-------------------------
// LibraryHarlequinWindow Library
//-------------------------
JestLibraryRegistry.LibraryHarlequinWindow =
	class LibraryHarlequinWindow {
		/**
		 * Creates the harlequin window library [object] for methods.
		 * RETURNS: [bool] `true` on success, else `false`.
		 * * options	- [object] Configuration options for the application.
		 */
		constructor() { }

		// Configure a window header with controls and a title atop a window [object].
		// RETURNS: [array] of data for elements to build
		// * icon		- [string] of icon url if to use one
		// * title		- [string] value of window header display title
		// * minimize	- [bool] `true` or `false` whether to include minimize button
		// * maximize	- [bool] `true` or `false` whether to include maximize button
		// * close		- [bool] `true` or `false` whether to include close button
		windowHeaderConfig( icon, title, minimize=true, maximize=true, close=true ) {
			let elements	= []; // begin configuration elements [array]
			// --------------------------------
			// Create Window Icon & Title
			// --------------------------------
			// Determine icon
			if ( icon!==null ) {
				const configIcon	=
					{
						name:		'icon',
						tag:		'img',
						classes:	[ 'jest-window-icon', 'jest-style-harlequin' ],
						attributes:	{ src: jestGetURL(icon) }
					};
				elements.push( configIcon ); // push into elements [array]
			}
			// Create title
			const configTitle	=
				{
					name:		'title',
					tag:		'div',
					classes:	[ 'jest-window-title', 'jest-style-harlequin' ],
					text:		title,
				};
			elements.push( configTitle ); // push into elements [array]
			// --------------------------------
			// Create Controls
			// --------------------------------
			let controls	= [];
			// Determine minimize button
			if ( minimize===true ) {
				const configMinBtn	=
					{
						name:		'minimize',
						tag:		'button',
						id:			'minimize-button',
						classes:	[ 'jest-button' ],
						text:		'−',
						callbacks:
							[
								{
									command:	'click',
									id:			'btnMinimize',
									type:		'dom',
									callback:
										function () {
											console.log( this.breadcrumbs[1] );
											this.breadcrumbs[1].minimize();
										}
								}
							]
					};
				controls.push( configMinBtn ); // push into elements [array]
			}
			// Determine maximize button
			if ( maximize===true ) {
				const configMaxBtn	=
					{
						name:		'maximize',
						tag:		'button',
						id:			'maximize-button',
						classes:	[ 'jest-button' ],
						text:		'□',
						callbacks:
							[
								{
									command:	'click',
									id:			'btnMaximize',
									type:		'dom',
									callback:
										function () {
											console.log( this );
											this.breadcrumbs[1].maximize();
										}
								}
							]
					};
				controls.push( configMaxBtn ); // push into elements [array]
			}
			// Add controls to the controls panel configuration
			const configControls		=
				{
					name:		'controls',
					tag:		'div',
					classes:	[ 'jest-window-controls', 'jest-style-harlequin' ],
					elements:	controls
				};
			elements.push( configControls ); // push into elements [array]
			// --------------------------------
			// Wrap-Up & Return
			// --------------------------------
			// Return successful configuration [array]
			return elements;
		}

		// Add event callbacks for dragging
		// * windowObj		- the Window [object] making draggable
		// * panelDrag		- the drag region ie. Panel [object]
		makeWindowDraggable( windowObj, panelDrag ) {
			const header = this.el.querySelector( '.jest-window-header' );
			let offsetX, offsetY, isDragging = false;

			header.addEventListener(
				'mousedown',
				(e) => {
					isDragging		= true;
					offsetX			= e.clientX - this.el.offsetLeft;
					offsetY			= e.clientY - this.el.offsetTop;
					document.body.style.userSelect = 'none'; // Prevent text selection
				});

			document.addEventListener(
				'mousemove',
				(e) => {
					if ( isDragging ) {
						this.el.style.left	= `${e.clientX - offsetX}px`;
						this.el.style.top	= `${e.clientY - offsetY}px`;
					}
				});

			document.addEventListener(
				'mouseup',
				() => {
					isDragging	= false;
					document.body.style.userSelect = ''; // Restore text selection
				});
		}
	};

/* --- BEGIN js/system/application/Application.js --- */

//-------------------------
// Application Class
//-------------------------
class Application extends OSObject {
	// Declare properties
	icon				= 'images/icons/med_book1.png'; // application icon image URL [string] value
	name				= 'Application';		// application name [string] value
	version				= '0.0';				// application version [string] value
	device				= null;					// [object] Device information.
	// Key [objects]
	windows				= [];					// window(s) [object] reference(s)
	shortcut			= null;					// DockShortcut [object]

	// Creates an application.
	// * options	- [object] Configuration options for the application.
	constructor( options={} ) {
		super( options ); // call OSMachine parent constructor
		// Set status to closed
		this.jot( 'status', 'closed' );
		// Process options
		this.name		= options.name || this.name;
		this.version	= options.version || this.version;
		// Setup device information.
		this.device	=
			{
			os       : DeviceEnv.getOS(),		// get operating system [string]
			browser  : DeviceEnv.getBrowser(),	// get browser type [string]
			isApp    : DeviceEnv.isElectron()	// is application [bool]
			};
		console.log( 'Constructing '+this.name+' application ...' );
	}

	// Setup the application [object]
	// RETURNS: [boolean] `true` on success else `false` on fail.
	setup() {
		// Call parent setup method
		return super.setup();
	}

	// Method to launch the application
	// RETURNS: [boolean] `true` on success else `false` on fail.
	launch() {
		return this.gearshift( 'launching' ); // attempt to launch
	}

	// Change the status of the application
	// RETURNS: [boolean] `true` on success else `false` on fail.
	gearshift( status ) {
		// Determine logic based upon requested status change
		const currentMode = this.skim( 'status' );
		switch ( status ) {
			case 'launching':
				// Ensure application isn't running
				if ( currentMode==='closed' ) {
					// Set status to launching
					this.jot( 'status', 'launching' );
					// Show the loading in the dock tray shortcut
					this.shortcut.el.classList.add( 'loading' );
					return true;	// success
				}
				break;
			case 'idle':
				// Ensure application is already launching
				if ( currentMode==='launching' ) {
					// Set status to idle
					this.jot( 'status', 'idle' );
					// Idle the dock tray shortcut
					this.shortcut.el.classList.remove( 'loading' );
					return true;	// success
				}
				break;
			case 'close': break;
		}
		return false; // fail
	}

	// Add a window to application.
	// RETURNS: window [object] else [null] on fail.
	// * title		- [string] value of the window title.
	// * config		- [object] to configure the window with.
	addWindow( title='Application Window', config ) {
		// Initialize modal-specific components
		const windowObj	= new Window( { title: title, breadcrumbs: [this], ...config } );
		this.windows.push( windowObj );		// store window reference inside the application
		return windowObj;					// success
	}

	// Open the a window [object]
	// RETURNS: [bool] `true` on success else `false`
	openWindow( windowObj ) {
		// Require windowObj to be part of application windows
		if ( !this.windows.includes(windowObj) )
			return false; // "window" not part of application
		// --------------------------------
		// Open the window
		// --------------------------------
		windowObj.open(); // open the window
		return true; // success
	}

	// Create a dock shortcut [object]
	// RETURNS: [bool] `true` on success else `false`
	dockShortcut() {
		// Require this element to be created
		//if ( this.el===null ) return false;
		// --------------------------------
		// Create Panel [object]
		// --------------------------------
		const shortcut	= new DockShortcut( this );
		this.shortcut	= shortcut; // keep [object] reference
		// Append to DOM & return
		JestEnvironment.dock.shortcuts.addShortcut( shortcut );
	}
}

