//-------------------------
// JestDisplay Class
//-------------------------
// Display class for custom content inside of a menu.
class JestDisplay extends JestElement {
	// Object properties
	canvases	= {};			// [object] Map of named ElementCanvas objects.
	target		= null;			// [object] JestElement inner target object.z

	// --------------------------------
	// Constructor
	// --------------------------------
	// Construct the [object].
	// RETURNS: [void].
	// * client		- client [object] that this piece belongs to.
	constructor( client ) {
		super( client ); // call parent constructor
	}

	// --------------------------------
	// Initialization
	// --------------------------------
	// Build the element [object].
	// RETURNS: [void].
	// * name		- unique [string] value of component name in the system.
	// * classes	- [array] of classes to add to panel element.
	build( name='display', classes=[] ) {
		// Construct the parent panel.
		if ( classes===null ) classes = [];
		super.build( "div", name, ['display'].mergeUnique(classes) );
		// Enable the display by default.
		this.enable(); // enable
	}

	//-------------------------
	// Canvas: Add
	//-------------------------
	// Add a named canvas to the display.
	// RETURNS: [ElementCanvas] the created canvas.
	// * name		– [string] unique canvas name.
	addCanvas( name ) {
		// Validate name.
		if ( !name || typeof name!=='string' ) return null;
		// Prevent duplicates.
		if ( this.canvases[ name ] ) return this.canvases[ name ];
		// Create and store canvas.
		const canvas = new ElementCanvas( this.client );
		canvas.resize( 0, 0 ); // resize to nothing
		this.canvases[ name ] = canvas;
		this.panel.addPanel( name, canvas );
		return canvas; // return canvas [object]
	}

	//-------------------------
	// Canvas: Remove
	//-------------------------
	// Remove a named canvas from the display.
	// RETURNS: [bool] true if removed, false if not found.
	// * name		– [string] canvas name to remove.
	removeCanvas( name ) {
		const canvas = this.canvases[ name ];
		if ( !canvas ) return false;
		// Remove from DOM and delete ref.
		canvas.remove(); // remove canvas
		delete this.canvases[ name ];
		return true; // success
	}

	//-------------------------
	// Canvas: Get
	//-------------------------
	// Get a named canvas from the map.
	// RETURNS: [ElementCanvas|null] the canvas if found.
	// * name		– [string] name of the canvas.
	getCanvas( name ) {
		return this.canvases[name] ?? null;
	}

	// --------------------------------
	// Add a Panel to Display
	// --------------------------------
	// Set a target element inside the display.
	// RETURNS: [bool] success.
	// target	- [JestElement] object to add, or [null] to autogenerate.
	setTarget( target ) {
		// Check if argument is valid.
		if ( !(target instanceof JestElement) ) {
			target	= new JestElement( this.client );
			target.build( 'div', 'target', ['display-target'] );
		}
		// Clear previous target if set.
		if ( this.target ) {
			this.target	= null; // clear target
			this.panel.removePanel( 'target' ); // remove panel
		}
		// Add the element inside the display.
		this.target	= target; // keep ref
		this.panel.addPanel( 'target', target.panel ); // add to DOM
		return true; // susccess
	}

	// Get the display target.
	// RETURNS: [object] or [null].
	getTarget() { return this.target; }

	// --------------------------------
	// Enabling & Activating Method(s)
	// --------------------------------
	// Enable the display.
	// RETURNS: [void].
	// * action		- [string] Value of action to toggle: 'enable', 'activate', etc.
	// * lever		- [bool] Value whether to toggle on `true` else `false`.
	toggle( action, lever ) {
		// Determine action being taken.
		switch ( action ) {
			case 'enable': // enable/disable
				if ( lever ) this.enable();		// enable
				else this.disable();			// disable
				break;
		}
	}

	//--------------------------------
	// Enable Display
	//--------------------------------
	// RETURNS: [bool] true if set, else false.
	enable() {
		// Do not double enable.
		const enabled	= this.skim( 'enabled' );
		if ( enabled===true ) return false; // no need to eanble
		// Enable.
		this.jot( 'enabled', true ); // enable
		this.panel.removeClass( 'disabled' );
		return true; // enabled
	}

	//--------------------------------
	// Disable Display
	//--------------------------------
	// RETURNS: [bool] true if set, else false.
	disable() {
		// Do not double enable.
		const enabled	= this.skim( 'enabled' );
		if ( enabled===false ) return false; // no need to disable
		// Disable.
		this.jot( 'enabled', false ); // disable
		this.panel.addClass( 'disabled' );
		return true; // disabled
	}

	//-------------------------
	// Render Canvas
	//-------------------------
	// Draw canvas content to named canvas.
	// * name		– [string] name of canvas to render into.
	// * source		– [ElementCanvas] canvas to draw.
	render( name, source ) {
		const canvas = this.getCanvas( name );
		if ( canvas ) canvas.draw( source, true, true );
	}
}

/* --- BEGIN js/apps/jest/components/ui/JestMenu.js --- */

//-------------------------
// JestMenu Class
//-------------------------
// A menu for handling buttons & actions.
class JestMenu extends JestElement {
	// Object properties
	actions			= [];			// [array] of possible action(s).
	buttons			= {};			// [object] of active buttons.

	// --------------------------------
	// Constructor
	// --------------------------------
	// Construct the [object].
	// RETURNS: [void].
	// * client		- client [object] that this piece belongs to.
	constructor( client ) {
		super( client ); // call parent constructor
	}

	// --------------------------------
	// Initialization
	// --------------------------------
	// Build the element [object].
	// RETURNS: [void].
	// * name		- unique [string] value of component name in the system.
	// * classes	- [array] of classes to add to panel element.
	build( name='menu', classes=[] ) {
		// Construct the parent panel.
		if ( classes===null ) classes = [];
		super.build( "div", name, ['menu'].mergeUnique(classes) );
	}

	// --------------------------------
	// Action Handling
	// --------------------------------
	// Generate menu action button(s)
	// RETURNS: [void].
	// * action		- [object] Data of action(s) to create a button for.
	/*addActions( actions ) {
		// Iterate modes to generate a button for each.
		Object.entries(actions).forEach( action => this.addAction(action) );
	}

	// Generate menu action button.
	// RETURNS: [void].
	// * action		- [object] Value of action data to create a button.
	addAction( action ) {
		// Determine if action has been previously processed.
		if ( action.name in this.actions ) return false;
		// Register a new action.
		this.actions[action.name] = action;
		return true; // success
	}*/

	// Generate menu action button.
	// RETURNS: [object] JestButton or [null] on fail.
	// * action		- [object] Value of action to create a button for.
	createButton( action ) {
		// Determine if action has been previously processed.
		if ( action.name in this.buttons ) {
			console.warn( `Button with action key "${action.name}" already exists.` );
			return null; // fail
		}
		// Create a new button for the action
		const button	= new JestButton( this.client );
		button.build( action.name, null, action.text );
		this.addButton( action, button ); // add button to panel
		return button; // success
	}

	// Generate menu action button.
	// RETURNS: [void].
	// * action		- [object] Value of action to create a button for.
	// * button		- [object] JestButton serving as a clickable button.
	addButton( action, button ) {
		// Validate argument.
		if ( !(button instanceof JestButton) ) {
			console.warn( `Invalid argument type for argument "button".` );
			return false; // fail
		}
		// Determine if action has been previously processed.
		if ( action.name in this.buttons ) {
			console.warn( `Button with action key "${action.name}" already exists.` );
			return false; // fail
		}
		// Add button to panel.
		this.buttons[action.name] = button; // store button reference
		button.panel.register( 'click', 'tab', e=>this.btnClick(e,action,button), 'dom' );
		this.panel.addPanel( action.name, button.panel ); // add button to panel
		return true; // success
	}

	// Get button by name value.
	// RETURNS: [JestButton] instance, or [null].
	// * skey	- [string] Value of button unique key.
	getButton( skey ) {
		// Loop through buttons & find matching button.
		for ( const key in this.buttons ) {
			const button = this.buttons[key]; // get the button object
			if ( button.skey===skey )
				return button; // found button
		}
		return null; // no button found
	}

	// Remove a menu action button.
	// RETURNS: [void].
	// * button		- [object] JestButton serving as a clickable button.
	removeButton( button ) {
		// Validate argument.
		if ( !(button instanceof JestButton) ) {
			console.warn( `Invalid argument type for argument "button".` );
			return false; // fail
		}
		// Detach event listener(s)
		button.panel.unregister( 'click', 'tab' );
		// Remove the button DOM element.
		this.panel.removePanel( button.skey ); // remove button from panel
		return true; // success
	}

	// --------------------------------
	// Button State Handling
	// --------------------------------
	// Toggle a menu button on/off.
	// * key		- [string] Value of menu button to toggle.
	// * lever		- [bool] Value whether to toggle on `true` else `false`.
	toggle( key, lever=true ) {
		// Check for button.
		if ( this.buttons?.[key] ) {
			const button = this.buttons[key];
			button.toggle( 'enable', lever ); // toggle button
		}
	}

	// Toggle all menu buttons.
	// RETURNS: [void].
	// * lever		- [bool] Value whether to toggle on `true` else `false`.
	toggleAll( lever=true ) {
		// Iterate all buttons & enable/disable.
		for ( const key in this.buttons ) {
			// Turn off all buttons.
			const button = this.buttons[key];
			button.toggle( 'enable', lever ); // toggle button
		}
	}

	// --------------------------------
	// Button State Handling
	// --------------------------------
	// Enable or disable a single button.
	// RETURNS: [void].
	// * name		- [string] Value of button name.
	enableButton( name ) {
		// Check for button.
		const button = this.buttons[name];
		if ( button ) button.enable(); // enable
	}

	// Enable or disable entire menu.
	// RETURNS: [void].
	enable() {
		// Iterate all buttons & enable.
		for ( const name in this.buttons )
			this.buttons[name].enable();
	}

	// Deactivate all the buttons.
	// RETURNS: [void].
	deactivateButtons() {
		// Toggle "active" Button Class
		Object.entries(this.buttons).forEach(
			( [key,button] ) => {
				button.deactivate();
			});
	}

	// --------------------------------
	// Event Handling
	// --------------------------------
	// Callback when a button was clicked.
	// RETURNS: [void].
	// * e			- [object] MouseEvent event listener data.
	// * action		- [string] Value of action of button.
	// * button		- [object] JestButton serving as a clickable button.
	btnClick( e, action, button ) {
		//console.log( `Button ${action.name} clicked.` );
		//console.log( action );
		// Emit an event
		this.emit( 'btnClick', null, e, action, button );
	}
}

