//-----------------------------
// JestInputTextarea Class
//-----------------------------
// Multi-line textarea input for long-form content.
// Extends: JestInput
// Emits: 'input', 'change'
class JestInputTextarea extends JestInput {
	// Object Properties
	name         = null;		// [string|null] input name
	id           = null;		// [string] HTML id
	defaultValue = null;		// [string|null] default content
	placeholder  = null;		// [string|null] placeholder hint
	rows         = 4;			// [int] row count for textarea height

	//-------------------------
	// Constructor
	//-------------------------
	// Initializes a textarea field with configurable rows and placeholder.
	// RETURNS: [void].
	// * client			- [object] parent client application.
	constructor(
		client, name=null, id=null, defaultValue="",
		placeholder=null, rows=4, readOnly=false ) {
		super( client ); // call parent constructor
		// Determine default value, placholder field hint & label.
		this.setName( name ?? null );				// [string] value of field name
		this.setId( id ?? this.skey );				// [string] HTML id
		this.setDefault( defaultValue ?? null );	// [string] default input value
		this.setPlaceholder( placeholder ?? null );	// [string] field hint (if no default input)
		this.setReadonly( readOnly ?? false );		// [bool] set field read-only
	}

	//-------------------------
	// Build UI
	//-------------------------
	// Build the element [object].
	// creates <textarea> element and registers event handlers
	// RETURNS: [void].
	// * name		- unique [string] name of component.
	// * classes	- [array] additional CSS classes to apply.
	build( name='textarea', classes=[] ) {
		if ( classes === null ) classes = [];
		super.build( name, ['textarea'].mergeUnique( classes ));
		// Build initial panel element.
		this.panel.addElements([{
			name		: 'input',
			tag			: 'textarea',
			text		: this.defaultValue,
			attributes	:
				Object.assign({
					id		: this.id,
					name	: this.name,
					rows	: this.rows
					},
					this.placeholder !== null ? { placeholder:this.placeholder } : {}
					)
			}]);

		// cache textarea reference
		this.field = this.panel.refs.input;

		// wire live input + finalized change
		this.registerDOMEvent( 'input' );
		this.registerDOMEvent( 'change' );
	}

	//-------------------------
	// Event: Input
	//-------------------------
	// emits input with current text
	input( e ) {
		this.emit( 'input', null, e.target.value );
	}

	//-------------------------
	// Event: Change
	//-------------------------
	// emits change with current text
	change( e ) {
		this.emit( 'change', null, e.target.value );
	}

	//-------------------------
	// Get Current Value
	//-------------------------
	// RETURNS: [string]
	getValue() {
		return this.field ? this.field.el.value : this.defaultValue;
	}

	//-------------------------
	// Set Value
	//-------------------------
	// * val – [string] new content
	setValue( val ) {
		if ( this.field ) this.field.el.value = val;
	}
}

/* --- BEGIN js/apps/jest/components/ui/JestInputFileSelect.js --- */

//-----------------------------
// JestInputFileSelect Class
//-----------------------------
// Cross-platform file select panel
// Extends: JestElement
class JestInputFileSelect extends JestInput {
	// Object properties
	accept			= null;		// [string] Value of accepted file(s) hint
	allowMultiple	= false;	// [bool] whether to allow selecting multiple files

	//--------------------------------
	// Constructor
	//--------------------------------
	// Construct the [object].
	// RETURNS: [void].
	// * client		- client [object] this piece belongs to.
	// * accept		- [string] accepted filetypes (e.g. '.txt,.json').
	constructor( client, accept='' ) {
		super( client ); // call parent constructor
		this.accept		= accept ?? '';
	}

	//--------------------------------
	// Build Component
	//--------------------------------
	// Build the element [object].
	// RETURNS: [void].
	// * name		- unique [string] name of component.
	// * classes	- [array] of classes to add to panel element.
	build( name='file-select', classes=[] ) {
		// Construct parent panel
		if ( classes===null ) classes = [];
		super.build( name, ['file-select'].mergeUnique(classes) );
		// Add hidden input element (fallback)
		this.panel.addElements([
			{
				name:		'input',
				tag:		'input',
				attributes:
					{
						type:		'file',
						accept:		this.accept,
						style:		'display:none',
						multiple:	this.allowMultiple
					},
				callbacks:
					[{
						command:	'change',
						classes:	'input-file',
						type:		'dom',
						callback:	( e ) => { this.onInputFileSelect(e); }
					}]
			}
		]);
		// Store DOM input reference
		this.field	= this.panel.refs.input;
	}

	//--------------------------------
	// Open File Dialog (Cross-platform)
	//--------------------------------
	// Trigger file open dialog based on environment
	// RETURNS: [void]
	async openFileDialog() {
		//--------------------------------
		// Detect Environment
		//--------------------------------
		const isElectron	= !!( window && window.process && window.process.type );
		//--------------------------------
		// Electron (v.<12): Path-Based Open
		//--------------------------------
		// If Electron, handle file open differently.
		if ( isElectron ) {
			try {
				const { dialog }	= require( 'electron' ).remote;
				const fs			= require( 'fs' );
				const { filePaths }	=
					await dialog.showOpenDialog({
						properties: [ this.allowMultiple ? 'multiSelections' : 'openFile' ],
						filters:
							[{
								name:		'Allowed Files',
								extensions:	this.accept.replace(/\./g,'').split(',')
							}]
						});
				// Check if files have been selected.
				if ( filePaths && filePaths.length>0 ) {
					for ( const path of filePaths ) {
						const data	= fs.readFileSync( path );
						// Get file information.
						const fileInfo = this.client.getFileInfo( null, null, data, null, 'local' );
						// Emit path with file data and path (one per file)
						await this.emitAsync( 'select', {}, fileInfo );
					}
				}
			}
			catch ( err ) {
				console.error( `JestInputFileSelect Electron Open Error:`, err );
			}
		}
		//--------------------------------
		// Electron (v.>12): Using Context Bridge
		//--------------------------------
		if ( window.jestAPI && window.jestAPI.openFileDialog ) {
			console.error( 'Calling Electron openFileDialog' );
			const result =
				await window.jestAPI.openFileDialog({
					allowMultiple:	this.allowMultiple,
					extensions:		this.accept.replace(/\./g,'').split(',')
					});
			if ( result.files && result.files.length>0 ) {
				for ( const fileObj of result.files ) {
					// Get file information.
					const fileInfo = this.client.getFileInfo( fileObj.path, null, fileObj.data, null, 'local' );
					// Emit event.
					this.emit( 'select', null, fileInfo );
				}
			}
			return;
		}
		//--------------------------------
		// Chromium Browser: showOpenFilePicker
		//--------------------------------
		else if ( 'showOpenFilePicker' in window ) {
			try {
				const handles	=
					await window.showOpenFilePicker({
						multiple:	this.allowMultiple,
						types:
							[{
								description:	'Allowed Files',
								accept:			this._buildAcceptObject()
							}]
					});
				for ( const handle of handles ) {
					const file		= await handle.getFile();
					const fileData	= await file.arrayBuffer();
					// Get file information.
					const fileInfo = this.client.getFileInfo( null, file, fileData, handle, 'local' );
					// Emit event with file data and handle
					this.emit( 'select', null, fileInfo );
				}
			}
			catch ( err ) {
				console.error( `JestInputFileSelect Browser Open Error:`, err );
			}
		}
		//--------------------------------
		// Fallback: input type=file
		//--------------------------------
		else {
			this.field.el.click(); // Trigger hidden input element
		}
	}

	//--------------------------------
	// Input File Select Handler
	//--------------------------------
	// Handler for fallback <input type="file"> select event
	// * e		- event [object] from DOM input change
	onInputFileSelect( e ) {
		// Get file(s) & iterate to send select event(s).
		const files	= e.target.files;
		for ( const file of files ) {
			// Read file as ArrayBuffer
			const reader = new FileReader();
			/*reader.onload =
				( e ) => {
					// Emit event with file data (one per file selected).
					this.emit( 'select', null, { file: file, data: e.target.result } );
				};
				reader.readAsArrayBuffer( file );*/
			// Get file information.
			const fileInfo = this.client.getFileInfo( null, file, null, null, 'local' );
			// Emit path with file data and path (one per file)
			this.emit( 'select', null, fileInfo );
		}
	}

	//--------------------------------
	// Build Accept Object for showOpenFilePicker
	//--------------------------------
	// RETURNS: [object] accept object for showOpenFilePicker
	_buildAcceptObject() {
		// Assemble extensions & MIME types.
		const extensions	= this.accept.replace(/\./g,'').split(',');
		const mimeTypes		= extensions.map( (ext)=>this._mapExtensionToMimeType(ext) );
		// Begin accept [object].
		const acceptObj		= {};
		mimeTypes.forEach(
			( mime, index ) => {
				acceptObj[mime] = [ `.${extensions[index]}` ];
			});
		return acceptObj; // return compiled list of mime extensions
	}

	//--------------------------------
	// Map Extension to Basic MimeType
	//--------------------------------
	// RETURNS: [string] basic MIME type
	// * ext	- [string] file extension
	_mapExtensionToMimeType( ext ) {
		// Simple static map — expand as needed
		const map = {
			'txt':	'text/plain',
			'json':	'application/json',
			'csv':	'text/csv',
			'png':	'image/png',
			'jpg':	'image/jpeg',
			'jpeg':	'image/jpeg',
			'gif':	'image/gif'
			};
		return map[ext] || 'application/octet-stream';
	}
}

/* --- BEGIN js/apps/jest/components/ui/JestInputSelectOption.js --- */

//-----------------------------
// JestInputSelectOption Class
//-----------------------------
// Single option element for select dropdown.
class JestInputSelectOption extends JestElement {
	// Parent ownership
	_owner		= null;		// [object] reference to owning JestInputSelect (or null)
	// Object properties
	_index		= -1;		// [int] Value of input select option's position in dropdown.
	value		= '';		// [string] internal value attribute
	label		= '';		// [string] visual display text

	//--------------------------------
	// Constructor
	//--------------------------------
	// Constuct the [object] instance.
	// * client		- [object] parent reference
	// * value		- [string] option value
	// * label		- [string] visible label
	//   index		- [int] value of frame's index in the animation.
	constructor( client, value, label, index=-1 ) {
		super( client );			// call parent constructor
		this.value	= value;		// set unique value/id
		this.label	= label;		// set select box option readable label
		this.setIndex( index );		// default layer index
	}

	//--------------------------------
	// Set the Owning Select
	//--------------------------------
	// Called automatically by JestInputSelect during _moveOptionTo().
	setOwner( select ) {
		//--------------------------------
		// Validate Input
		//--------------------------------
		// Validate the select is an input dropdown.
		if ( !(select instanceof JestInputSelect) && select!==null ) {
			console.warn( 'setOwner(): Invalid select passed in.' );
			return false; // abort
		}

		//--------------------------------
		// Set the Owner
		//--------------------------------
		// Set the owner.
		this._owner = select;
	}
	// Called automatically by JestInputSelect during _moveOptionTo().
	getOwner() { return this._owner; }
	// Check if this option is inside a select box
	// RETURNS: [bool]
	hasOwner() { return !!this._owner; }

	//--------------------------------
	// Remove Self From Owner
	//--------------------------------
	// Detaches this option from its parent JestInputSelect if it exists.
	// RETURNS: [bool] true if removed successfully
	detachFromOwner() {
		// Check if owner is set.
		if ( !this._owner ) return false;
		// Remoev the option if it exists.
		const success = this._owner.removeOption( this.value );
		this.setOwner( null ); // nullify the owner
		return success; // return [boo]
	}

	//-------------------------
	// Index Management
	//-------------------------
	// Get the layer's index in the layer lineup.
	// RETURNS: [int] index value of layer order in the frame.
	getIndex() {
		return this._index;
	}

	// Sets the index of this layer within the frame.
	setIndex( index ) {
		this._index	= index;
	}

	//--------------------------------
	// Build Option Element
	//--------------------------------
	// Build the element [object].
	// RETURNS: [void].
	// * name		- unique [string] name of component.
	// * classes	- [array] additional CSS classes to apply.
	build( name='option', classes=[] ) {
		// Construct the parent panel.
		if ( classes === null ) classes = [];
		super.build( name, [`option-${this.value}`].mergeUnique( classes ));
		this.panel.el.value		= this.value;
		this.panel.el.innerText	= this.label;
	}

	//--------------------------------
	// Update the label text of the option
	//--------------------------------
	// RETURNS: [void]
	// * label – [string] new label text
	setLabel( label ) {
		this.label = label;
		if ( this.panel?.el ) this.panel.el.innerText = label;
	}
}

