//-----------------------------
// JestInputRadioSet Class
//-----------------------------
// Group of related radio buttons with a single selected value.
// Extends: JestInput
// Emits: 'change' – when selection changes
class JestInputRadioSet extends JestInput {
	// Object Properties
	name        = null;			// [string] shared group name for all radio inputs
	id          = null;			// [string|null] optional ID base (currently unused)
	options     = [];			// [array] list of { value, label } radio choices
	selected    = null;			// [string|null] current selected value

	//-------------------------
	// Constructor
	//-------------------------
	// Initializes the radio set group with options and default selection.
	// * client        – [object] parent system client
	// * name          – [string] group name (used in all radio inputs)
	// * options       – [array] of {value, label} objects
	// * defaultValue  – [string|null] value to mark as checked initially
	constructor( client, name, options=[], defaultValue=null ) {
		super( client ); // call parent constructor
		this.name		= name;
		this.options	= options;
		this.selected	= defaultValue;
	}

	//-------------------------
	// Build UI
	//-------------------------
	// Creates radio inputs and labels, wiring change events.
	// * name     – [string] internal element name
	// * classes  – [array] additional class names
	build( name='radio-set', classes=[] ) {
		if ( classes === null ) classes = [];
		super.build( name, ['radio-set'].mergeUnique( classes ));

		// loop through each option and build radio+label
		this.options.forEach( opt => {
			const id = `${this.name}_${opt.value}`;

			this.panel.addElements([
				{
					name		: `input_${opt.value}`,
					tag			: 'input',
					attributes	: {
						type	: 'radio',
						id		: id,
						name	: this.name,
						value	: opt.value,
						checked	: ( opt.value === this.selected )
					}
				},
				{
					name		: `label_${opt.value}`,
					tag			: 'label',
					attributes	: { for:id },
					text		: opt.label
				}
			]);

			// wire change listener per radio
			const field = this.panel.refs[ `input_${opt.value}` ];
			field.register( 'change', `change-${opt.value}`, e => this.change( e ) );
		});
	}

	//-------------------------
	// Event: Change
	//-------------------------
	// updates selection value and emits 'change'
	// * e – [DOMEvent]
	change( e ) {
		this.selected = e.target.value;
		this.emit( 'change', null, this.selected );
	}

	//-------------------------
	// Set Selected Value
	//-------------------------
	// sets selected value and updates radio DOM state
	// * val – [string]
	setValue( val ) {
		this.selected = val;

		this.options.forEach( opt => {
			const fld = this.panel.refs[ `input_${opt.value}` ];
			if ( fld ) fld.el.checked = ( opt.value === val );
		});
	}

	//-------------------------
	// Get Selected Value
	//-------------------------
	// RETURNS: [string|null] selected value
	getValue() {
		return this.selected;
	}
}

/* --- BEGIN js/apps/jest/components/ui/JestInputCheckbox.js --- */

//-----------------------------
// JestInputCheckbox Class
//-----------------------------
// Versatile single checkbox input with full label support.
// Emits: 'change' – when checked state changes
//        'click'  – when manually clicked
class JestInputCheckbox extends JestInput {
	// Object Properties
	checked         = false;		// [bool] whether the checkbox is initially checked

	//-------------------------
	// Constructor
	//-------------------------
	// Initializes the input field properties.
	// RETURNS: [void]
	// * client          – [object] parent application client
	// * name            – [string|null] name of the input (form use)
	// * id              – [string|null] HTML ID; if null, defaults to auto-generated skey
	// * defaultChecked  – [bool] default state of checkbox (true/false)
	// * labelText       – [string|null] optional text to show in a <label> element
	// * readOnly		- [bool]   Whether field is read-only
	constructor(
		client, name=null, id=null, defaultChecked=false,
		labelText=null, readOnly=false ) {
		super( client ); // call parent constructor
		// Determine default value, placholder field hint & label.
		this.setChecked( defaultChecked );		// [bool] whether box is checked
		this.setLabel( labelText ?? null );		// [string] the text for the label
		this.setName( name ?? null );			// [string] value of field name
		this.setId( id ?? this.skey );			// [string] HTML id
		this.setReadonly( readOnly ?? false );	// [bool] set field read-only
	}

	//-------------------------
	// Build UI
	//-------------------------
	// Constructs the HTML structure and initializes DOM references.
	// RETURNS: [void]
	// * name     – [string] internal identifier name for this field type
	// * classes  – [array] list of extra CSS class names (merged with 'checkbox')
	build( name='checkbox', classes=[] ) {
		// Construct the parent panel.
		if ( classes===null ) classes = [];
		super.build( name, ['checkbox'].mergeUnique(classes) );
		//--------------------------------
		// Create Input Field
		//--------------------------------
		// Add actual checkbox input field
		this.panel.addElements([
			{
				name		: 'input',
				tag			: 'input',
				attributes	:
					{
					type	: 'checkbox',
					id		: this.id,
					name	: this.name,
					checked	: this.checked
					}
			}]);
		// Cache input element
		this.field = this.panel.refs.input;
		// Register standard DOM events (auto-wired to this.change() etc)
		this.registerDOMEvent( 'change' );
		//--------------------------------
		// Ensure Default(s) Are Applied
		//--------------------------------
		// Set default(s) (supplied previously).
		this.setChecked( this.checked ); // [bool] whether box is checked
	}

	//-------------------------
	// Set Checked State
	//-------------------------
	// Programmatically set checkbox to checked/unchecked.
	// * val – [bool] new state
	setChecked( val=true ) {
		// Set checked value.
		this.checked = Boolean( val );
		// Trigger field display.
		if ( this.field )
			this.field.el.checked = this.checked;
		// Emit the changed event.
		this.emit( 'change', null, val );
	}

	//-------------------------
	// Get Checked State
	//-------------------------
	// RETURNS: [bool] current checkbox state
	getChecked() {
		return this.field ? this.field.el.checked : this.checked;
	}

	//-------------------------
	// Event: Change
	//-------------------------
	// Called when checkbox value is toggled.
	// Emits 'change' with boolean state.
	// * e – [DOMEvent] browser event object
	change( e ) {
		// Set checked value.
		this.setChecked( e.target.checked );
	}

	//-------------------------
	// Event: Click
	//-------------------------
	// Optional click handler. Emits full event.
	// * e – [DOMEvent] browser event object
	click( e ) {
		this.emit( 'click', null, e );
	}
}

