//-------------------------
// JestForm Class
//-------------------------
// Create a form for grouping input field(s).
class JestForm extends JestMenu {
	// Object properties
	fields		= {};			// [object] Input fields included in the form.

	// --------------------------------
	// Constructor
	// --------------------------------
	// Construct the [object].
	// RETURNS: [void].
	// * client		- client [object] that this piece belongs to.
	constructor( client ) {
		super( client ); // call parent constructor
	}

	// --------------------------------
	// Initialization
	// --------------------------------
	// Build the element [object].
	// RETURNS: [void].
	// * name		- unique [string] value of component name in the system.
	// * classes	- [array] of classes to add to panel element.
	build( name='form', classes=[] ) {
		// Construct the parent panel.
		if ( classes===null ) classes = [];
		super.build( name, ['form'].mergeUnique(classes) );
	}

	//--------------------------------
	// Add Input Field to Form
	//--------------------------------
	// RETURNS: [bool]
	// * name  – [string] field key
	// * input – [JestInput] instance
	addField( name, input ) {
		// Require element to exist.
		if ( !input?.panel?.el ) return false;
		// Store input field reference by name.
		this.fields[name] = input;
		// Add input DOM element to the panel.
		this.panel.addPanel( name, input.panel );
		return true; // success
	}

	//--------------------------------
	// Remove Field from Form
	//--------------------------------
	// RETURNS: [bool]
	// * name – [string]
	removeField( name ) {
		// Require input [object] to exist.
		const field = this.fields[name];
		if ( !field ) return false;
		delete this.fields[name]; // delete it
		// Remove input DOM element from panel.
		this.panel.removePanel( name );
		field.destroy();
		return true; // success
	}

	//--------------------------------
	// Get Field Reference
	//--------------------------------
	// RETURNS: [JestInput|null]
	// * name – [string]
	getField( name ) {
		return this.fields[name] ?? null;
	}

	//--------------------------------
	// Get Single Field Value
	//--------------------------------
	// RETURNS: [any]
	// * name – [string]
	getValue( name ) {
		// Get the field input [object].
		const field = this.getField( name );
		return field?.getValue?.(); // return value
	}

	//--------------------------------
	// Get All Field Values
	//--------------------------------
	// RETURNS: [object]
	getValues() {
		const out = {};
		// Iterate all fields by key-name.
		for ( const name in this.fields ) {
			const field = this.fields[name];
			if ( field?.getValue )
				out[name] = field.getValue();
		}
		return out;
	}

	//--------------------------------
	// Set Single Field Value
	//--------------------------------
	// RETURNS: [void]
	// * name – [string] Name of field.
	// * val  – [any]
	setValue( name, val ) {
		// Get the field input [object].
		const field = this.getField( name );
		// Attempt to set the value.
		if ( field?.setValue )
			field.setValue( val );
	}

	//--------------------------------
	// Set Multiple Field Values
	//--------------------------------
	// RETURNS: [void]
	// * obj – [object] of key/value pairs
	setValues( obj ) {
		// Iterate all properties by key-name.
		for ( const name in obj )
			this.setValue( name, obj[name] );
	}

	//--------------------------------
	// Clear All Fields
	//--------------------------------
	// RETURNS: [void]
	clearFields() {
		// Iterate all fields by key-name.
		for ( const name in this.fields )
			this.removeField( name );
	}

	//--------------------------------
	// Validate All Fields
	//--------------------------------
	// RETURNS: [object] { valid:bool, errors:object }
	// * validators – [object] optional map: { fieldName: (val)=>bool|string }
	validate( validators=null ) {
		let isValid = true;
		const errors = {};
		// Iterate all fields by key-name.
		for ( const name in this.fields ) {
			// Get input [object].
			const field	= this.fields[name];
			const value	= field?.getValue?.(); // get field value
			// Run custom validator if provided
			if ( validators?.[name] ) {
				const result = validators[name]( value );
				if ( result!==true ) {
					isValid			= false;
					errors[name]	= result || 'Invalid value';
				}
			}
			// Default required check if no validator and field has .required
			else if ( field?.required && (value===null || value==='') ) {
				isValid			= false;
				errors[name]	= 'Required';
			}
		}
		// Return valid status & error(s).
		return { valid: isValid, errors: errors };
	}

	//--------------------------------
	// Enable/Disable Single Field
	//--------------------------------
	// RETURNS: [void]
	// * name   – [string]
	// * active – [bool] true = enabled
	setDisabled( name, active=false ) {
		// Get the field input [object].
		const field = this.getField( name );
		if ( field?.setDisabled )
			field.setDisabled( !active );
	}

	//--------------------------------
	// Enable/Disable Entire Form
	//--------------------------------
	// RETURNS: [void]
	// * active – [bool] true = enabled
	setAllDisabled( active=false ) {
		// Iterate all fields by key-name.
		for ( const name in this.fields )
			this.setDisabled( name, active );
	}

	//==================================================
	// checkFieldMismatches()
	//==================================================
	// Compares field values in the form against the given data.
	// Highlights mismatched fields with a CSS class and toggles apply button.
	// RETURNS: [bool] True if any mismatches were found.
	// * dataValues			- [object] Source of expected data values.
	// * fieldMapCompare	- [object] { formFieldKey: dataKey }
	checkFieldMismatches( dataValues, fieldMapCompare ) {
		// Track if any mismatches found
		let foundMismatch	= false;

		// Iterate over comparison map
		Object.entries(fieldMapCompare).forEach(
			( [ f, d ] ) => {
				//--------------------------------
				// Grab field and data values
				//--------------------------------
				// Compare field(s).
				const fieldVal	= this.fields[f]?.getValue?.()?.toString() ?? '';
				const dataVal	= dataValues[d]?.toString();

				//--------------------------------
				// Compare values
				//--------------------------------
				// Log mismatch if fields don't match.
				const mismatch	= fieldVal !== dataVal;

				// Apply unsaved highlight
				this.fields[f]?.panel?.toggleClass?.( 'unsaved', mismatch );

				// Track mismatch found
				if ( mismatch===true )
					foundMismatch = true;
			});
		// Return whether any fields have changed.
		return foundMismatch;
	}
}

/* --- BEGIN js/apps/jest/components/ui/JestCuratorObject.js --- */

//-----------------------------
// JestCuratorObject Class
//-----------------------------
// Object wrapper for registered selectable data.
class JestCuratorObject extends JestElement {
	// Object properties
	id		= '';			// [string] unique identifier
	data	= {};			// [object] attached data
	action	= '';			// [string] optional data action

	//--------------------------------
	// Constructor
	//--------------------------------
	// RETURNS: [void]
	// * client	- [object] parent context
	// * id		- [string] object ID
	// * data	- [object] optional payload
	constructor( client, id='', data={} ) {
		super( client ); // call parent constructor
		this.id		= id;
		this.data	= data;
		this.action	= data.action ?? '';
	}

	//--------------------------------
	// Build Component (Optional View)
	//--------------------------------
	// Create a visible panel with info.
	// RETURNS: [void]
	// * name		- [string] DOM name ID
	// * classes	- [array] optional class list
	build( name='predefined-object', classes=[] ) {
		// Construct the parent panel.
		if ( classes===null ) classes = [];
		super.build( 'div', name, ['predefined-object'].mergeUnique(classes) );
		/*this.panel.addElements([
			{ name: 'id',		tag: 'div', classes: ['object-id'], text: this.id },
			{ name: 'action',	tag: 'div', classes: ['object-action'], text: this.action },
			{ name: 'data',		tag: 'pre', classes: ['object-data'], text: JSON.stringify(this.data, null, 2) }
		]);*/
	}

	//--------------------------------
	// Set Object ID
	//--------------------------------
	// RETURNS: [bool] success
	// * str	- [string] new ID
	setId( str ) {
		if ( typeof str!=='string' || str.trim()==='' ) return false;
		this.id = str;
		this.emit( 'update-id', null, str );
		if ( this.panel?.refs?.id ) this.panel.refs.id.el.innerText = str;
		return true;
	}

	//--------------------------------
	// Set Data Object
	//--------------------------------
	// RETURNS: [bool] success
	// * obj	- [object] new data
	setData( obj ) {
		// Ensure data is [object] & update property.
		if ( typeof obj!=='object' || Array.isArray(obj) || obj===null )
			return false; // abort
		this.data = obj;
		// Emit event.
		this.emit( 'update-data', null, obj );
		// Optional: update action if embedded
		if ( obj.action ) this.setAction( obj.action );
		// Update inner text.
		if ( this.panel?.refs?.data )
			this.panel.refs.data.el.innerText = JSON.stringify( obj, null, 2 );
		return true; // success
	}

	//--------------------------------
	// Update a Single Data Property
	//--------------------------------
	// Safely updates one key in the data object.
	// RETURNS: [bool] success
	// * key	- [string] key to update
	// * value	- [any] new value
	updateData( key, value ) {
		// Validate argument(s).
		if ( typeof key!=='string' || key==='' )
			return false; // abort
		// Ensure data is [object] & update property.
		if ( typeof this.data!=='object' || this.data===null ) this.data = {};
		this.data[key] = value;
		// Emit event.
		this.emit( 'update-data-key', null, key, value );
		// Check if action is being set.
		if ( key==='action' ) this.setAction( value ); // keep action in sync
		// Update inner text.
		if ( this.panel?.refs?.data )
			this.panel.refs.data.el.innerText = JSON.stringify( this.data, null, 2 );
		return true; // success
	}

	//--------------------------------
	// Set Object Action
	//--------------------------------
	// RETURNS: [bool] success
	// * str	- [string] action value
	setAction( str ) {
		if ( typeof str!=='string' ) return false;
		this.action = str;
		this.emit( 'update-action', null, str );
		if ( this.panel?.refs?.action ) this.panel.refs.action.el.innerText = str;
		return true;
	}

	//--------------------------------
	// Get Summary Line
	//--------------------------------
	// RETURNS: [string] readable string
	summary() {
		return `${this.id} (${this.action || 'unknown'})`;
	}

	//--------------------------------
	// Export Object
	//--------------------------------
	// RETURNS: [object] structure
	toObject() {
		return {
			id:		this.id,
			action:	this.action,
			data:	this.data
		};
	}
}

/* --- BEGIN js/apps/jest/components/ui/JestCurator.js --- */

//-----------------------------
// JestCurator Class
//-----------------------------
// Panel for selecting and displaying objects by key.
class JestCurator extends JestElement {
	// Object properties
	toolbar			= null;			// [object] JestToolbar for buttons
	selectBox		= null;			// [object] JestInputSelect
	detail			= null;			// [HTMLElement] detail viewer
	objects			= {};			// [object] map of id -> JestCuratorObject
	types			= [];			// [array] registered types (strings)
	typeBox			= null;			// [object] JestInputSelect for type filtering
	typeSelected	= 'tiles';		// [string] default selected type
	filterCallbacks	= {};			// [object] map of type -> callback
	// Cached Visible Options
	cachedOptions	= {};			// map of type -> [array] of ids
	// Private counter variable(s)
	_idCounter		= 0;			// [int] value of id

	//--------------------------------
	// Constructor
	//--------------------------------
	// RETURNS: [void]
	// * client - [object] parent reference
	constructor( client ) {
		super( client );
	}

	//--------------------------------
	// Build Component
	//--------------------------------
	// RETURNS: [void]
	// * name		- [string] system name
	// * classes	- [array] additional class names
	build( name='object-selector', classes=[] ) {
		//--------------------------------
		// Setup Selector Panel
		//--------------------------------
		// Construct the parent panel.
		if ( classes===null ) classes = [];
		super.build( 'div', name, ['object-selector'].mergeUnique(classes) );
		// Add panel elements.
		this.panel.addElements([
			{ name: 'selectwrap', tag: 'div', classes: [ 'selector-wrap' ] },
			{ name: 'detail',     tag: 'div', classes: [ 'selector-detail' ] },
			{ name: 'buttons',    tag: 'div', classes: [ 'selector-buttons' ] }
			]);
		// Assign detail element
		this.detail		= this.panel.refs.detail;
		//-------------------------
		// Create Type Select Box
		//-------------------------
		this.typeBox = new JestInputSelect( this.client );
		this.typeBox.build( 'type-dropdown' );
		this.typeBox.register( 'change', 'update-type', ()=>this.typify() );
		this.panel.refs.selectwrap.addPanel( 'types', this.typeBox.panel );
		// Default selected type
		this.typeBox.setOptions(
			this.types.map(
				( t ) =>
					({
						label    : t.charAt(0).toUpperCase()+t.slice(1), // optional prettier label
						value    : t
					})
				));
		//--------------------------------
		// Create Input Select-Box
		//--------------------------------
		// Create select box and hook events
		this.selectBox	= new JestInputSelect( this.client );
		this.selectBox.build( 'object-dropdown' );
		this.selectBox.register( 'change', 'update-detail', ()=>this.display() );
		this.panel.refs.selectwrap.addPanel( 'items', this.selectBox.panel );
		// Select a default item.
		this.typeBox.setValue( this.typeSelected );
		// --------------------------------
		// Create Toolbar [object]
		// --------------------------------
		// Create the toolbar.
		const toolbar	= new JestToolbar( this );
		this.toolbar	= toolbar; // set toolbar
		toolbar.build();
		// Add toolbar to client interface.
		this.panel.refs.buttons.addPanel( 'toolbar', toolbar.panel );
		//-------------------------
		// Update Curator Loop
		//-------------------------
		// Register "update" loop callback event.
		this.client.register(
			'update', `curator_${this.skey}`,
			( e, state, enabled, mode ) => this.update()
			);
	}

	//--------------------------------
	// Update & Rendering Method(s)
	//--------------------------------
	// Update the curator on the application display loop.
	update() {
		// Disable all menu buttons.
		this.toolbar.toggleAll( false );
		// Get current selected option [object].
		const object	= this.getSelectedObject();
		// Emit 'update' event for display.
		this.emit( 'update', null, this.typeSelected, object ); // emit event
	}

	//--------------------------------
	// Register One or More Types
	//--------------------------------
	// Accepts a single type or array of types.
	// * input - [string|array] type(s) to register
	registerType( input ) {
		// Normalize input into array
		const list = Array.isArray(input) ? input : [ input ];
		// Iterate types.
		for ( const type of list ) {
			if ( typeof type==='string' && !this.types.includes(type) )
				this.types.push( type );
		}
		// Refresh dropdown
		this._refreshTypeBox();
		// Auto-select last added type
		if ( list.length>0 ) {
			this.typeSelected = list[list.length - 1];
			this.typeBox.setValue( this.typeSelected );
			this.refreshOptions();
		}
	}

	//--------------------------------
	// Unregister One or More Types
	//--------------------------------
	// Removes provided types and reselects remaining type if needed.
	// * input - [string|array] type(s) to unregister
	unregisterType( input ) {
		const list	= Array.isArray(input) ? input : [ input ];
		let changed	= false;
		// Iterate types.
		for ( const type of list ) {
			const index = this.types.indexOf( type );
			if ( index!==-1 ) {
				this.types.splice( index, 1 );
				changed = true;
			}
		}
		// Check if any types removed.
		if ( changed ) {
			// Refresh dropdown
			this._refreshTypeBox();
			// Fallback type selection
			if ( !this.types.includes(this.typeSelected) ) {
				this.typeSelected = this.types.length>0 ? this.types[0] : null;
				this.typeBox.setValue( this.typeSelected ?? '' );
				this.refreshOptions(); // will auto-hide all if none
			}
		}
	}

	//--------------------------------
	// Clear All Types
	//--------------------------------
	// Empties all type entries and hides all items.
	clearTypes() {
		// Empty types list.
		this.types = [];
		this.typeSelected = null;
		if ( this.typeBox ) {
			this.typeBox.clearOptions();
			this.typeBox.setValue( '' );
		}
		// Refresh dropdown
		this._refreshTypeBox();
		this.refreshOptions(); // will auto-hide all
	}

	//--------------------------------
	// Refresh Type Dropdown List
	//--------------------------------
	// INTERNAL: Call after adding/removing types.
	_refreshTypeBox() {
		// Check if typebox exists.
		if ( !this.typeBox ) return;
		// Iterate options and assign label + value.
		const options =
			this.types.map(
				type => ({
					label: type.charAt(0).toUpperCase() + type.slice(1),
					value: type
				}) );
		// Set all existing "type" option(s).
		this.typeBox.setOptions( options );
	}

	//--------------------------------
	// Refresh Object Options by Type
	//--------------------------------
	// Called when type dropdown changes
	refreshOptions() {
		//-------------------------
		// Reset visibility before filtering
		//-------------------------
		Object.values( this.objects )
			.forEach(
				obj => obj.jot?.( 'visible', true )
			);
		//-------------------------
		// Begin Filtering
		//-------------------------
		// Get active selected type.
		const type			= this.typeSelected;
		const options		= this.selectBox.options;
		// Track visible candidates
		let firstVisible	= null;
		// Hide/show options based on type
		for ( const option of options ) {
			const id		= option.value;
			const object	= this.objects[id];
			const match		= this.isVisibleObject( object );
			if ( option.panel?.el ) {
				option.panel.el.hidden = !match;
				if ( match && !firstVisible )
					firstVisible = option;
			}
		}
		// Check if currently selected option is hidden
		const selectedId	= this.selectBox.getValue();
		const selectedOpt	= options.find( o => o.value === selectedId );
		const visible		= selectedOpt && !selectedOpt.panel?.el.hidden;
		// If the current selection is no longer visible, switch to first visible
		if ( !visible ) {
			if ( firstVisible ) {
				this.selectBox.setValue( firstVisible.value );
				this.display(); // force display sync
			}
			else {
				this.selectBox.setValue( '' ); // no match, clear selection
				this.display(); // clear display
			}
		}
	}

	//--------------------------------
	// Resort Options by Custom Comparator
	//--------------------------------
	// Sorts the dropdown options and updates the UI accordingly.
	// RETURNS: [void]
	// * comparator - [function] Comparator function (a,b)=>int (like array.sort)
	resortOptions( comparator ) {
		// Defensive: bail if no comparator or selectBox
		if ( typeof comparator!=='function' || !this.selectBox ) return;

		//--------------------------------
		// Get All Option Entries
		//--------------------------------
		// Grab the current options from the selectBox
		const options = this.selectBox.options;
		if ( !options || options.length===0 ) return;

		//--------------------------------
		// Apply Sort to Options
		//--------------------------------
		// Sort using the comparator passed in
		options.sort(
			( a, b ) => {
				const objA	= this.objects[ a.value ];
				const objB	= this.objects[ b.value ];
				return comparator( objA, objB );
			});

		//--------------------------------
		// Rebuild DOM <option> Order
		//--------------------------------
		// Clear all <option> tags from the <select>
		const selectEl		= this.selectBox.field.el;
		const selectedId	= this.selectBox.getValue();
		selectEl.innerHTML	= ''; // clear all

		// Re-add in new order
		for ( const opt of options ) {
			selectEl.appendChild( opt.panel.el );
		}

		//--------------------------------
		// Restore Option Order Reference
		//--------------------------------
		// Replace the options array in place
		this.selectBox.options = options;

		//--------------------------------
		// Restore Selection
		//--------------------------------
		// Re-set selected value (to avoid accidental deselection)
		if ( selectedId )
			this.selectBox.setValue( selectedId );

		//--------------------------------
		// Re-filter visibility after sort
		//--------------------------------
		this.refreshOptions();
	}

	//--------------------------------
	// Determine if Object is Visible
	//--------------------------------
	// Centralized visibility logic using type + plugin filters.
	// RETURNS: [bool]
	// * object - [JestCuratorObject]
	// * type	– [string|null] filter by type (defaults to current typeSelected)
	isVisibleObject( object, type=null ) {
		const t	= type ?? this.typeSelected;
		// Ensure valid object and type match
		if ( !object?.data || object.data.type!==t )
			return false;
		// Emit 'filter' for external plugin filtering
		this.emit( 'filter', null, t, object.data, object );
		// Read state from mode flag
		const mode 	= object.skim?.( 'visible' );
		if ( mode===false ) return false;
		// Passed all checks
		return true;
	}

	//--------------------------------
	// Get All Visible Options (by type)
	//--------------------------------
	// Get an [array] list of all visible option [ids].
	// RETURNS: [array] of option ids
	// * type	– [string|null] filter by type (defaults to current typeSelected)
	getVisibleOptions( type=null ) {
		const t	= type ?? this.typeSelected;
		// Check cache
		if ( this.cachedOptions[t] )
			return this.cachedOptions[t];
		// Generate list from scratch
		const options	= this.selectBox.options;
		const visible	=
			options.map(
				opt => {
					const obj = this.objects[ opt.value ];
					return this.isVisibleObject(obj,t) ? opt.value : null;
				})
				.filter( id => id!==null );
		// Cache it
		this.cachedOptions[t] = visible;
		return visible;
	}

	//--------------------------------
	// Get Curated Object By ID
	//--------------------------------
	// Get a curator item object using the object id.
	// RETURNS: [JestCuratorObject|null]
	// * id - [string] object ID
	getObject( id ) {
		// Determine if object exists & return it if it does.
		return this.objects?.[id] ?? null;
	}

	// Get a curator item object from the curator list of required type.
	// RETURNS: [JestCuratorObject|null].
	// * type		– [string|null] item type to remove (defaults to current selection)
	// * idParam	– [string|null] id to remove (defaults to current selection)
	getObjectByType( type=null, idParam=null ) {
		//--------------------------------
		// Validate Object(s)
		//--------------------------------
		// Get selected ID and corresponding object.
		const object	= this.getObject( idParam );
		// Validate curator object data type.
		if ( !object ) {
			console.warn( `Could not find curator object of specified id "${idParam}".` );
			return null; // user aborted
		}

		// Validate curator object data type.
		if ( object?.data?.type!==type ) {
			console.warn( `Cannot retrieve object. Object not of type "${type}".` );
			return null; // user aborted
		}

		//--------------------------------
		// Return Result
		//--------------------------------
		// Return the found object.
		return object; // [JestCuratorObject|null]
	}

	// Locate all visible objects in the curator matching:
	// (1) .data.type === type
	// (2) all key/value pairs in `props` match .data
	// RETURNS: [array<object>] list of matched objects (can be empty).
	// * type		- [string] Type to match in .data.type
	// * props		- [object] Key/value pairs to match inside .data
	// * visible	- [bool] restrict search to visible options
	getByTypeAndProps( type, props={}, visible=false ) {
		//--------------------------------
		// Prepare Match Collection
		//--------------------------------
		const matches = [];
		// Get items based upon criteria.
		const ids =
			visible
			? this.getVisibleOptions(type)
			: Object.keys( this.objects ).filter(
				id => this.objects[id]?.data?.type === type
				);

		//--------------------------------
		// Iterate Over All Curated Objects
		//--------------------------------
		for ( const id of ids ) {
			const obj = this.objects[id];
			if ( !obj?.data ) continue;

			//--------------------------------
			// Check All Specified Key/Value Pairs
			//--------------------------------
			let match = true;
			for ( const [key,val] of Object.entries(props) ) {
				if ( obj.data[key]!==val ) {
					match = false;
					break; // escape
				}
			}

			// Add Match
			if ( match ) matches.push( obj );
		}

		//--------------------------------
		// Return All Matches (may be empty)
		//--------------------------------
		return matches;
	}

	//--------------------------------
	// Get Visible Curator Objects
	//--------------------------------
	// Get an [array] list of all option [objects].
	// RETURNS: [array] of visible JestCuratorObjects
	// * type	– [string|null] filter by type (defaults to current typeSelected)
	getVisibleObjects( type=null ) {
		const t = type ?? this.typeSelected;
		// Check if cache exists
		if ( !this.cachedOptions?.[t] )
			this.getVisibleOptions( t ); // triggers population
		// Map cached ids to objects (skip missing ones for safety)
		return ( this.cachedOptions[t] ?? [] )
			.map( id => this.objects[id] )
			.filter( obj => !!obj );
	}

	//--------------------------------
	// Get Current Selected Type
	//--------------------------------
	// RETURNS: [string|null] current type
	getSelectedType() {
		return this.typeSelected ?? null;
	}

	//--------------------------------
	// Get Currently Selected Object
	//--------------------------------
	// Returns the currently selected object (if any).
	// RETURNS: [JestCuratorObject|null]
	getSelectedObject() {
		const id = this.selectBox.getValue();		// current selected ID
		if ( !id ) return null;						// no selection made
		return this.objects[id] ?? null;			// return matching object or null
	}

	//--------------------------------
	// Flush Visible Options Cache
	//--------------------------------
	// * type – [string|null] flush specific type or all
	flushVisibleCache( type=null ) {
		if ( type ) {
			// Flush one type safely
			if ( this.cachedOptions?.[type] )
				delete this.cachedOptions[type];
		}
		else this.cachedOptions = {}; // flush all
	}

	//--------------------------------
	// Add Object to Selector
	//--------------------------------
	// Adds a new predefined object to the curator.
	// RETURNS: [JestCuratorObject] or [null].
	// * type		- [string] value of item type
	// * data		- [object] any payload
	//   autoselect	- [bool] whether to autoselect the added item (default: true)
	addObject( type, data, autoselect=true ) {
		//--------------------------------
		// Normalize Object Metadata
		//--------------------------------
		// Define initial data propert(ies).
		const id	= data.id ?? this.generateId( data.action ?? 'obj' );
		data.id		= id;					// ensure ids match
		data.type	= type ?? 'unknown';	// assign fallback type if missing

		//--------------------------------
		// Handle Duplicate ID
		//--------------------------------
		// If an object with this ID already exists, remove it before re-adding
		if ( this.objects[id] ) {
			console.error( `[JestCurator] Duplicate ID "${id}" detected. Removing old object before re-adding.` );
			this.removeObject( id );
		}

		//--------------------------------
		// Debug Specific Case (Backend)
		//--------------------------------
		//if ( data.name==='Sign' )
			//console.warn( 'Adding SIGN:', data );

		//--------------------------------
		// Wrap in Curator Object
		//--------------------------------
		const object	= new JestCuratorObject( this.client, id, data );
		this.objects[id] = object;			// keep [object] ref
		// Flush the cache.
		this.flushVisibleCache();
		// Set initial visibility
		object.jot( 'visible', true );

		//--------------------------------
		// Create Display Element
		//--------------------------------
		// Create the display for the select option.
		const display	= new JestDisplay( this.client );
		display.build( `display_${id}` );	// note the “hidden” class
		object.display	= display;			// stash it on the object
		object.display.disable();			// disable display by default
		// Add display to detail panel
		this.detail.addPanel( id, display.panel );

		//--------------------------------
		// Add to Select Dropdown
		//--------------------------------
		// Add new option to select box.
		let option;
		// Create new [JestInputSelectOption] if not supplied.
		if ( !data?._option || !(data._option instanceof JestInputSelectOption) ) {
			option			= this.selectBox.addOption( id, data.name ?? id );
			data._option	= option; // keep [JestInputSelectOption] option in data
		}
		// Use existing option instance.
		else {
			option	= data._option; // existing option
			this.selectBox.adoptOption( option, option.getIndex() );
		}

		// Hide if type doesn't match current selection.
		if ( option?.panel?.el )
			option.panel.el.hidden = !this.isVisibleObject( object );

		//--------------------------------
		// Emit Add Event
		//--------------------------------
		// Emit "added" event.
		this.emit( 'add', null, object );

		//--------------------------------
		// Auto-Select Item
		//--------------------------------
		// Auto select option.
		if ( autoselect===true )
			this.select( option.value );
		// Return the newly created curator object.
		return object; // [JestCuratorObject] instance
	}

	//--------------------------------
	// Remove An Object Safely
	//--------------------------------
	// Removes a curator item object from the curator list of required type.
	// RETURNS: [JestCuratorObject|null].
	// * type		– [string|null] item type to remove (defaults to current selection)
	// * idParam	– [string|null] id to remove (defaults to current selection)
	removeObjectByType( type=null, idParam=null ) {
		//--------------------------------
		// Validate Object(s)
		//--------------------------------
		// Get selected ID and corresponding object.
		const object	= this.getObject( idParam );
		// Validate curator object data type.
		if ( !object ) {
			console.error( `Could not find curator object of specified id "${idParam}".` );
			return null; // user aborted
		}

		// Validate curator object data type.
		if ( object?.data?.type!==type ) {
			console.error( `Cannot remove object. Object not of type "${type}".` );
			return null; // user aborted
		}

		//--------------------------------
		// Remove Object & Return
		//--------------------------------
		// Remove & return result.
		return this.removeObject( idParam ); // [JestCuratorObject|null]
	}

	// Removes a curator item object from the curator list.
	// RETURNS: [JestCuratorObject|null].
	// * idParam – [string|null] id to remove (defaults to current selection)
	removeObject( idParam=null ) {
		//--------------------------------
		// Check If Item Exists
		//--------------------------------
		// Determine the real target ID.
		let targetId;
		// Fallback to current selected visible item (if no id supplied).
		if ( idParam===null ) {
			// Check if any visible options exist at all
			const visible	= this.getVisibleOptions();
			if ( visible.length===0 ) {
				console.error( `[JestCurator] removeObject(): no visible items to remove` );
				return null; // abort
			}
			// Use selected item id.
			targetId = this.selectBox.getValue();
		}
		// Use supplied item id.
		else targetId = idParam;

		// Check target existence.
		if ( !this.objects[targetId] ) {
			console.error( `[JestCurator] removeObject(): object "${targetId}" not found` );
			return null; // abort
		}

		//--------------------------------
		// Clear Cache(s)
		//--------------------------------
		// Flush the cache.
		this.flushVisibleCache( this.typeSelected );

		//--------------------------------
		// Remove Display Element
		//--------------------------------
		// Remove display from detail panel.
		const object	= this.objects[targetId];
		this.detail.removePanel( targetId, object.display.panel );

		//--------------------------------
		// Remove From Select Dropdown
		//--------------------------------
		// Delete the item.
		delete this.objects[targetId];
		// Remove from select box
		this.selectBox.options = this.selectBox.options.filter( (o)=>o.value!==targetId );
		this.selectBox.field.el.querySelectorAll( 'option' )
			.forEach(
				opt => {
					if ( opt.value===targetId )
						opt.remove();
				});

		//--------------------------------
		// Emit Add Event
		//--------------------------------
		// Emit "remove" event.
		this.emit( 'remove', null, object );

		//--------------------------------
		// Auto-Select Item
		//--------------------------------
		// Auto-select next visible neighbor
		if ( this.getVisibleOptions().length>0 )
			this.select(); // auto-select
		else {
			this.selectBox.setValue( '' ); // select nothing
			this.display(); // refresh display
		}
		return object; // success
	}

	//--------------------------------
	// Select Method(s)
	//--------------------------------
	// Select an option with flexible args.
	// * id    – [string|null]   option value to start from (if null, first visible)
	// * delta – [number]        offset from base index (e.g. 1, -1, 2, etc.)
	select( id=null, delta=0 ) {
		//--------------------------------
		// Get Visible Option(s)
		//--------------------------------
		// Gather visible options.
		const visible = this.selectBox.options.filter(
			opt => {
				const obj = this.objects[opt.value];
				return !opt.panel?.el.hidden && this.isVisibleObject(obj);
			});
		// Extract option ids.
		const ids	= visible.map( opt => opt.value );
		const total	= ids.length; // count visible otions

		//--------------------------------
		// No Options: Clear Selection
		//--------------------------------
		// No options available → clear selection
		if ( total===0 ) {
			this.selectBox.setValue( '' );
			this.display(); // update display
			// Return empty stats.
			return {
				previousIndex : null,
				newIndex      : null,
				selectedItem  : null,
				clampedCount  : 0,
				totalOptions  : 0
				};
		}

		//--------------------------------
		// Calculate Relative "Previous-most Index"
		//--------------------------------
		// Determine base index from id.
		// NOTE: Resets to first item if requested id not found.
		let prevIndex	= null;
		if ( id!==null ) {
			const index	= ids.indexOf( id );
			if ( index===-1 ) {
				//console.warn( `[JestCurator] select(): ID "${id}" not found in visible list.` );
				return {
					previousIndex : null,
					newIndex      : null,
					selectedItem  : null,
					clampedCount  : 0,
					totalOptions  : ids.length
					};
			}
			prevIndex	= index;
		}
		else prevIndex	= 0;

		//--------------------------------
		// Clamp & Calculate Selection Indices
		//--------------------------------
		// Apply delta and clamp to bounds
		let desired			= prevIndex + delta;
		let clampedCount	= 0;
		if ( desired<0 ) {
			clampedCount	= -desired;
			desired			= 0;
		}
		else if ( desired>=total ) {
			clampedCount	= desired - (total-1);
			desired			= total - 1;
		}

		//--------------------------------
		// Select New Option & Refresh Display
		//--------------------------------
		// Perform the selection, & update display.
		const newId	= ids[ desired ];
		this.selectBox.setValue( newId );
		this.display(); // update display

		//--------------------------------
		// Build & Return Stats
		//--------------------------------
		// Return diagnostics statistical data.
		const scope	= {
			previousIndex : id!==null ? prevIndex : null,
			newIndex      : desired,
			selectedItem  : this.objects[newId],
			clampedCount  : clampedCount,
			totalOptions  : total
			};
		return scope;
	}

	//--------------------------------
	// Set Selected Type Explicitly
	//--------------------------------
	// Sets the selected type in the type dropdown.
	// Refreshes visibility and internal state.
	// RETURNS: [void]
	// * type - [string] type key to set
	setType( type ) {
		//--------------------------------
		// Validate & Apply Type
		//--------------------------------
		if ( !type || !this.types.includes(type) ) {
			console.warn( `[JestCurator] setType(): Invalid type "${type}"` );
			return;
		}

		//--------------------------------
		// Set Type & Trigger Refresh
		//--------------------------------
		this.typeSelected = type;			// update internal type
		this.typeBox.setValue( type );		// update dropdown
		this.typify();						// refresh visible objects
	}

	//--------------------------------
	// Select First Visible Entry
	//--------------------------------
	// Selects the first visible item in the type dropdown.
	// RETURNS: [void].
	selectTopType() {
		// Select the top item in the type dropdown.
		if ( this.types.length>0 ) {
			const firstType		= this.types[0];
			this.typeSelected	= firstType;
			this.typeBox.setValue( firstType );
			this.refreshOptions(); // triggers re-filtering
		}
	}

	// Selects the first visible item in the item dropdown.
	// RETURNS: [void].
	selectTopObject() {
		// Select the top item in the object dropdown.
		const visible = this.getVisibleOptions();
		if ( visible.length>0 ) {
			this.selectBox.setValue( visible[0] );
			this.display(); // force update
		}
	}

	// Get the current index of a select option.
	getOptionIndex( id ) {
		const options = this.selectBox.options;
		for ( let i=0; i<options.length; i++ ) {
			if ( options[i].value === id )
				return i;
		}
		return -1; // not found
	}

	//--------------------------------
	// Update Label of an Existing Option
	//--------------------------------
	// Updates the visible label in the select box when data changes.
	// RETURNS: [void]
	// * id    - [string] id of the object whose label changed
	// * label - [string] new label to display
	updateOptionLabel( id, label ) {
		// Update the actual DOM <option> tag if it exists
		this.selectBox.setOptionLabel( id, label );
	}

	//--------------------------------
	// Update Option Label and Value
	//--------------------------------
	// Updates both the label and/or value of a visible curated object.
	// Maintains selection state and updates all internal references.
	// RETURNS: [bool] success
	// * oldId		– [string] current ID of the object/option
	// * newId		– [string|null] new ID to assign (optional; leave null to keep existing)
	// * newLabel	– [string|null] new display label (optional; leave null to keep existing)
	updateOption( oldId, newId=null, newLabel=null ) {
		//--------------------------------
		// Validate Input Existence
		//--------------------------------
		const object = this.objects?.[oldId];
		if ( !object ) {
			console.warn( `[JestCurator] updateOption(): No object found for ID "${oldId}"` );
			return false; // abort
		}
		const select = this.selectBox;

		//--------------------------------
		// Locate Option Entry
		//--------------------------------
		const opt = select.options.find( o => o.value === oldId );
		if ( !opt ) {
			console.warn( `[JestCurator] updateOption(): No option found for ID "${oldId}"` );
			return false; // abort
		}

		//--------------------------------
		// Track Current Selection
		//--------------------------------
		const isSelected = ( select.getValue() === oldId );

		//--------------------------------
		// Update Label (if provided)
		//--------------------------------
		if ( newLabel !== null ) {
			opt.setLabel( newLabel );	// update label in object
			if ( opt.panel?.el )
				opt.panel.el.textContent = newLabel; // update DOM node
		}

		//--------------------------------
		// Update Value (if changed)
		//--------------------------------
		if ( newId && newId!==oldId ) {
			// Reassign in Objects Map
			this.objects[ newId ] = object;
			delete this.objects[ oldId ];
			object.data.id = newId;

			// Update Option Value
			opt.value = newId;
			if ( opt.panel?.el )
				opt.panel.el.value = newId;

			// Update DOM Selection If Active
			if ( isSelected )
				select.selectOption( newId );
		}

		// Done
		return true;
	}

	//--------------------------------
	// Hide All Display Panels
	//--------------------------------
	// Hides all children of the detail panel container.
	// RETURNS: [void]
	hideAllDisplays() {
		// Safety check: detail panel must exist
		if ( !this.detail?.panel?.el ) return;
		// Hide every child node
		Array.from( this.detail.panel.el.children )
			.forEach(
				child => child.hidden = true
				);
	}

	//--------------------------------
	// Display Selected Object
	//--------------------------------
	// Select the current select box item (display it).
	// RETURNS: [void]
	display() {
		// Get selected ID and corresponding object
		const object	= this.getSelectedObject();
		// Hide all displays.
		this.hideAllDisplays(); // use helper method
		// Hide all displays
		for ( const key in this.objects )
			if ( this.objects[key]?.display )
				this.objects[key].display.disable();
		// If the selected object is invalid, exit early
		if ( !object ) {
			this.emit( 'display', null, null ); // emit null selection
			return; // abort
		}
		// Show the selected object’s display
		if ( object.display )
			object.display.enable();
		// Emit selection event
		this.emit( 'display', null, object );	// object to display
		this.emit( 'displayed', null, object ); // event when display finished
	}

	// Change the type of selected box items (e.g. 'links').
	// RETURNS: [void]
	typify() {
		// Get selected "type" value from select box.
		const val	= this.typeBox.getValue();
		if ( !val ) return; // no value found
		// Change selected type to value.
		this.typeSelected = val;
		// Flush the cache.
		this.flushVisibleCache( this.typeSelected );
		this.refreshOptions(); // refresh options list
	}

	//--------------------------------
	// Generate Unique ID
	//--------------------------------
	// Generate an [object] id.
	// RETURNS: [string]
	// * base - [string] base name (optional)
	generateId( base='obj' ) {
		//--------------------------------
		// Use Master Counter to Prevent Reuse
		//--------------------------------
		let id = `${base}_${this._idCounter++}`;

		//--------------------------------
		// Ensure Uniqueness Just In Case
		//--------------------------------
		// Rare edge case fallback if object already exists
		while ( this.objects[id] ) {
			id = `${base}_${this._idCounter++}`;
		}

		// Return unique id
		return id;
	}

	//--------------------------------
	// Export All Predefined Objects
	//--------------------------------
	// Download all objects as a structured JSON file.
	// RETURNS: [void]
	exportObjects() {
		// Extract all object data [array].
		const data	= Object.values(this.objects).map( o=>o.data );
		// Convert to downloadable blob.
		console.log( data );
		const blob	=
			new Blob(
				[ JSON.stringify( data, null, 2 ) ],
				{ type: 'application/json' }
				);
		const url	= URL.createObjectURL( blob );
		// Create & trigger download link.
		const a		= document.createElement( 'a' );
		a.href		= url;
		a.download	= 'predefined-objects.json';
		a.click();
		// Clean up URL object
		URL.revokeObjectURL( url );
	}

	//--------------------------------
	// Open Import File Dialog
	//--------------------------------
	// Opens file picker for .json file containing exported objects.
	// RETURNS: [void]
	openImportDialog() {
		// Create <input type=file>
		const input		= document.createElement( 'input' );
		input.type		= 'file';
		input.accept	= 'application/json';
		// File load callback
		input.onchange	=
			( e ) => {
				const file		= e.target.files?.[0];
				if ( !file ) return;
				const reader	= new FileReader();
				reader.onload	= ( evt ) => this.importObjects( evt.target.result );
				reader.readAsText( file );
			};
		// Trigger dialog
		input.click();
	}

	//--------------------------------
	// Import Object Catalog from JSON
	//--------------------------------
	// Accepts stringified JSON array or raw array and loads each [object] as a predefined.
	// RETURNS: [void]
	// * jsonData	- [string|array] input to parse and import
	importObjects( jsonData ) {
		let arr;
		//-------------------------
		// Parse if string
		//-------------------------
		if ( typeof jsonData==='string' ) {
			try {
				arr = JSON.parse( jsonData );
			}
			catch ( err ) {
				console.error( 'JestCurator: Invalid JSON during import.', err );
				return;
			}
		}
		else if ( Array.isArray(jsonData) ) {
			arr = jsonData;
		}
		else {
			console.error(
				'JestCurator: importObjects() expected string or array but got:',
				typeof jsonData
				);
			return;
		}

		//-------------------------
		// Validate parsed array
		//-------------------------
		if ( !Array.isArray(arr) ) {
			console.warn( 'JestCurator: Imported content is not an array.' );
			return;
		}

		//-------------------------
		// Import entries
		//-------------------------
		arr.forEach(
			( data ) => {
				// A type is required.
				if ( !data?.type ) {
					console.warn( 'JestCurator: Imported item did not define type, skipping.' );
					return;
				}
				else this.addObject( data.type, data );
			});
		// Force dropdown refresh after batch
		this.typeBox.setValue( this.typeSelected );
		this.typify();

		//--------------------------------
		// Auto-Select First Visible Matching Option
		//--------------------------------
		// If there is a first visible matching option, auto-select it
		this.select();

		//--------------------------------
		// Update Counter to Avoid Reuse
		//--------------------------------
		// Find highest numeric suffix across all object IDs
		const maxId = Object.keys( this.objects )
			.map( id => parseInt( id.split('_')[1], 10 ) )
			.filter( n => !isNaN(n) )
			.reduce( (a,b) => Math.max(a,b), 0 );

		// Ensure counter is always ahead of highest existing ID
		if ( maxId >= this._idCounter )
			this._idCounter = maxId + 1;
	}
}

/* --- BEGIN js/apps/jest/components/ui/JestModal.js --- */

//-----------------------------
// JestModal Class
//-----------------------------
// Lightweight modal dialog with header, text, input, and buttons.
// Extends: JestElement
class JestModal extends JestElement {
	// Object properties
	titleText		= '';				// [string] title of modal
	bodyText		= '';				// [string] body content
	inputs			= {};				// [object] map of name -> JestInputText
	box				= null;				// DOM [object] of the inner box
	payload			= null;				// [any] contextual data passed to modal when opened.
	// Button storage & sequencing
	buttons			= {};				// [object<string,JestButton>] keyed by our own keys (e.g., 'ok','cancel')
	buttonSeq		= 0;				// [int] monotonically increasing counter to build unique button ids

	//--------------------------------
	// Constructor
	//--------------------------------
	// Construct the [object].
	// * client		- [object] parent controller
	constructor( client ) {
		super( client ); // call parent constructor
	}

	// Destroy the dialog.
	// RETURNS: [void]
	destroy() {
		this.panel.el.remove(); // remove from DOM
	}

	//--------------------------------
	// Build Component
	//--------------------------------
	// Build modal layout.
	// * name		- [string] unique identifier
	// * classes	- [array] extra CSS class names
	build( name='modal', classes=[] ) {
		// Construct the parent panel.
		if ( classes===null ) classes = [];
		super.build( 'div', name, ['jest-modal'].mergeUnique(classes) );
		this.panel.addElements([
			{
				name:		'overlay',
				tag:		'div',
				classes:	[ 'modal-overlay' ]
			},
			{
				name:		'box',
				tag:		'div',
				classes:	[ 'modal-box' ],
				elements:	[
					{ name: 'title',	tag: 'div', classes: [ 'modal-title' ] },
					{ name: 'text',		tag: 'div', classes: [ 'modal-text' ] },
					{ name: 'inputwrap',tag: 'div', classes: [ 'modal-input' ] },
					{ name: 'buttons',	tag: 'div', classes: [ 'modal-buttons' ] }
					]
			}
		]);
		// Keep inner box reference.
		this.box	= this.panel.refs.box;
		// Close on overlay click
		this.panel.refs.overlay.register( 'click', 'close', ()=>this.close(), 'dom' );
	}

	//--------------------------------
	// Set Modal Title
	//--------------------------------
	// RETURNS: [void]
	// * value	- [string] title text
	setTitle( value ) {
		// Set prompt title.
		this.titleText	= value;
		this.box.refs.title.el.innerText = value;
	}

	//--------------------------------
	// Set Modal Message Text
	//--------------------------------
	// RETURNS: [void]
	// * value	- [string] body content
	setText( value ) {
		// Prompt message.
		this.bodyText	= value;
		this.box.refs.text.setHTML( value );
	}

	//--------------------------------
	// Add Input Field to Modal
	//--------------------------------
	// Adds a named text input to the modal panel.
	// RETURNS: [JestInputText]
	// * name			- [string] unique input name (required)
	// * id				- [string] optional HTML id
	// * defaultValue	- [string] pre-filled text
	// * placeholder	- [string] field hint
	// * labelText		- [string] label element
	//   type			- [string] value of input type ("text", "password")
	addTextfield(
		name, id=null, defaultValue=null, placeholder=null, labelText=null, type="text" ) {
		// Validate input name
		if ( !name ) {
			console.warn( 'JestModal.addTextfield: Input must have a valid name.' );
			return null; // abort
		}
		// Check for duplicate
		if ( this.inputs[name] ) {
			console.warn( `Input "${name}" already exists.` );
			return this.inputs[name];
		}
		// Create input [object]
		const input	= new JestInputText( this.client, name, id, defaultValue, placeholder, labelText );
		input.setType( type );
		input.build( `input-${name}` );
		// Show the text field label.
		if ( labelText!==null ) input.showLabel();
		// Append to panel
		this.box.refs.inputwrap.addPanel( name, input.panel );
		// Store reference
		this.inputs[name] = input;
		// Return input
		return input;
	}

	//--------------------------------
	// Add Checkbox Input Field
	//--------------------------------
	// Adds a boolean [checkbox] input to the modal.
	// RETURNS: [JestInputCheckbox]
	// * name			- [string] unique key name
	// * id				- [string|null] optional HTML id
	// * defaultValue	- [bool] initial checked state
	// * labelText		- [string|null] visible label
	addCheckbox( name, id=null, defaultValue=false, labelText=null ) {
		// Check for existing field
		if ( this.inputs[name] ) return this.inputs[name];

		// Create Checkbox field
		const input = new JestInputCheckbox( this.client, name, id, defaultValue, labelText );
		input.build( `input-${name}` );

		// Append to modal UI
		this.box.refs.inputwrap.addPanel( name, input.panel );

		// Store reference
		this.inputs[name] = input;
		return input;
	}

	//--------------------------------
	// Add Textarea Input Field
	//--------------------------------
	// Adds a multiline [textarea] input to the modal.
	// RETURNS: [JestInputTextarea]
	// * name			- [string] unique input name
	// * id				- [string|null] optional HTML id
	// * defaultValue	- [string|null] default content
	// * placeholder	- [string|null] input placeholder
	// * labelText		- [string|null] field label
	addTextarea( name, id=null, defaultValue=null, placeholder=null, labelText=null ) {
		// Check for existing field
		if ( this.inputs[name] ) return this.inputs[name];

		// Create input field
		const input = new JestInputTextarea( this.client, name, id, defaultValue, placeholder, labelText );
		input.build( `input-${name}` );

		// Append to modal UI
		this.box.refs.inputwrap.addPanel( name, input.panel );

		// Store reference
		this.inputs[name] = input;
		return input;
	}

	//--------------------------------
	// Add Select Dropdown Field
	//--------------------------------
	// Adds a dropdown [select] input to the modal.
	// RETURNS: [JestInputSelect]
	// * name			- [string] unique field key
	// * id				- [string|null] HTML id override
	// * defaultValue	- [string|null] selected value
	// * options		- [array] list of value options
	// * labelText		- [string|null] visible label
	addSelect( name, id=null, defaultValue=null, options=null, labelText=null ) {
		// Check for existing field
		if ( this.inputs[name] ) return this.inputs[name];

		// Create input field
		const input = new JestInputSelect( this.client, name, id, null, options, labelText );
		input.build( `input-${name}` );

		// Load initial options if provided.
		if ( options )
			input.setOptions( options );

		// Select default option if supplied.
		if ( defaultValue )
			input.setDefault( defaultValue );

		// Append to modal UI
		this.box.refs.inputwrap.addPanel( name, input.panel );

		// Store reference
		this.inputs[name] = input;
		return input;
	}

	//--------------------------------
	// Add Radio Set Input Field
	//--------------------------------
	// Adds a radio button group to the modal.
	// RETURNS: [JestInputRadioSet]
	// * name			- [string] field name
	// * id				- [string|null] HTML id
	// * defaultValue	- [string|null] selected value
	// * options		- [array] set of string labels
	// * labelText		- [string|null] group label
	addRadioSet( name, id=null, defaultValue=null, options=null, labelText=null ) {
		// Check for existing field
		if ( this.inputs[name] ) return this.inputs[name];

		// Create input field
		const input = new JestInputRadioSet( this.client, name, id, defaultValue, options, labelText );
		input.build( `input-${name}` );

		// Append to modal UI
		this.box.refs.inputwrap.addPanel( name, input.panel );

		// Store reference
		this.inputs[name] = input;
		return input;
	}

	//--------------------------------
	// Add Range Slider Input Field
	//--------------------------------
	// Adds a numeric slider input (0–100 default).
	// RETURNS: [JestInputRange]
	// * name			- [string] unique name key
	// * id				- [string|null] HTML id
	// * defaultValue	- [number] initial slider value
	// * labelText		- [string|null] field label
	addRange( name, id=null, defaultValue=0, labelText=null ) {
		// Check for existing field
		if ( this.inputs[name] ) return this.inputs[name];

		// Create input field
		const input = new JestInputRange( this.client, name, id, defaultValue, labelText );
		input.build( `input-${name}` );

		// Append to modal UI
		this.box.refs.inputwrap.addPanel( name, input.panel );

		// Store reference
		this.inputs[name] = input;
		return input;
	}

	//--------------------------------
	// Add Number Input Field
	//--------------------------------
	// Adds a numeric [step input] field.
	// RETURNS: [JestInputNumber]
	// * name			- [string] unique field key
	// * id				- [string|null] optional HTML id
	// * defaultValue	- [number] initial value
	// * placeholder	- [string|null] placeholder hint
	// * labelText		- [string|null] visible label
	addNumber( name, id=null, defaultValue=0, placeholder=null, labelText=null ) {
		// Check for existing field
		if ( this.inputs[name] ) return this.inputs[name];

		// Create input field
		const input = new JestInputNumber( this.client, name, id, defaultValue, placeholder, labelText );
		input.build( `input-${name}` );

		// Append to modal UI
		this.box.refs.inputwrap.addPanel( name, input.panel );

		// Store reference
		this.inputs[name] = input;
		return input;
	}

	//--------------------------------
	// Add File Select Input Field
	//--------------------------------
	// Adds a file picker input (open file dialog).
	// RETURNS: [JestInputFileSelect]
	// * name			- [string] unique field name
	// * id				- [string|null] HTML id override
	// * defaultValue	- [string|null] initial file path
	// * labelText		- [string|null] field label
	addFileSelect( name, id=null, defaultValue=null, labelText=null ) {
		// Check for existing field
		if ( this.inputs[name] ) return this.inputs[name];

		// Create input field
		const input = new JestInputFileSelect( this.client, name, id, defaultValue, labelText );
		input.build( `input-${name}` );

		// Append to modal UI
		this.box.refs.inputwrap.addPanel( name, input.panel );

		// Store reference
		this.inputs[name] = input;
		return input;
	}

	//--------------------------------
	// Get Input Value by Name
	//--------------------------------
	// RETURNS: [string|null]
	// * name - [string] field name
	getInputValue( name ) {
		return this.inputs[name]?.getValue?.() ?? null;
	}

	//--------------------------------
	// Get All Input Values
	//--------------------------------
	// RETURNS: [object] key-value pairs
	getAllInputs() {
		const result = {};
		for ( const key in this.inputs )
			result[key] = this.inputs[key].getValue();
		return result;
	}

	//--------------------------------
	// Remove Input Field by Name
	//--------------------------------
	// RETURNS: [bool] success
	removeInput( name ) {
		// Check if input field exists.
		const input = this.inputs[name];
		// Remove the input field if it exists.
		if ( input ) {
			input.remove(); // remove DOM
			delete this.inputs[name];
			return true; // success
		}
		return false; // failed
	}

	//--------------------------------
	// Reset All Input Fields
	//--------------------------------
	// Clears all fields to their default values.
	resetInputs() {
		// Iterate all inputs & reset.
		for ( const key in this.inputs )
			this.inputs[key].reset?.();
	}

	//--------------------------------
	// Add Button to Modal
	//--------------------------------
	// Creates a new button, appends to footer, and stores it in a keyed map.
	//	• If the key already exists, remove the old button cleanly first.
	//	• Uses a per-instance counter for id sequencing (no array .length hacks).
	// RETURNS: [JestButton]
	// * key	- [string] button key name (e.g., 'ok','cancel','overwrite')
	// * label	- [string] button text
	// * callback - [function|null] click handler
	addButton( key, label, callback=null ) {
		// If a button with this key exists, remove it before adding a new one.
		if ( this.buttons[key] )
			this.removeButton( key );

		// Build a unique id using a per-instance monotonic counter.
		const nextId = `modal-button-${++this.buttonSeq}`;

		// Create button [object].
		const button = new JestButton( this.client, nextId );
		button.build( 'modal-button', [], label );	// build [object]

		// Register click event (primary action)
		if ( typeof callback==='function' )
			button.register( 'click', `btn-${key}`, callback );

		// Optional SFX (leave exactly as you had it)
		button.register( 'mousedown', 'sfx',
			() => this.client.soundboard.playSound( 'jest_mouse_down', 'mp3', 1.1 ) );
		button.register( 'mouseup', 'sfx',
			() => this.client.soundboard.playSound( 'jest_mouse_up', 'mp3', 1.1 ) );

		// Append into footer container
		this.box.refs.buttons.addPanel( key, button.panel );

		// Store by key in the map
		this.buttons[key] = button;
		return button; // return button [object]
	}

	//--------------------------------
	// Remove One Button by Key
	//--------------------------------
	// Safely removes the button DOM and its map entry.
	// RETURNS: [bool] true if removed
	removeButton( key ) {
		// Check if button exists.
		const btn = this.buttons?.[key];
		if ( !btn ) return false; // button not found
		// Remove from DOM if present
		this.box.refs.buttons.removePanel( key );
		// Drop reference
		delete this.buttons[key];
		return true; // successfully removed
	}

	//--------------------------------
	// Clear All Buttons
	//--------------------------------
	// Nukes the footer container and resets the map.
	//	• Call before repopulating a modal with new actions.
	// RETURNS: [void]
	clearButtons() {
		// Remove known buttons by key (lets GC reclaim)
		if ( this.buttons && typeof this.buttons==='object' ) {
			for ( const key in this.buttons )
				this.removeButton( key );
		}

		// Hard clear footer container just in case
		const footer = this.box?.refs?.buttons?.el;
		if ( footer )
			while ( footer.firstChild )
				footer.removeChild( footer.firstChild );

		// Reset map
		this.buttons = {};
	}

	//--------------------------------
	// Dismissing Modal
	//--------------------------------
	// Reset the dialog.
	// RETURNS: [void]
	reset() {
		// Reset the panel.
		this.close(); // remove from visibility
		// Clear the input.
		this.setText( '' );		// clear input field
		this.setTitle( '' );	// clear title
		this.resetInputs();		// clear all input values
	}

	// Close the dialog.
	// RETURNS: [void]
	// * data	- [any] optional override payload (if different from open)
	close( data=null ) {
		// Hide the panel.
		this.hide(); // remove from visibility
		// Emit close event.
		this.emit( 'close', null, this.payload, data ); // emit close event
		this.payload	= null; // clear context
	}

	// Hide the dialog.
	// RETURNS: [void]
	hide() {
		// Hide the panel.
		this.panel.addClass( 'hidden' ); // hide the dialog
	}

	//--------------------------------
	// Showing Modal
	//--------------------------------
	// Open the dialog.
	// RETURNS: [void]
	// * data	- [any] optional payload for event context
	open( data=null ) {
		// Store optional payload (accessible via open & close events).
		this.payload	= data;	// store context
		// Emit pre-open event.
		this.emit( 'preopen', null, this.payload );
		// Open the panel.
		this.show();			// show the dialog
		// Play a "prompt" sound-effect for affirmation.
		this.client.soundboard.playSound( 'jest_prompt', 'mp3', 1.1 );
		// Emit open event.
		this.emit( 'open' );
	}

	// Show the dialog.
	// RETURNS: [void]
	show() {
		// Hide the panel.
		this.panel.removeClass( 'hidden' ); // show the dialog
	}
}

