//-------------------------
// JestSecretary Class
//-------------------------
// Manages *.* files (downloads, preloading, data handling).
class JestSecretary extends JestGamepiece {
	// Declare properties
	baseURL		= null;			// [string] Root directory for remote file requests
	filetypes	= {};			// [object] Specs for supported extensions
	records		= {};			// [object] Cached parsed data per extension

	// --------------------------------
	// Constructor
	// --------------------------------
	// Construct with a default base URL.
	// * client		- Client [object] that this piece belongs to.
	// * baseURL	- [string] Base URL for all image(s) / image folder(s).
	constructor( client, baseURL=null ) {
		super( client );					// Call the parent constructor.
		this.baseURL	= baseURL;			// Set the global placeholder.
	}

	// --------------------------------
	// Register Filetype(s)
	// --------------------------------
	// Add a new filetype dynamically.
	// RETURNS: [void] on success, throws [object[ Error on fail.
	// * ext	- [string] Extension (e.g. 'png', 'json')
	// * specs	- [object] { parser?, cacheTime?, strict?, responseType? }
	addFiletype( ext, specs ) {
		// Validate argument
		if ( !jsos.prove(ext,'string') )
			throw new Error( 'Invalid extension. Must be [string].' );
		// Validate argument
		if ( !specs || typeof specs!=='object' )
			throw new Error( 'Invalid specs for filetype registration.' );
		// Register filetype.
		this.filetypes[ext]	= {
			responseType:	'text',
			cacheTime:		0,
			strict:			true,
			...specs
			};
		// Ensure file storage exists for this filetype.
		if ( !this.records[ext] )
			this.records[ext]	= {};
	}

	// Remove an existing filetype.
	// RETURNS: [void] on success, throws [object[ Error on fail.
	// * ext	- [string] The ext key to remove.
	removeFiletype( ext ) {
		// Validate argument
		if ( !jsos.prove(ext,'string') )
			throw new Error( 'Invalid ext. Must be of type [string].' );
		// Remove associated ext & storage.
		if ( this.filetypes[ext] ) {
			delete this.filetypes[ext];
			delete this.records[ext];
		}
	}

	// Store a file's result in the secretary's records.
	// RETURNS: [boolean] `true` on success, `false` if any file fails.
	// * ext		- [string] Value of file filetype extension.
	// * key		- [string] Unique record key of file being stored.
	// * data		- [...] data of file to store.
	file( ext, key, data ) {
		// Further parse file data into game [object]
		//try {
			// Build generic result [object].
			const result	= { key, data };
			// Check for additional parsing.
			let parsed		= null;
			const parser	= this.filetypes[ext]?.parser ?? null;
			if ( parser ) {
				if ( parser in this.client.parsers )
					parsed	= this.client.parsers[parser].parse( result );
				else {
					console.warn( `Secretary could not locate parser: ${parser}` );
					parsed	= data; // fallback
				}
			}
			else parsed		= data; // raw data
			// Check if value successfully parsed.
			if ( parsed )
				this.records[ext][key] = parsed;
			else throw new Error( "could not parse file because data corrupted or incorrect format" );
			return true; // success
		/*}
		catch ( err ) {
			console.warn( `Secretary could not load ${ext} file "${key}": ${err.message}` );
			return false; // fail
		}*/
	}

	// --------------------------------
	// Web File Downloading
	// --------------------------------
	// Retrieves *.* file, parses it, then stores the file by stem.
	// RETURNS: [boolean] `true` on success, `false` if any file fails.
	// * address - [string] value of address path
	async loadFile( address ) {
		return await this.loadFiles( [address] );
	}

	// Loads remote files by full address (e.g., 'tiles/grass.png').
	// RETURNS: [boolean] `true` if all load, `false` if any fail.
	// * addresses - [array] of [string] address paths
	async loadFiles( addresses ) {
		// --------------------------------
		// Validate Argument(s)
		// --------------------------------
		// Validate argument(s)
		if ( !jsos.prove(addresses,'array') )
			throw new Error( 'Secretary loadFiles(): `addresses` must be [array]' );

		// --------------------------------
		// Setup Data For Transfer
		// --------------------------------
		const queue = [];
		// Iterate all addresses & load file(s).
		for ( const address of addresses ) {
			// --------------------------------
			// Attempt to Purview Address
			// --------------------------------
			// Purview the address & queue if successful.
			const purview	= this.getRecordPurview( address );
			// Check if purview succeeded.
			if ( !purview ) continue; // skip
			// Queue the item.
			queue.push( purview );
		}

		// --------------------------------
		// Begin Downloading
		// --------------------------------
		// Use transmitter to load files queue in batches of 3
		await this.client.transmitter.loadFiles( queue, 3 );

		// --------------------------------
		// Process Each Result
		// --------------------------------
		// Process results
		let allOK	= true;
		for ( const request of queue ) {
			// Get overview of address file info.
			const { address, filename, path, extension: ext, stem, key } = request;
			// Check if previously loaded.
			if ( this.hasRecord(address) ) continue; // skip

			// Continue to load file.
			const data	= this.client.transmitter.getFiles( address );
			if ( !data ) {
				console.warn( `No data returned for: ${address}` );
				allOK	= false;
				continue; // skip
			}

			// Further parse file data into game [object]
			let parsed	= data.parsed;
			// Check whether data successfully loaded.
			if ( !parsed ) {
				console.warn( `Failed to download/parse file: ${filename}` );
				allOK = false;
				continue; // skip
			}

			// Proceed to file the file in secretary records.
			const filed		= this.file( ext, key, parsed );
			if ( !filed ) {		// check if file failed
				allOK = false;	// at least one file failed
				continue;		// continue to try next file
			}
			// Notify console that the file has been processed.
			console.log( `Loaded and stored [${ext}]: ${address}` );
		}

		return allOK; // success status
	}

	// --------------------------------
	// Local File Reading
	// --------------------------------
	// Read a File object (e.g., from drag-drop or input).
	// RETURNS: [boolean] `true` on success, `false` if any file fails.
	// * item		– either a File or a FileInfo [object]
	async readFile( item ) {
		// delegate to readFiles for uniform handling
		const ok = await this.readFiles( [item] );
		return ok;
	}

	// Read File [objects] (e.g., from drag-drop or input).
	// RETURNS: [boolean] `true` on success, `false` if any file fails.
	// * items		– [array] of File or FileInfo [objects]
	async readFiles( items ) {
		// --------------------------------
		// Validate Argument(s)
		// --------------------------------
		// Validate argument(s)
		if ( !jsos.prove(items,'array') )
			throw new Error( '`items` must be [array] of File/FileInfo' );

		// --------------------------------
		// Prevent Re-Reading Previously Read Files
		// --------------------------------
		//const queue	= items;
		const queue = [];
		// Filter out previously read items
		for ( const item of items ) {
			const purview = this.getRecordPurview( item.address, 'local' );
			const { extension: ext, key } = purview;
			// ❗ Already stored? Skip.
			if ( this.records?.[ext]?.[key] ) continue;
			// Proceed with queueing
			queue.push( item );
		}
		// Stop reading if already read.
		if ( queue.length===0 )
			return true; // ✅ all already read

		// --------------------------------
		// Begin Reading
		// --------------------------------
		// Use transmitter to read files (in batches of 3)
		const reads	= await this.client.transmitter.readFiles( queue, 'arrayBuffer' );

		// --------------------------------
		// Process Each Result
		// --------------------------------
		// Process results
		let allOK	= true;
		console.log( reads );
		for ( const { request, file, result } of reads ) {
			// Get overview of address file info.
			const { address, filename, path, extension: ext, stem } = request;
			// Purview the address & extract record key.
			const purview	= this.getRecordPurview( address, 'local' );
			const { key }	= purview;
			// Check if specs have been defined for this filetype.
			const specs		= this.filetypes[ext];
			if ( !specs ) {
				console.warn( `Unregistered extension: ${filename})` );
				allOK		= false;
				continue; // skip
			}

			// Further parse file data into game [object]
			let parsed		= this.client.convertData( result, 'arrayBuffer', specs.parse || 'text');
			// Check whether data successfully loaded.
			if ( !parsed ) {
				console.warn( `Failed to read/parse file: ${filename}` );
				allOK = false;
				continue; // skip
			}

			// Proceed to file the file in secretary records.
			const filed		= this.file( ext, key, parsed );
			if ( !filed ) {		// check if file failed
				allOK = false;	// at least one file failed
				continue;		// continue to try next file
			}
			// Notify console that the file has been processed.
			console.log( `Loaded and stored [${ext}]: ${address}` );
		}

		//console.log( this.records );
		return allOK; // success status
	}

	// Save file data as Blob locally.
	// RETURNS: [string] URL to file blob (or downloads it if preferred).
	/*writeFile( filetype, name, data ) {
		// Begin generating the
		const ext	= this.filetypes[filetype]?.extension ?? 'txt';
		const blob	= new Blob( [data], { type: 'text/plain' } );
		const url 	= URL.createObjectURL( blob );
		// Optionally auto-download
		const a		= document.createElement( 'a' );
		a.href		= url;
		a.download	= `${name}.${ext}`;
		a.click();
		// Return the URL
		return url;
	}*/

	// --------------------------------
	// Get a Record (with Warning)
	// --------------------------------
	// Get a record full path.
	// RETURNS: [object] of file information, else [null] on fail.
	// * address	- [string] Full path to jani file, with filename + extension.
	//   network	- [string] One of: 'local', 'remote'
	getRecordPurview( address, network='remote' ) {
		//-------------------------
		// Validate Arguments
		//-------------------------
		// Ensure filetype & stem are [string].
		if ( !jsos.prove(address,'string') ) {
			console.warn( `Invalid argument(s): 'address' must a [string].` );
			return null; // abort
		}

		// --------------------------------
		// Parse Path & Add to Queue
		// --------------------------------
		// Get overview of address file info.
		const fileInfo	= this.client.getFileInfo( address );

		// --------------------------------
		// Validate Specs Defined for Filetype
		// --------------------------------
		// Check if specs have been defined for this filetype.
		const specs		= this.filetypes[fileInfo.extension];
		if ( !specs ) {
			console.warn( `Unregistered extension: ${address}` );
			return null; // abort
		}

		//-------------------------
		// Parse Path Information
		//-------------------------
		// Extract fileInfo data for purview.
		const filename	= fileInfo.filename;	// file stem + extension
		const ext		= fileInfo.extension;	// filetype extension (no stem)
		const stem		= fileInfo.stem;		// file name (no extension)

		// Remove leading/trailing slashes & re-add single trailing slash.
		let path		= fileInfo.path;		// path to file
		path			= !path ? '' : path.trim().replace(/^\/+|\/+$/g,'');
		if ( path.length>0 ) path += '/';

		// Get file MIME subpath for extension.
		const subpath	= this.filetypes[ext]?.subpath ?? ''; // interpret response data

		// Properly redirect the full parsed path.
		let fullPath	= '';
		if ( network==='remote' ) {
			// Auto-generate full URL-based record key.
			if ( !ext ) {
				console.warn( `Secretary: Unknown extension for extension "${ext}".` );
				return null; // abort
			}
			// Ensure full remote path ends with slash before filename.
			fullPath	= `${this.baseURL}/`;
			// Include subpath (defined in specs).
			if ( subpath.length>0 )
				fullPath	= `${fullPath}${subpath}/`;
			// Include requested path (from address argument).
			if ( path.length>0 )
				fullPath	= `${fullPath}${path}`;
		}

		//-------------------------
		// Generate Record Key
		//-------------------------
		// Generate prefix based upon network.
		const prefix	= network==='local' ? 'loc' : 'web';
		const key		= `${prefix}:${fullPath}${filename}`;

		// --------------------------------
		// Create Purview & Return Data
		// --------------------------------
		// Define purview [object] return data.
		let purview		= {
			key:			key,
			address:		`${fullPath}${filename}`,
			path:			path,
			subpath:		subpath,
			stem:			stem,
			filename:		filename,
			extension:		ext,
			network:		network==='remote' ? 'remote' : 'local',
			cacheTime:		specs.cacheTime,
			strict:			specs.strict,
			responseType:	specs.responseType
			};
		return purview;		// return purview
	}

	// Retrieve a record of the given filetype extension & record key.
	// RETURNS: [object] Record if found, else [null] + warning.
	// * address	- [string] Full path to jani file, with filename + extension.
	//   network	- [string] One of: 'local', 'remote'
	getRecord( address, network='remote' ) {
		// --------------------------------
		// Parse Path & Get Extension
		// --------------------------------
		// Get overview of address file info.
		const purview	= this.getRecordPurview( address, network );
		const ext		= purview.extension; // filetype extension (no stem)
		const key		= purview.key;
		// --------------------------------
		// Proceed to Return Record
		// --------------------------------
		// Check if record exists.
		if ( this.hasRecord(address,network) )
			return this.records[ext][key];
		// Throw warning & return [null].
		console.error( `Secretary: No record found for file "${address}".` );
		return null; // doesn't exist
	}

	// Check if a record exists for the given filetype extension & record key.
	// RETURNS: [boolean] `true` if exists, `false` if not.
	// * address	- [string] Full path to jani file, with filename + extension.
	//   network	- [string] One of: 'local', 'remote'
	hasRecord( address, network='remote' ) {
		// --------------------------------
		// Parse Path & Get Extension
		// --------------------------------
		// Get overview of address file info.
		const purview	= this.getRecordPurview( address, network );
		const ext		= purview.extension; // filetype extension (no stem)
		const key		= purview.key;
		// --------------------------------
		// Proceed to Check Record
		// --------------------------------
		// Validate arguments
		if ( !jsos.prove(ext,'string') || !jsos.prove(key,'string') ) {
			console.warn( 'Invalid argument(s). `ext` and `key` must both be of type [string].' );
			return false; // abort
		}
		// Check existence
		return !!( this.records?.[ext]?.[key] );
	}
	// Remove a secretary record if it exists (clears cache only).
	// RETURNS: [boolean] `true` if exists, `false` if not.
	// * address	- [string] Full path to jani file, with filename + extension.
	//   network	- [string] One of: 'local', 'remote'
	removeRecord( address, network='remote' ) {
		// --------------------------------
		// Parse Path & Get Extension
		// --------------------------------
		// Get overview of address file info.
		const purview	= this.getRecordPurview( address, network );
		const ext		= purview.extension; // filetype extension (no stem)
		const key		= purview.key;
		// --------------------------------
		// Proceed to Remove Record
		// --------------------------------
		// Check if record already exists.
		if ( this.hasRecord(address,network) ) {
			delete this.records[ext][key]; // remove it
			console.log( `Removed record ${ext}:${key}` );
			return true; // cleared cache
		}
		// Throw warning & return [bool] false.
		console.warn( `No record to remove: ${ext}:${key}` );
		return false; // nothing removed
	}
}

/* --- BEGIN js/apps/jest/components/editing/JestGovernor.js --- */

//-------------------------
// JestGovernor Class
//-------------------------
// A state manager for state changes.
class JestGovernor extends JestElement {
	// Object properties
	stacks		= {};			// [object] { states: [ … ], index: number, limit: number }
	queue		= {};			// [object] Map of { [key]: object } pending metadata to merge on next log

	// --------------------------------
	// Constructor
	// --------------------------------
	// Construct the [object].
	// RETURNS: [void].
	// * client		- [object] Application client that this piece belongs to.
	constructor( client ) {
		super( client ); // call parent constructor
		// Initialize mode(s) & propert(ies).
		this.jot( 'reverting', false ); // not active
	}

	// --------------------------------
	// Stack Handling
	// --------------------------------
	// Initialize (or re-initialize) a stack under `key`, with an optional limit.
	// If the stack already exists, this will override its limit and clear history.
	// RETURNS: [void].
	// * key		– string identifier for this stack
	// * limit		– max number of entries to keep in history (oldest drop first)
	init( key, limit=100 ) {
		// Enforce that limit is an integer ≥ 1
		const maxLimit		= Number.isInteger(limit) && limit>0 ? limit : 100;
		this.stacks[key]	= {
			states:		[],			// array of JSON snapshots
			index:		-1,			// “pointer” into states; −1 means “no states yet”
			limit:		maxLimit	// max entries to keep
			};
		// Emit event.
		this.emit( `init`, null, key, limit ); // emit event
	}

	// --------------------------------
	// Queue Metadata for Next Log
	// --------------------------------
	// Queues extra data to be merged into the next log() snapshot.
	// * key   – [string] The stack key
	// * data  – [object] Metadata to merge into next log state
	enqueue( key, data ) {
		if ( typeof key!=='string' || !data || typeof data!=='object' ) return;
		if ( !this.queue[key] ) this.queue[key] = {};
		Object.assign( this.queue[key], data );
	}

	// --------------------------------
	// Dequeue Metadata Before Log
	// --------------------------------
	// Removes any queued metadata waiting to be merged into the next log().
	// * key   – [string] Stack key to clear metadata for
	// * fields – [array] Optional [array] of specific field names to remove
	dequeue( key, fields=null ) {
		// No queue? Nothing to remove.
		if ( !this.queue?.[key] ) return;
		// Remove specific fields
		if ( Array.isArray(fields) ) {
			for ( const f of fields )
				delete this.queue[key][f];
			// If empty, nuke the whole key
			if ( Object.keys(this.queue[key]).length===0 )
				delete this.queue[key];
		}
		// No fields? Remove entire metadata block.
		else delete this.queue[key];
	}

	// Record a new state for `key`. If the current index is not at the very end,
	// drop any “redo” states first. Then append newState. Finally, if we exceed
	// the limit, remove the oldest entry(s) from the front.
	// RETURNS: Newly logged snapshot [object|null].
	// * key		– [string] Value of which stack to use.
	// * newState	– any JSON-serializable [object].
	log( key, newState ) {
		// If reverting, skip.
		if ( this.skim('reverting') ) return null;
		// Ensure the stack exists (default limit = 100)
		if ( !this.stacks[key] ) this.init( key );

		// --------------------------------
		// Log New Result
		// --------------------------------
		const stack		= this.stacks[key];
		const i			= stack.index;
		const lastIndex	= stack.states.length - 1;
		// If we’re not at the latest snapshot, drop everything after `index`
		if ( i<lastIndex ) {
			// Find how many states are removed.
			const overwrite	= lastIndex - i;
			// Remove from current state (i+1) through end of list.
			stack.states.splice( i+1, lastIndex-i );
			// Emit event.
			this.emit( `overwrote`, null, key, overwrite ); // emit event
			// No more redos are possible.
			this.emit( `redo:limit`, null, key );
		}

		// Merge queued metadata, if any
		const meta = this.queue[key] || null;
		if ( meta ) delete this.queue[key];
		// Merge queued data or use raw supplied arg.
		const snapshot = ( meta && typeof newState==='object' )
			? Object.assign( {}, newState, meta )
			: newState;

		// Push a deep-cloned copy of newState
		// (so future mutation of the original object won’t affect history)
		stack.states.push( snapshot );
		stack.index		= stack.states.length - 1;

		// Emit new event signaling that an event was logged.
		this.emit( `logged`, null, key, stack, snapshot );
		// Emit new event signaling that something has changed.
		this.emit( `changed`, null, key, snapshot );
		// Emit new event signaling that undo is possible.
		this.emit( `undoable`, null, key, stack.states.length );

		// --------------------------------
		// Clear Overflowed States
		// --------------------------------
		// Call overflow check.
		this.overflow( key );
		// Return snapshot.
		return snapshot; // log [object]
	}

	// --------------------------------
	// Append to Current State
	// --------------------------------
	// Merge additional metadata into the *current* state (if exists).
	// RETURNS: [bool] true if successful, else false
	// * key		– [string] stack key
	// * updates	– [object] fields to merge into the latest snapshot
	domino( key, updates ) {
		// If reverting, abort.
		if ( this.skim('reverting') ) return false;
		// Validate inputs
		if ( typeof key!=='string' || !updates || typeof updates!=='object' ) return false;
		const stack = this.stacks[key];
		if ( !stack || stack.index<0 ) return false;

		// Grab the actual logged object
		const current = stack.states[stack.index];

		// Shallow merge the updates
		Object.assign( current, updates );

		// Emit event for metadata update
		this.emit( 'modified', null, key, current, stack.index );
		return true;
	}

	// --------------------------------
	// Get Current Log Reference
	// --------------------------------
	// Gets a *live reference* to the actual current snapshot object.
	// WARNING: modifying this directly alters undo history!
	// RETURNS: [object|null] the actual state object or null
	// * key     – [string] stack key
	pezLog( key ) {
		const stack = this.stacks[key];
		if ( !stack || stack.index<0 ) return null;
		return stack.states[stack.index]; // live reference
	}

	// --------------------------------
	// Get Stack (if exists)
	// --------------------------------
	// Attempt to get a stack.
	// RETURNS: [void].
	// * key	– [string] Value of which stack to get.
	getStack( key ) {
		// If reverting, skip.
		if ( this.skim('reverting') ) return;
		// Ensure the stack exists
		if ( !this.stacks?.[key] ) return;
		return this.stacks[key]; // return stack
	}

	// --------------------------------
	// Revert Method(s)
	// --------------------------------
	// Attempt to undo an action inside an open level file.
	// RETURNS: [void].
	// * count	- signed [int] value to iterate (negative for undo).
	// * key	– [string] Value of which stack to use.
	revert( count, key ) {
		// If reverting, skip.
		if ( this.skim('reverting') ) return;
		// Determine action by count.
		const action	= count<0 ? 'undo' : 'redo'; // determine action
		// Iterate requested amount of action.
		for ( let i=0; i<Math.abs(count); i++ ) {
			if ( action==='undo' )
				this.undo( key );	// undo
			else this.redo( key );	// redo
		}
	}

	// Step backward one state, if possible.
	// RETURNS: the new “current” snapshot, or null if no undo is possible.
	// * key	– [string] Value of which stack to use.
	undo( key ) {
		// If reverting, skip.
		if ( this.skim('reverting') ) return;
		// Check if undos are possible.
		const stack	= this.stacks[key];
		if ( !stack || stack.index<0 ) return null;
		// Get new current snapshot.
		const snapshot	= stack.states[stack.index];
		// Iterate the stack index back one state.
		stack.index--;
		// If undo max limit reached, emit event.
		if ( stack.index<0 ) // emit event
			this.emit( `undo:limit`, null, key );
		// Emit undo event.
		this.emit( `undo`, null, key, snapshot, stack.states.length, stack.index );
		// Emit new event signaling that something has changed.
		this.emit( `changed`, null, key, snapshot );
		// Emit new event signaling that redo is possible.
		this.emit( `redoable`, null, key, stack.states.length );
		return snapshot; // return snapshot
	}

	// Step forward one state, if possible.
	// RETURNS: the new “current” snapshot, or null if no redo is possible.
	// * key	– [string] Value of which stack to use.
	redo( key ) {
		// If reverting, skip.
		if ( this.skim('reverting') ) return;
		// Check if redos are possible.
		const stack	= this.stacks[key];
		if ( !stack || stack.index>=(stack.states.length-1) ) return null;
		// Iterate the stack index back one state.
		stack.index++;
		// Get new current snapshot.
		const snapshot	= stack.states[stack.index];
		// If redo max limit reached, emit event.
		if ( stack.index>=(stack.states.length-1) ) // emit event
			this.emit( `redo:limit`, null, key );
		// Emit redo event.
		this.emit( `redo`, null, key, snapshot, stack.states.length, stack.index );
		// Emit new event signaling that something has changed.
		this.emit( `changed`, null, key, snapshot );
		return snapshot; // return snapshot
	}

	//-----------------------------
	// Clear All History Immediately
	//-----------------------------
	// Wipes internal governor stack with no undo logic.
	// Emits `clear` event so UI can purge history list.
	// RETURNS: [void]
	// * key – [string] identifier for this stack
	clear( key ) {
		// If reverting, skip.
		if ( this.skim('reverting') ) return;
		// Check if stack for key exists.
		const stack		= this.stacks[key];
		if ( !stack ) return;
		// Empty states [array].
		stack.states	= [];
		stack.index 	= -1; // reset index
		// Emit event.
		this.emit( 'clear', null, key ); // signal UI to clear
	}

	//-----------------------------
	// Reset History by Rewinding
	//-----------------------------
	// Performs full stepwise undo to index -1.
	// Emits 'undo' events for each step, preserving animation.
	// RETURNS: [void]
	// * key – [string] identifier for this stack
	reset( key ) {
		// If reverting, skip.
		if ( this.skim('reverting') ) return;
		// Iterate all undo states & undo.
		while ( this.canUndo(key) )
			this.undo( key ); // each call emits full undo event
		// Emit event.
		this.emit( 'reset', null, key ); // signal UI reset took place
	}

	// Checks if a stack overflowed & trims the excess.
	// RETURNS: [bool] if overflowed, else [false].
	// * key	– which stack to update
	// * limit	– limit to overflow check on.
	overflow( key, limit=null ) {
		// Get the stack.
		const stack	= this.stacks[key];
		if ( !stack ) return false;
		if ( limit==null )
			limit	= stack.limit ?? 0;
		// If we now exceed `limit`, remove oldest entries at the front
		if ( stack.states.length>limit ) {
			// Number of items to drop = currentLength – limit
			const overflow = stack.states.length - stack.limit;
			// Remove `overflow` items from start
			stack.states.splice( 0, overflow );
			// Adjust index downward by however many we removed
			stack.index -= overflow;
			if ( stack.index<0 ) {
				stack.index = -1; // clamp index
				this.emit( `undo:limit`, null, key ); // emit event
			}
			// Emit event.
			this.emit( `overflow`, null, key, overflow, stack.index );
			return true; // overflowed
		}
		return false; // no overflow
	}

	// --------------------------------
	// Log New Result
	// --------------------------------
	// Peek at the current state without modifying anything.
	// RETURNS: the JSON snapshot at `index`, or null if stack is empty.
	current( key ) {
		// Check if current state exists.
		const stack	= this.stacks[key];
		if ( !stack || stack.index<0 ) return null;
		return stack.states[stack.index]; // return state
	}

	// Change the limit for `key`. If the existing history is longer than the
	// new limit, immediately drop the oldest entries.
	// RETURNS: [void].
	// * key      – which stack to update
	// * newLimit – integer ≥ 1; if invalid, no change is made
	setLimit( key, newLimit ) {
		const stack	= this.stacks[key];
		if ( !stack ) return;
		// Validate newLimit
		if ( !Number.isInteger(newLimit) || newLimit<1 ) return;
		stack.limit	= newLimit;
		// Call overflow check.
		this.overflow( key, newLimit );
	}

	// --------------------------------
	// Reporting Method(s)
	// --------------------------------
	// Does `key` exist and have at least one recorded state?
	hasState( key ) {
		const stack	= this.stacks[key];
		return !!( stack && stack.states.length>0 );
	}

	// Can an undo be performed?
	// RETURNS: [bool] true if undo is possible, else false.
	canUndo( key ) {
		const stack = this.stacks[key];
		return !!( stack && stack.index>=0 );
	}

	// Can a redo be performed?
	// RETURNS: [bool] true if redo is possible, else false.
	canRedo( key ) {
		const stack = this.stacks[key];
		return !!( stack && stack.index<(stack.states.length-1) );
	}

	// How many undo steps are possible?
	// RETURNS: [int] number of undos possible.
	getUndoCount( key ) {
		const stack = this.stacks[key];
		if ( !stack ) return 0;
		return stack.index + 1;
	}

	// How many redo steps are possible?
	// RETURNS: [int] number of redos possible.
	getRedoCount( key ) {
		const stack = this.stacks[key];
		if ( !stack ) return 0;
		return stack.states.length - stack.index - 1;
	}

	// Full stack report.
	// RETURNS: [object] with report details.
	report( key ) {
		const stack = this.stacks[key];
		if ( !stack ) {
			return {
				exists:		false,
				states:		0,
				index:		-1,
				limit:		0,
				canUndo:	false,
				canRedo:	false,
				undoCount:	0,
				redoCount:	0,
				current:	null
				};
		}
		return {
			exists:		true,
			states:		stack.states.length,
			index:		stack.index,
			limit:		stack.limit,
			canUndo:	this.canUndo( key ),
			canRedo:	this.canRedo( key ),
			undoCount:	this.getUndoCount( key ),
			redoCount:	this.getRedoCount( key ),
			current:	this.current( key )
			};
	}
}

