//-------------------------
// Transmission Class
//-------------------------
// A class to handle data transmissions using Fetch or XHR with event-based updates.
class Transmission extends OSCallback {
	// Input data
	inquiries		= [];					// [array] queue of inquiries to process (multiple at once)
	inquiry			= null;					// [object] Inquiry currently being processed (or last one sent)
	// Output data
	request			= null;					// The XMLHttpRequest object used for the transmission (if applicable).

	// Initializes a new Transmission instance.
	// RETURNS: [void] Nothing.
	//   options		- [Object] Configuration options.
	constructor( options={} ) {
		super( options );	// call parent constructor
		// Set mode to idle
		this.jot( 'status', 'idle' );
	}

	//-------------------------
	// Modal Methods
	//-------------------------
	// Set a mode state (override OSConfigurable parent method).
	// * mode		- [string] name of mode to set.
	// * state		- [string] value of mode.
	// RETURNS: [bool] `true` on success, else `false`.
	jot( mode, state ) {
		// If setting status, handle differently
		if ( mode==='status' && state!==this.skim('status') ) { // determine if status is changing
			if ( super.jot('status',state) ) {
				this.emit( 'statusChange', null, state );
				return true; // success
			}
			else return false; // fail
		}
		// Set some other mode besides 'status'
		return super.jot( mode, state ); // call super
	}

	//-------------------------
	// Server Interactions
	//-------------------------
	// Queue a inquiry
	//   inquiry	- [object] Inquiry configuration data
	queue( inquiry ) {
		console.log( 'transmission queued activity: '+inquiry.action+'->'+inquiry.context );
		// Validate object type
		if ( !(inquiry instanceof Inquiry) ) {
			console.warn( 'transmission cannot queue inquiry: invalid type' );
			return false;
		}
		// Push onto array stack
		if ( this.inquiries===null ) this.inquiries = [];
		this.inquiries.push( inquiry );
	}

	// Retrieve all quir(ies)
	/*retrieve() {
		//-------------------------
		// Validate Retrieval
		//-------------------------
		console.log( 'transmission attempting to retrieve' );
		// Require inquiry(s)
		if ( this.inquiries===null || this.inquiries.length<1 ) {
			console.warn( 'transmission cannot retrieve: no inquiry(s) queued' );
			return false;
		}
		//-------------------------
		// Compile Quir(ies) Data
		//-------------------------
		// Apply inquiries to FormData object
		//data.append( 'bookmark', jsos.bookmark );	// Register with session bookmark
		// Check for inquiry information
		if ( jsos.prove(this.inquiries,'array') ) {
			for ( const inquiry of this.inquiries ) {
				var inquiry	= this.inquiries[i];
				// [insert send logic here]
		}
	}*/

	// Sends a data transmission request using a Inquiry [object].
	// RETURNS: [Promise<any>] Resolves with response data or rejects with an error.
	// * inquiry	- [Object] Inquiry with appropriate data to configure a request.
	async send( inquiry ) {
		//-------------------------
		// Calibrate Mode & Stamp
		//-------------------------
		// Confirm mode
		if ( this.skim('status')!=='idle' ) {
			console.warn( 'Transmission already in progress.' );
			return Promise.reject( new Error('Transmission already in progress.') );
		}
		//-------------------------
		// Validate & Prepare
		//-------------------------
		// Handle the data & process the method
		switch ( inquiry.method ) {
			case 'POST':	// outgoing transmission
				console.log( 'transmission sending POST: '+inquiry.address );
				break;
			case 'GET':		// ingoing transmission
				console.log( 'transmission sending GET: '+inquiry.address );
				break;
			default: // unknown transmission
				alert( 'Transmission Cannot Start: Unknown Method `'+inquiry.method+'`' );
				this.jot( 'status', 'idle' );
				return false;
		}
		// Switch mode & attempt errand
		this.jot( 'status', 'starting' );		// Status is transmitting
		this.emit( 'starting' );				// Kickoff event
		this._clock( 'start' );					// Clock the object to log current timestamp
		this.inquiry	= inquiry;				// Set active inquiry to requested inquiry
		inquiry.prepare();						// Ensure inquiry data is prepared for request
		//-------------------------
		// Begin Retrieval Method
		//-------------------------
		try {
			// Handle request based upon requested interface
			let result;
			switch ( inquiry.iface ) {
				case 'FETCH':	// Fetch interface
					result	= await this._fetchRequest( inquiry );
					break;
				case 'HTTP':	// XMLHttpRequest interface
				default:
					result	= await this._xhrRequest( inquiry );
					break;
			}
			return result;
		}
		catch ( error ) {
			throw error;
		}
	}

	//-------------------------
	// Private Methods
	//-------------------------
	// Sends a inquiry using the Fetch API.
	// RETURNS: [Promise<any>] Resolves with response data or rejects with an error.
	// * inquiry	- [Object] Inquiry with appropriate data to configure a request.
	_fetchRequest( inquiry ) {
		//-------------------------
		// AbortController Setup
		//-------------------------
		const controller	= new AbortController();
		const request		= controller.signal;
		this.aborter		= controller; // save controller to allow abort later
		//-------------------------
		// Handle Fetch
		//-------------------------
		const options		=
			{
				method:		inquiry.method.toUpperCase(),
				headers:	inquiry.prepped.headers,
				body:		inquiry.method==='POST' ? inquiry.prepped.body : undefined,
				signal:		controller.signal // Attach the abort signal
			};
		//-------------------------
		// Switch Status
		//-------------------------
		// Switch mode & attempt kickoff errand
		this.jot( 'status', 'transmitting' );	// status is transmitting
		this.emit( 'kickoff' );					// kickoff event
		//-------------------------
		// Return "Fetch" Transmission
		//-------------------------
		// Call the fetch
		return fetch( inquiry.address, options )
			.then(
				response => {
					//console.log( response );
					// Throw error is response not "ok"
					if ( !response.ok ) {
						const error = new Error( `HTTP Error: ${response.status}` );
						this.emit( 'error', null, error ); // Emit error event
						throw error; // throw error
					}
					// Extract Content-Type
					const contentType	= response.headers.get('Content-Type') || 'application/octet-stream';
					inquiry.contentType	= contentType; // store content type in inquiry
					// Emit a "progress" event for download tracking
					if ( response.body && response.headers.get('content-length') ) {
						//console.log( response );
						// Create a reader
						const reader	= response.body.getReader();
						// Create vars for progress counting
						const total		= parseInt( response.headers.get('content-length'), 10 ); // total data size to load
						let loaded		= 0;		// reset load percent for new request
						const _self		= this;		// Capture `this` for use in progress
						// Read the stream and emit custom progress events
						return new ReadableStream({
							start( controller ) {
								function read() {
									reader.read().then(
										( { done, value } ) => {
											// Stream isn't done, track progress
											loaded	= !done ? loaded+value.length : total;
											_self.progress( loaded, total ); // track progress
											// Check if stream is done
											if ( done ) {
												controller.close();
												return;
											}
											else { // continue reading
												controller.enqueue( value );
												read();
											}
										});
								}
								read();
							}});
					}
					// No progress tracking possible
					return response;
				})
			.then(
				result => {
					// Response is a Response object (default case)
					if ( result instanceof Response )
						return result.arrayBuffer();
					// Result is a ReadableStream (streaming branch)
					else return new Response(result).arrayBuffer();
				}) // Process response stream
			.then( data => this.load(data) ) // Return loaded data
			.catch( // Throw an error
				error => {
					//console.log( error );
					if ( error.name==='AbortError' )
						this.abort( error );		// call abort method
					else this.error( error );		// call error method
				});
	}

	// Sends a request using XMLHttpRequest.
	// RETURNS: [Promise<any>] Resolves with response data or rejects with an error.
	// * inquiry	- [Object] Inquiry with appropriate data to configure a request.
	_xhrRequest( inquiry ) {
		//-------------------------
		// Create Return Promise
		//-------------------------
		// Return a promise [object]
		return new Promise(
			( resolve, reject ) => {
				//-------------------------
				// Begin XMLHttpRequest
				//-------------------------
				// Create an XMLHttpRequest [object] with listeners
				const request		= new XMLHttpRequest();
				this.request		= request;	// set request reference
				this.aborter		= request;	// the request is also the aborter
				this.request.open( inquiry.method, inquiry.address, true );

				// Add headers
				Object.keys(inquiry.prepped.headers).forEach(
					key => {
						this.request.setRequestHeader( key, inquiry.prepped.headers[key] );
					});

				// Add event listeners
				const onprogress				= (e) => this.progress( e.loaded, e.total );
				this.request.onprogress			= onprogress;
				this.request.upload.onprogress	= onprogress;
				//this.request.onreadystatechange	= (e) => this.change(e);
				this.request.responseType		= 'arraybuffer'; // Force arrayBuffer return

				// On load event
				this.request.onload =
					() => {
						// Require response to be okay
						if ( this.request.status>=200&&this.request.status<300 ) {
							const contentType	= request.getResponseHeader('Content-Type') || 'application/octet-stream';
							inquiry.contentType	= contentType;		// store content type in inquiry
							this.load( this.request.response );		// call load method
							resolve( this.request.response );		// resolve the promise
						}
						else {
							const error = new Error( `XHR failed with status ${this.request.status}` );
							this.error( error );	// call error method
							reject( error );		// reject the promise
						}
					};

				// On error event
				this.request.onerror	=
					( e ) => {
						console.error( 'An error occurred during the XHR request.', e );
						const error		= new Error( 'Network error occurred during the XHR request.' );
						error.event		= e;	// Attach the original event
						this.error( error );	// call error method
						reject( error );		// reject the promise
					};

				// On abort event
				this.request.onabort	=
					() => {
						const err		= new Error( 'Request aborted' );
						this.abort( error );	// call abort method
						reject( error );		// reject the promise
					};
				// Send the request
				this.request.send( inquiry.method==='POST' ? inquiry.prepped.body : null );
			});
	}

	//-------------------------
	// Activity Tracking
	//-------------------------
	// Cancels the current transmission.
	// RETURNS: [void] Nothing.
	cancel() {
		// If aborter exists, attempt abort
		if ( this.aborter ) {
			// Abort the request
			this.aborter.abort();
			console.log( 'Request aborted' );
			// Set mode to aborted & emit abort event
			this.jot( 'status', 'aborted' );
		}
		else console.log( 'No request to abort' );
	}
	// Tracking state change
	// NOTE: Deprecated!!!
	// RETURNS: [void] Nothing.
	change( e ) {
		// Determine the ready state
		switch ( this.request.readyState ) {
			case 0: // request not initialized
			case 1: // server connection established
			case 2: // request received
			case 3: // processing request
				break;
			case 4:	// complete
				// Determine completion status
				switch ( this.request.status ) {
					case 200: // success
						// Complete the file load
						this.inquiry.receive( this.request.response )
						return;
					default:
						// Complete the request as failed
						console.error( 'XHR request failed:', this.request.status );
						this.close( 'fail' );
						return;
				}
				break;
		}
	}
	// Determine the progress of the transmission
	// RETURNS: [void] Nothing.
	// @param {number} loaded	- The amount of data loaded.
	// @param {number} total	- The total size of the request.
	progress( loaded, total ) {
		const percent	= total>0 ? loaded/total * 100 : 100;
		this.percent	= percent;
		console.log( `Transmission Progress: ${percent.toFixed(2)}%` );
		this.emit( 'progress', null, { loaded, total, percent } ); // Emit intermediate progress
	}
	// Transmission loaded data fully.
	// RETURNS: [void] Nothing.
	// * response		- [...] response data from fetch or xhr request
	load( response ) {
		// Call current inquiry to receive response & content type
		this.inquiry.receive( response, this.inquiry.contentType );
		this.complete();						// Call the complete method
	}
	// Transmission threw an error.
	// RETURNS: [void] Nothing.
	// * err	- error [object]
	error( err ) {
		this.emit( 'error', null, err );		// Emit error event with data
		this.close( 'error' );					// Call the complete method
	}
	// Transmission has been aborted.
	// RETURNS: [void] Nothing.
	// * err	- error [object]
	abort( err ) {
		this.close( 'abort' );					// Call the complete method
	}

	//-------------------------
	// End Handling
	//-------------------------
	// Complete the transmission.
	// RETURNS: [void] Nothing.
	complete() {
		this.emit( 'complete' );				// Emit complete event with data
	}
	// A transmission closed before completion (abort, fail, error, etc.)
	// RETURNS: [void] Nothing.
	// * status		- [string] Status of closure reason (e.g. 'abort', 'fail', etc.)
	close( status ) {
		switch ( status ) {
			case 'error':
			case 'abort':
			case 'fail':
				//console.log( 'transmission '+status+'ed' );
				this.aborter.abort();
				this.emit( 'close', null, status );		// Emit close event with status
				break;
			default:
				console.warn( 'Unknown status: '+status );
		}
	}
}

/* --- BEGIN js/system/data/Inquiry.js --- */

//-------------------------
// Inquiry Class
//-------------------------
// A class for handling a server request.
class Inquiry extends OSCallback {
	// For data & action handling
	address			= null;				// [string] URL endpoint for the transmission.
	iface			= 'HTTP';			// [string] Interface to use for the request (e.g., 'FETCH', 'HTTP').
	method			= 'POST';			// [string] Method for the request (e.g., 'POST', 'GET').
	mime			= null;				// [string] filetype of data to be handled
	// Calibration variables
	action			= null;				// [string] name of action to take: ie. 'load'
	context			= null;				// [string] name of action context: ie. 'settings'
	data			= null;				// [...] outgoing data to send to request
	requestType		= null;				// [string] name of data type to send: ie. 'application/json' (if null, type is approximated)
	contentType		= null;				// [string] name of response data file type: ie. 'image/jpeg'
	responseType	= null;				// [string] name of data type to receive: ie. 'json', 'raw'
	headers			= null;				// [object] Headers for the request.
	// Server interations
	prepped			= null;				// [object] of prepare data to set
	response		= null;				// [object] of data server response
	parsed			= null;				// [object] of parsed data server response

	// Initializes a new Transmission instance.
	// RETURNS: [void] Nothing.
	// * address		- [string] The URL endpoint for the request.
	// * iface			- [string] Fetch or HTTP method to use (default: 'FETCH').
	// * method			- [string] POST or GET method to use (default: 'POST').
	// * action			- [string] name of action to take: ie. 'load'
	// * context		- [string] name of action context: ie. 'settings'
	//   data			- [...] outgoing data to send to action-context
	//   responseType	- [string] name of data type to receive
	//   requestType	- [string] name of data type to send (if null, type is approximated)
	//   headers		- [object] Of headers to send in request.
	constructor( address, iface, method, action, context, data='', responseType='text', requestType='application/json', headers={} ) {
		super(); // call parent constructor
		// Validate action and context
		if ( typeof action!=='string' || action.trim()==='' ) {
			throw new Error( `Invalid action: '${action}'. It must be a non-empty string.` );
		}
		if ( typeof context!=='string' || context.trim()==='' ) {
			throw new Error( `Invalid context: '${context}'. It must be a non-empty string.` );
		}
		// Configure request [object]
		this.address		= address;									// web URL to make request to
		this.setIface( iface ?? null );								// Set request interface (e.g. 'FETCH', 'HTTP')
		this.setMethod( method ?? null );							// Set request method (e.g. 'POST', 'GET')
		this.action			= action;								// e.g., 'load'
		this.context		= context;								// e.g., 'settings'
		this.data			= data ?? '';							// Payload to send
		this.responseType	= responseType ?? this.expect();		// responseType type (e.g., 'json', 'formData', etc.)
		this.requestType	= requestType ?? this.approximate();	// requestType type (e.g., 'application/json', etc.)
		this.head( headers );										// Custom headers
		this.response		= null;									// Store server response
		this.jot( 'status', 'initialized' );						// status is instantiated
	}

	//-------------------------
	// Argument Processing
	//-------------------------
	// Set the interface to use
	// RETURNS: [void].
	// * iface		- [string] value of interface to use: 'FETCH', 'HTTP'
	setIface( iface='FETCH' ) {
		// Validate & Set Interface
		this.iface	= ['FETCH','HTTP'].includes(iface) ? iface : 'FETCH';
	}

	// Set the method to use
	// RETURNS: [void].
	// * method		- [string] value of method to use: 'POST', 'GET', 'FETCH'
	setMethod( method='POST' ) {
		// Validate & Set Method
		this.method	= ['POST','GET'].includes(method) ? method : 'POST';
	}

	// Approximate the content-type of data being sent.
	approximate() {
		// No content type needed for empty data
		if ( !this.data ) return null;
		const dataTypeMap = {
			'[object FormData]':		null,
			'[object Blob]':			this.data.type || 'application/octet-stream',
			'[object ArrayBuffer]':		'application/octet-stream',
			'[object URLSearchParams]':	'application/x-www-form-urlencoded',
			'[object Document]':		'application/xml',
			};
		const type = Object.prototype.toString.call( this.data );
		return dataTypeMap[type] || (typeof this.data==='object' ? 'application/json' : 'text/plain');
	}

	// Set the data responseType type
	// * type	- [...] value of responseType data type (defaults to 'text').
	expect( type='text' ) {
		// Throw error if none found
		if ( ['json','blob','text','arrayBuffer','document'].includes(type) )
			return type; // Set valid responseType
		else { // error, default to 'text'
			console.warn( `Unsupported responseType: '${type}'. Defaulting to 'text'.` );
			return 'text'; // Default fallback
		}
	}

	// Set & validate headers
	// RETURNS: [void].
	// * headers	- [object] Headers for fetch or xhr request to validate.
	head( headers ) {
		// Ensure headers is an object
		if ( !headers || typeof headers!=='object' || Array.isArray(headers) )
			throw new Error( `Invalid headers: Headers must be a plain object. Received: ${typeof headers}` );

		// Iterate through the headers to validate and set them
		Object.entries(headers).forEach(
			( [key, value] ) => {
				// Validation: Key must be a non-empty string
				if ( typeof key!=='string' || key.trim()==='' ) {
					console.warn( `Invalid header key: '${key}'. Keys must be non-empty strings.` );
					return;
				}

				// Validation: Value must be a string or a valid data type
				if ( typeof value!=='string' && typeof value!=='number' && typeof value!=='boolean' ) {
					console.warn( `Invalid header value for key '${key}': Must be a string, number, or boolean. Received: ${typeof value}` );
					return;
				}

				// Special handling for Content-Type
				if ( key.toLowerCase()==='content-type' ) {
					console.warn( `Content-Type header is set automatically based on the requestType. Ignored: '${value}'` );
					return;
				}

				// Add valid header to the headers object
				this.headers[key.trim()] = String( value );
			});

		// Debug: Log the final headers
		//console.log( 'Headers after validation:', this.headers );
	}

	//-------------------------
	// Data Preparation
	//-------------------------
	// Encode the data to be sent.
	encode() {
		// No data to encode
		const data	= this.data;
		if ( data===null || data===undefined ) return null;
		// Attempt to encode data
		const type	= this.requestType;
		if ( type==='application/json' ) return JSON.stringify( data );
		if ( type==='multipart/form-data' ) {
			// Convert [object] data to FormData
			const formData = new FormData();
			Object.keys(this.data).forEach(
				( key ) => {
					formData.append( key, this.data[key] );
				});
			return formData;
		}
		if ( data instanceof FormData || data instanceof Blob || data instanceof ArrayBuffer || data instanceof BufferSource )
			return data; // Binary or FormData doesn't need transformation
		if ( type==='application/x-www-form-urlencoded' )
			return data instanceof URLSearchParams ? data.toString() : null;
		if ( type==='application/xml' && data instanceof Document )
			return new XMLSerializer().serializeToString(data);
		if ( type==='text/plain' && typeof data==='string' )
			return data;
		throw new Error( 'Unsupported data type for responseType.' );
	}

	// Prepare the body & contentType for a request.
	// RETURNS: [bool] `true` on success, else `false`.
	prepare() {
		//-------------------------
		// Confirm Proper Mode
		//-------------------------
		// Confirm mode
		if ( this.skim('status')!=='initialized' ) {
			console.warn( 'Inquiry already prepped to send.' );
			return false;
		}
		//-------------------------
		// Attempt to Prepare
		//-------------------------
		const prep	= { body: null, headers: { ...this.headers } };	// Begin prepped data return
		const data	= this.data;									// Load pre-processed data [object]
		// Build body & header(s)
		if ( data!==null && data!==undefined ) {
			prep.body	= this.encode();
			if ( this.requestType && this.requestType!=='multipart/form-data' ) {
				prep.headers['Content-Type'] = this.requestType;
			}
		}
		//-------------------------
		// Change Mode & Clock
		//-------------------------
		this.prepped = prep;				// Save prepped data to this.prepped property
		this.jot( 'status', 'prepped' );	// inquiry prepared to sent
		this._clock( 'prepped' );			// Clock the object to log prepped timestamp
		return true;						// Return processed body & contentType
	}

	//-------------------------
	// Data Receiving
	//-------------------------
	// Receive a server response & parse it.
	// * response	- [...] value of response to parse.
	// * contentType - (Optional) Content-Type header from the server.
	async receive( response, contentType='application/octet-stream' ) {
		// Throw error if response error
		if ( !response ) return null;
		// Attempt to process data by type
		try {
			switch ( this.responseType ) {
				case 'json':
					// Decode buffer to raw string
					const decoded	= new TextDecoder().decode( response );
					//console.log( '🟨 Raw Decoded Response:', decoded );
					// Try parse
					try {
						this.parsed	= JSON.parse( decoded );
						console.log( '🟩 Parsed JSON:', this.parsed );
					}
					catch ( error ) {
						console.error( '🟥 JSON PARSE FAILED:', error );
						console.error( '🟥 Offending Text:', decoded.split('').map(c => `${c} [${c.charCodeAt(0)}]`).join('') );
						this.parsed = null;
					}
					break;
				case 'blob': // Create a Blob from the arrayBuffer
					this.parsed	= new Blob( [response], { type: contentType } );
					break;
				case 'text': // Decode arrayBuffer into a string
					this.parsed	= new TextDecoder().decode( response );
					break;
				case 'arrayBuffer':
					this.parsed	= this.parsed = response; // Already an arrayBuffer
					break;
				case 'document': // Parses as XML/HTML
					try {
						const decoded	= new TextDecoder().decode( response );
						this.parsed		= new DOMParser().parseFromString( decoded, 'text/html' );
					}
					catch ( error ) {
						console.error( 'Failed to parse document:', error );
						this.parsed	= null;
					}
					break;
				default:
					console.warn( `Unsupported response type: '${this.responseType}'.` );
					this.parsed	= null;
			}
		}
		catch ( error ) { // catch error if failed try
			console.error( 'Failed to parse server response:', error) ;
			this.parsed	= null;
		}
		// Return processed data
		return this.parsed;
	}
}

